import { useTranslation } from "react-i18next";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { useEffect } from "react";
import config from "../../config";
import DatalistMiddleware from "../../middleware/datalist_middleware";
import empty from "../../helpers/empty_helper";
import { DocumentInsertCollectionDatalistOnloadActionCreator } from "../../reducers/document_insert_reducer";

const DocumentInsertComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-document-insert";

  useEffect(() => {
    const offcanvas = document.getElementById(offcanvas_id);

    offcanvas.addEventListener("hide.bs.offcanvas", () => {
      setTimeout(() => { props.DocumentInsertOnclear() },
      config.offcanvas_refresh_delay);
    });
  }, []);

  if(empty(props.files)) {
    const files = document.getElementById("document-insert-files");
    if(files) {
      files.value = "";
    }
  }

  const DocumentInsertFilesOnchange = (event) => {
    props.DocumentInsertFilesOnchange(event.target.files);
  }

  const submit_enabled = props.files.length > 0 && props.collection_datalist.collection_id > 0;

  const DocumentInsertOninsert = (event) => {
    event.preventDefault();
    if (submit_enabled) {
      props.DocumentInsertOninsert();
    }
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title">{ t("offcanvas-document-insert-title") }</h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

          <div className="form-text">
            { t("document-insert-collection-text") }
          </div>

          <div className="form-text mt-2">
            <DatalistMiddleware
              dispatch={ props.dispatch }
              user_token={ props.user_token }
              // datalist data
              datalist_name="document-insert-collection-datalist"
              datalist_placeholder={ t("filter-collection-name") }
              datalist_value={ props.collection_datalist.collection_name }
              datalist_id={ props.collection_datalist.collection_id }
              response_data={ props.collection_datalist.response_data }
              response_code={ props.collection_datalist.response_code }
              datalist_options={ !empty(props.collection_datalist.response_data) ? props.collection_datalist.response_data.collections.map(el => { return { id: el.id, value: el.collection_name } }) : [] }
              // request
              request_url={ config.server_host + "collections" }
              request_param="collection_name__ilike"
              request_order_by="collection_name"
              request_order="asc"
              // datalist actions
              datalist_onchange={ props.DocumentInsertCollectionDatalistCollectionNameOnchange }
              datalist_onload_action_creator={ DocumentInsertCollectionDatalistOnloadActionCreator }
              onupdate={ () => {} }
            />
          </div>

          <div className="form-text mt-4">
            { t("document-insert-files-text") }
          </div>

          <div className="mt-2">
            <input id="document-insert-files" className={ "form-control" + (props.files.length > 0 ? " border-primary" : "") } type="file" multiple="multiple" onInput={ DocumentInsertFilesOnchange } files={ props.files } />
          </div>

          <button onClick={ offcanvas_hide } className="btn btn-outline-primary mt-4" type="button">
            <i className="bi bi-arrow-left"></i> { t("button-cancel") }
          </button>

          <button onClick={ DocumentInsertOninsert } className={"btn btn-primary mt-4 ms-2 " + (!submit_enabled ? "disabled" : "")} type="button" >
            <i className="bi bi-arrow-up"></i> { t("button-upload") }
            <div className={ "spinner-border spinner-border-sm text-light ms-2" + (props.files_elapsed ? "" : " d-none") } role="status">
              <span className="visually-hidden">Loading...</span>
            </div>
          </button>

        </form>
      </div>
    </div>
  );
}

export default DocumentInsertComponent;
