const DOCUMENT_SELECT_DOCUMENT_ID_ONCHANGE = "DOCUMENT_SELECT_DOCUMENT_ID_ONCHANGE";
const DOCUMENT_SELECT_REVISIONS_ONLOAD = "DOCUMENT_SELECT_REVISIONS_ONLOAD";
const DOCUMENT_SELECT_ONSELECT = "DOCUMENT_SELECT_ONSELECT";
const DOCUMENT_SELECT_ONCLEAR = "DOCUMENT_SELECT_ONCLEAR";

const initial = {
  document_id: 0,
  revisions: {
    response_data: {},
    response_code: 0,
  },
  onselect: {
    response_data: {},
    response_code: 0,
  }
};

const DocumentSelectReducer = (state = initial, action) => {

  if (action.type === DOCUMENT_SELECT_DOCUMENT_ID_ONCHANGE) {
    state.document_id = action.document_id;

  } else if (action.type === DOCUMENT_SELECT_REVISIONS_ONLOAD) {
    state.revisions.response_data = action.response_data;
    state.revisions.response_code = action.response_code;

  } else if (action.type === DOCUMENT_SELECT_ONSELECT) {
    state.onselect.response_data = action.response_data;
    state.onselect.response_code = action.response_code;
 
  } else if (action.type === DOCUMENT_SELECT_ONCLEAR) {
    state.document_id = 0;

    state.revisions.response_data = {};
    state.revisions.response_code = 0;

    state.onselect.response_data = {};
    state.onselect.response_code = 0;
  }

  return state;
}

export const DocumentSelectDocumentIdOnchangeActionCreator = (document_id) => {
  return {
    type: DOCUMENT_SELECT_DOCUMENT_ID_ONCHANGE,
    document_id: document_id,
  }
}

export const DocumentSelectRevisionsOnloadActionCreator = (response_data, response_code) => {
  return {
    type: DOCUMENT_SELECT_REVISIONS_ONLOAD,
    response_data: response_data,
    response_code: response_code,
  }
}

export const DocumentSelectOnselectActionCreator = (response_data, response_code) => {
  return {
    type: DOCUMENT_SELECT_ONSELECT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const DocumentSelectOnclearActionCreator = () => {
  return {
    type: DOCUMENT_SELECT_ONCLEAR,
  }
}

export default DocumentSelectReducer;
