import { useTranslation } from "react-i18next";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { useEffect } from "react";
import config from "../../config";
import { parseBoolean } from "../../helpers/boolean_helper";

const CollectionLockComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-collection-lock";

  useEffect(() => {
    const offcanvas = document.getElementById(offcanvas_id);

    offcanvas.addEventListener("hide.bs.offcanvas", () => {
      setTimeout(() => { props.CollectionLockCollectionIdOnchange(0) },
      config.offcanvas_refresh_delay);
    });
  }, []);

  const CollectionLockOnlock = (event) => {
    event.preventDefault();
    props.CollectionLockOnlock();
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title">{ t("offcanvas-collection-lock-title") }</h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

          <div className="form-text">
            { t("offcanvas-collection-lock-text") }
          </div>

          <div className="mt-2">
            { t("collection-selected") } <span className="badge text-bg-primary">{ props.collection_id ? 1 : props.collections_count }</span>
          </div>

          <div className="form-text mt-4">
            { t("collection-locked-text") }
          </div>
          <div className="form-floating mt-2">
            <div className="form-switch">
              <input id="collection-lock-locked" onChange={ props.CollectionLockIsLockedOnchange } checked={ props.is_locked } className="form-check-input focused" type="checkbox" role="switch" />
              <label className="form-check-label ms-2" htmlFor="collection-lock-locked">{ props.is_locked ? t("collection-locked-true") : t("collection-locked-false") }</label>
            </div>
          </div>

          <button onClick={ offcanvas_hide } className="btn btn-outline-primary mt-4" type="button">
            <i className="bi bi-arrow-left"></i> { t("button-cancel") }
          </button>

          <button onClick={ CollectionLockOnlock } className="btn btn-primary mt-4 ms-2" type="button" >
            <i className="bi bi-lock-fill"></i> { t("button-lock") }
          </button>

        </form>
      </div>
    </div>
  );
}

export default CollectionLockComponent;
