import {
  DocumentSelectRevisionsOnloadActionCreator,
  DocumentSelectOnselectActionCreator,
  DocumentSelectOnclearActionCreator } from "../../reducers/document_select_reducer";
import DocumentSelectComponent from "../../components/document/document_select_component";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { log } from "../../helpers/log_helper";
import redirect from "../../helpers/redirect_helper";
import {
  CommentListOnselectActionCreator,
  CommentListOnclearActionCreator,
  CommentListOffsetOnchangeActionCreator  } from "../../reducers/comment_list_reducer";
import {
  CommentInsertCommentContentOnchangeActionCreator,
  CommentInsertOninsertActionCreator,
  CommentInsertOnclearActionCreator } from "../../reducers/comment_insert_reducer";
  import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";

import {
  CommentDeleteCommentIdOnchangeActionCreator,
  CommentDeleteOndeleteActionCreator,
  CommentDeleteOnclearActionCreator } from "../../reducers/comment_delete_reducer";
import { DocumentUpdateDocumentIdOnchangeActionCreator } from "../../reducers/document_update_reducer";
import { DocumentDeleteDocumentIdOnchangeActionCreator } from "../../reducers/document_delete_reducer";

let comments_loading = false;

const DocumentSelectMiddleware = (props) => {
  const navigate = useNavigate();

  const DocumentSelectRevisionsOnload = () => {
    const log_prefix = "document-select-revisions";
    const document_id = props.store.getState().document_select.document_id;

    axios({
      method: "get",
      url: config.server_host + "document/" + document_id + "/revisions",
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      params: {
        offset: 0, 
        limit: 200,
        order_by: "id", 
        order: "desc",
      },

    }).then((response) => {
      log.debug(log_prefix, response);

      const action = DocumentSelectRevisionsOnloadActionCreator(response.data, response.status);
      props.store.dispatch(action);
      
    }).catch(e => {
      log.error(log_prefix, e);
    });
  }

  const DocumentSelectOnselect = () => {
    const log_prefix = "document-select-onselect";

    axios({
      method: "get",
      url: config.server_host + "document/" + props.store.getState().document_select.document_id, 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      params: {},

    }).then((response) => {
      log.debug(log_prefix, response);

      const action = DocumentSelectOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);

      CommentListOnclear();
      CommentListOnselect();
      
    }).catch(e => {
      log.error(log_prefix, e);
      redirect(e, navigate);
    });
  }

  const DocumentSelectOnclear = () => {
    const action = DocumentSelectOnclearActionCreator();
    props.store.dispatch(action);
  }

  const CommentInsertCommentContentOnchange = (comment_content) => {
    const action = CommentInsertCommentContentOnchangeActionCreator(comment_content);
    props.store.dispatch(action);
  }
 
  const CommentInsertOninsert = () => {
    const offcanvas_id = "offcanvas-document-select";
    const log_prefix = "comment-insert-oninsert";
    buttons_disable(offcanvas_id);

    axios({
      method: "post",
      url: config.server_host + "comment", 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      data: {
        comment_content: props.store.getState().comment_insert.comment_content,
        document_id: props.store.getState().document_select.document_id,
      },

    }).then(response => {
      log.debug(log_prefix, response);
      buttons_enable(offcanvas_id);

      CommentInsertOnclear();
      CommentListOnclear();
      CommentListOnselect();

    }).catch(e => {
      log.error(log_prefix, e);
      buttons_enable(offcanvas_id);

      if (e.status === 422) {
        const action = CommentInsertOninsertActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }
    });
  }

  const CommentInsertOnclear = () => {
    const action = CommentInsertOnclearActionCreator();
    props.store.dispatch(action);
  }

  const CommentDeleteOndelete = (comment_id) => {
    const log_prefix = "comment-delete-ondelete";

    axios({
      method: "delete",
      url: config.server_host + "comment/" + comment_id, 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },

    }).then(response => {
      log.debug(log_prefix, response);

      CommentListOnclear();
      CommentListOnselect();

    }).catch(e => {
      log.error(log_prefix, e);

      if (e.status === 422) {
        const action = CommentDeleteOndeleteActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }
    });
  }

  const CommentListOffsetOnchange = (offset) => {
    const action = CommentListOffsetOnchangeActionCreator(offset);
    props.store.dispatch(action);
  }

  const CommentListOnselect = () => {
    if (comments_loading) { return }
    comments_loading = true;

    const log_prefix = "comment-list-onselect";

    axios({
      method: "get",
      url: config.server_host + "comments", 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      params: {
        document_id__eq: props.store.getState().document_select.document_id,
        offset: props.store.getState().comment_list.offset,
        limit: config.default_comments_limit,
        order_by: config.default_comments_order_by, 
        order: config.default_comments_order,
      },

    }).then(response => {
      log.debug(log_prefix, response);
      comments_loading = false;

      const action = CommentListOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);

    }).catch(e => {
      log.error(log_prefix, e);
      comments_loading = false;
      redirect(e, navigate);
    });
  }

  const CommentListOnclear = () => {
    const action = CommentListOnclearActionCreator();
    props.store.dispatch(action);    
  }

  const DocumentUpdateDocumentIdOnchange = (document_id) => {
    const action = DocumentUpdateDocumentIdOnchangeActionCreator(document_id);
    props.store.dispatch(action);
  }

  const DocumentDeleteDocumentIdOnchange = (document_id) => {
    const action = DocumentDeleteDocumentIdOnchangeActionCreator(document_id);
    props.store.dispatch(action);
  }

  const download = (revision_id) => {
    axios({
      method: "get",
      url: config.server_host + "document/" + props.store.getState().document_select.document_id + "/revision/" + revision_id, 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      params: {},
      responseType: "blob",

    }).then((response) => {
      log.debug("document downlaod", response);

      const blob = new Blob([response.data], { type: props.store.getState().document_select.onselect.response_data.document_mimetype });
      const link = document.createElement("a");
      link.href = URL.createObjectURL(blob);
      link.download = props.store.getState().document_select.onselect.response_data.document_filename;
      link.click();
      URL.revokeObjectURL(link.href);

    }).catch(e => {
      log.error("document download", e);
      redirect(e, navigate);
    });
  }

  return (
    <DocumentSelectComponent
      store={ props.store }
      dispatch={ props.store.dispatch }
      user_timezone={ props.store.getState().app.user_timezone }
      user_token={ props.store.getState().app.user_token }
      user_role={ props.store.getState().app.token_payload.user_role }
      token_payload={ props.store.getState().app.token_payload }

      document_id={ props.store.getState().document_select.document_id }
      revisions={ props.store.getState().document_select.revisions }
      response_data={ props.store.getState().document_select.onselect.response_data }
      response_code={ props.store.getState().document_select.onselect.response_code }
      download={ download }

      DocumentSelectRevisionsOnload={ DocumentSelectRevisionsOnload }
      DocumentSelectOnselect={ DocumentSelectOnselect }
      DocumentSelectOnclear={ DocumentSelectOnclear }

      DocumentUpdateDocumentIdOnchange={ DocumentUpdateDocumentIdOnchange }
      DocumentDeleteDocumentIdOnchange={ DocumentDeleteDocumentIdOnchange }

      comment_content={ props.store.getState().comment_insert.comment_content }
      comment_oninsert={ props.store.getState().comment_insert.oninsert }
      CommentInsertCommentContentOnchange={ CommentInsertCommentContentOnchange }
      CommentInsertOninsert={ CommentInsertOninsert }
      CommentInsertOnclear={ CommentInsertOnclear }

      CommentDeleteOndelete={ CommentDeleteOndelete }

      comment_list_onselect={ props.store.getState().comment_list.onselect }
      CommentListOnselect={ CommentListOnselect }
      CommentListOnclear={ CommentListOnclear }
      CommentListOffsetOnchange={ CommentListOffsetOnchange }
    />
  );
}
  
export default DocumentSelectMiddleware;
