import {
  UserSelectOnselectActionCreator,
  UserSelectOnclearActionCreator } from "../../reducers/user_select_reducer";
import UserSelectComponent from "../../components/user/user_select_component";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { log } from "../../helpers/log_helper";
import redirect from "../../helpers/redirect_helper";
import { UserRoleUserIdOnchangeActionCreator } from "../../reducers/user_role_reducer";

const UserSelectMiddleware = (props) => {
  const navigate = useNavigate();

  const UserSelectOnselect = () => {
    const log_prefix = "user-select";

    axios({
      method: "get",
      url: config.server_host + "user/" + props.store.getState().user_select.user_id, 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      params: {},

    }).then((response) => {
      log.debug(log_prefix, response);

      const action = UserSelectOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);
      
    }).catch(e => {
      log.error(log_prefix, e);
      redirect(e, navigate);
    });

  }

  const UserSelectOnclear = () => {
    const action = UserSelectOnclearActionCreator();
    props.store.dispatch(action);
  }

  const UserRoleUserIdOnchange = (user_id) => {
    const action = UserRoleUserIdOnchangeActionCreator(user_id);
    props.store.dispatch(action);
  }

  return (
    <UserSelectComponent
      user_timezone={ props.store.getState().app.user_timezone }
      user_role={ props.store.getState().app.token_payload.user_role }
      token_payload={ props.store.getState().app.token_payload }

      user_id={ props.store.getState().user_select.user_id }
      response_data={ props.store.getState().user_select.onselect.response_data }
      response_code={ props.store.getState().user_select.onselect.response_code }

      UserSelectOnselect={ UserSelectOnselect }
      UserSelectOnclear={ UserSelectOnclear }
      UserRoleUserIdOnchange={ UserRoleUserIdOnchange }
    />
  );
}
  
export default UserSelectMiddleware;
