import { useTranslation } from "react-i18next";
import { useEffect } from "react";
import config from "../../config";
import empty from "../../helpers/empty_helper";
import datetime from "../../helpers/datetime_helper";
import { can_read, can_write, can_edit, can_admin } from "../../helpers/role_helper"
import { offcanvas_hide, offcanvas_show } from "../../helpers/offcanvas_helper";
import { parseBoolean } from "../../helpers/boolean_helper";

const UserSelectComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-user-select";

  useEffect(() => {
    document.getElementById(offcanvas_id).addEventListener("show.bs.offcanvas", () => {
      props.UserSelectOnselect();
    });

    document.getElementById(offcanvas_id).addEventListener("hide.bs.offcanvas", () => {
      setTimeout(
        () => { props.UserSelectOnclear() },
        config.offcanvas_latency);
    });
  }, []);

  const UserRoleUserIdOnchange = (event) => {
    event.preventDefault();
    props.UserRoleUserIdOnchange(props.user_id);

    offcanvas_hide();
    offcanvas_show("offcanvas-user-role");
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title d-flex">
          { t("offcanvas-user-select-title") }
        
          <div className="dropdown ms-2">
            <a href="#" className="link link-primary dropdown-toggle no-after" type="button" data-bs-toggle="dropdown">
              <i className="bi bi-list"></i>
            </a>
            <ul className="dropdown-menu">
              <li><a className="dropdown-item" href="#" onClick={ offcanvas_hide }>{ t("button-cancel") }</a></li>
              <li><a className={ "dropdown-item" + (props.response_data.id === props.token_payload.user_id ? "" : " d-none") } href="#offcanvas-user-update" data-bs-toggle="offcanvas">Edit profile</a></li>
              <li><a className={ "dropdown-item" + (can_admin(props.user_role) && props.response_data.id !== props.token_payload.user_id ? "" : " d-none") } href="#" onClick={ UserRoleUserIdOnchange }>Change role</a></li>
            </ul>
          </div>
        
        </h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

          <div className="form-text">
            { t("id") }
          </div>
          <div>
            { props.response_code === 200 ? props.response_data.id : <span className="placeholder placeholder-lg col-2"></span> }
          </div>

          <div className="form-text mt-4">
            { t("user-full-name") }
          </div>
          <div>
            { props.response_code === 200 ? props.response_data.first_name + " " + props.response_data.last_name : <span className="placeholder placeholder-lg col-8"></span> }
          </div>

          { props.response_code === 200 && props.response_data.userpic_url && <>
            <div className="form-text d-flex justify-content-center align-items-center mt-4">
              <img src={ props.response_data.userpic_url } className="card-img-top" style={{ width: "auto", height: "auto" }} alt={ props.response_data.user_login } />
            </div>
          </> }

          <div className="form-text mt-4">
            { t("user-login") }
          </div>
          <div>
            { props.response_code === 200 ? props.response_data.user_login : <span className="placeholder placeholder-lg col-8"></span> }
          </div>

          <div className="form-text mt-4">
            { t("user-role") }
          </div>
          <div>
            { props.response_code === 200 ? props.response_data.user_role : <span className="placeholder placeholder-lg col-8"></span> }
          </div>

          { props.response_code === 200 && props.response_data.user_contacts && <>
            <div className="form-text mt-4">
              { t("user-contacts") }
            </div>
            <div>
              { props.response_code === 200 ? props.response_data.user_contacts : <span className="placeholder placeholder-lg col-12"></span> }
            </div>
          </> }

          { props.response_code === 200 && props.response_data.user_caption && <>
            <div className="form-text mt-4">
              { t("user-caption") }
            </div>
            <div>
              { props.response_code === 200 ? props.response_data.user_caption : <span className="placeholder placeholder-lg col-12"></span> }
            </div>
          </> }

          <div className="form-text mt-4">
            { t("user-active") }
          </div>
          <div>
            <i className={ "bi me-1 " + (props.response_code === 200 && props.response_data.is_active ? "bi-check" : "bi-dot") }></i>
            { props.response_code === 200 ? (props.response_data.is_active ? t("activity-active") : t("activity-inactive")) : <span className="placeholder placeholder-lg col-2"></span> }
          </div>

          <div className="form-text mt-4">
            { t("user-created-date") }
          </div>
          <div>
            { props.response_code === 200 ? datetime(props.response_data.created_date, props.user_timezone, t) : <span className="placeholder placeholder-lg col-8"></span> }
          </div>

          <div className="form-text mt-4">
            { t("user-last-login-date") }
          </div>
          <div>
            { props.response_code === 200 ? datetime(props.response_data.last_login_date, props.user_timezone, t) : <span className="placeholder placeholder-lg col-8"></span> }
          </div>

        </form>
      </div>
    </div>
  );
}

export default UserSelectComponent;
