import { PartnerDeletePartnerIdsOnshiftActionCreator, PartnerDeleteOnclearActionCreator } from "../../reducers/partner_delete_reducer";
import { PartnerListOffsetOnchangeActionCreator, PartnerListOnclearActionCreator } from "../../reducers/partner_list_reducer";
import PartnerDeleteComponent from "../../components/partner/partner_delete_component";
import config from "../../config";
import axios from "axios";
import empty from "../../helpers/empty_helper";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import { log } from "../../helpers/log_helper";
import { useNavigate } from "react-router-dom";
import redirect from "../../helpers/redirect_helper";

const PartnerDeleteMiddleware = (props) => {
  const navigate = useNavigate();

  const PartnerDeletePartnerIdsOnshift = (partner_id) => {
    const action = PartnerDeletePartnerIdsOnshiftActionCreator(partner_id);
    props.store.dispatch(action);
  }

  const PartnerDeleteOndelete = () => {
    const offcanvas_id = "offcanvas-partner-delete";
    const log_prefix = "partner-delete";
    buttons_disable(offcanvas_id);

    const partner_id = props.store.getState().partner_delete.partner_id;
    const partner_ids = props.store.getState().partner_delete.partner_ids;

    let ids_to_delete = partner_id ? [partner_id] : Array.from(partner_ids);
    let ids_in_progress = Array.from(ids_to_delete);

    ids_to_delete.forEach(id => {

      axios({
        method: "delete",
        url: config.server_host + "partner/" + id, 
        headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
        params: {},

      }).then(response => {
        log.debug(log_prefix, response);

        ids_in_progress.splice(ids_in_progress.indexOf(id), 1);
        if (partner_ids.includes(id)) {
          PartnerDeletePartnerIdsOnshift(id);
        }

        if (empty(ids_in_progress)) {
          PartnerListOnclear();
          buttons_enable(offcanvas_id);
          offcanvas_hide();
        }
        
      }).catch(e => {
        log.error(log_prefix, e);

        if (e.status === 404) {
            ids_in_progress.splice(ids_in_progress.indexOf(id), 1);
            if (partner_ids.includes(id)) {
              PartnerDeletePartnerIdsOnshift(id);
            }
  
          if (empty(ids_in_progress)) {
            PartnerListOnclear();
            buttons_enable(offcanvas_id);
            offcanvas_hide();
          }
  
        } else {
          redirect(e, navigate);
        }

      });
    });
  }

  const PartnerDeleteOnclear = () => {
    const action = PartnerDeleteOnclearActionCreator();
    props.store.dispatch(action);
  }

  const PartnerListOnclear = () => {
    let action = PartnerListOffsetOnchangeActionCreator(0);
    props.store.dispatch(action);

    action = PartnerListOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <PartnerDeleteComponent
      partner_id={ props.store.getState().partner_delete.partner_id }
      partner_ids={ props.store.getState().partner_delete.partner_ids }

      PartnerDeleteOndelete={ PartnerDeleteOndelete }
      PartnerDeleteOnclear={ PartnerDeleteOnclear }
    />
  );
}
  
export default PartnerDeleteMiddleware;
