import {
  DocumentUpdateIsFlaggedOnchangeActionCreator,
  DocumentUpdateDocumentFilenameOnchangeActionCreator,
  DocumentUpdateDocumentSummaryOnchangeActionCreator,
  DocumentUpdateDocumentTagsOnchangeActionCreator,
  DocumentUpdateFilesOnchangeActionCreator,
  DocumentUpdateCollectionDatalistCollectionNameOnchangeActionCreator,
  DocumentUpdatePartnerDatalistPartnerNameOnchangeActionCreator,
  DocumentUpdateOnselectActionCreator,
  DocumentUpdateOnupdateActionCreator,
  DocumentUpdateOnclearActionCreator } from "../../reducers/document_update_reducer";
import { DocumentListOnclearActionCreator } from "../../reducers/document_list_reducer";
import DocumentUpdateComponent from "../../components/document/document_update_component";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import { log } from "../../helpers/log_helper";
import redirect from "../../helpers/redirect_helper";
import { DocumentSelectOnselectActionCreator } from "../../reducers/document_select_reducer";

const DocumentUpdateMiddleware = (props) => {
  const navigate = useNavigate();

  const DocumentUpdateIsFlaggedOnchange = () => {
    const action = DocumentUpdateIsFlaggedOnchangeActionCreator();
    props.store.dispatch(action);
  }

  const DocumentUpdateDocumentFilenameOnchange = (document_filename) => {
    const action = DocumentUpdateDocumentFilenameOnchangeActionCreator(document_filename);
    props.store.dispatch(action);
  }

  const DocumentUpdateDocumentSummaryOnchange = (document_summary) => {
    const action = DocumentUpdateDocumentSummaryOnchangeActionCreator(document_summary);
    props.store.dispatch(action);
  }

  const DocumentUpdateDocumentTagsOnchange = (document_tags) => {
    const action = DocumentUpdateDocumentTagsOnchangeActionCreator(document_tags);
    props.store.dispatch(action);
  }

  const DocumentUpdateFilesOnchange = (files) => {
    const log_prefix = "document-update-onreplace";
    const document_id = props.store.getState().document_update.document_id;

    const formData = new FormData();
    formData.append("file", Array.from(files)[0]);

    axios({
      method: "post",
      url: config.server_host + "document/" + document_id, 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      data: formData,

    }).then(response => {
      log.debug(log_prefix, response);
      DocumentUpdateOnselect();

      const action = DocumentUpdateFilesOnchangeActionCreator("");
      props.store.dispatch(action);
      
    }).catch(e => {
      log.error(log_prefix, e);
    });
  }

  const DocumentUpdateCollectionDatalistCollectionNameOnchange = (collection_name) => {
    const action = DocumentUpdateCollectionDatalistCollectionNameOnchangeActionCreator(collection_name);
    props.store.dispatch(action);
  }

  const DocumentUpdatePartnerDatalistPartnerNameOnchange = (partner_name) => {
    const action = DocumentUpdatePartnerDatalistPartnerNameOnchangeActionCreator(partner_name);
    props.store.dispatch(action);
  }

  const DocumentUpdateOnselect = () => {
    const log_prefix = "document-update-onselect";

    axios({
      method: "get",
      url: config.server_host + "document/" + props.store.getState().document_update.document_id, 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },

    }).then((response) => {
      log.debug(log_prefix, response);

      const action = DocumentUpdateOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);
      
    }).catch(e => {
      log.error(log_prefix, e);
      redirect(e, navigate);
    });
  }

  const DocumentUpdateOnupdate = () => {
    const offcanvas_id = "offcanvas-document-update";
    const log_prefix = "document-update";
    buttons_disable(offcanvas_id);

    let data = {
      collection_id: props.store.getState().document_update.collection_datalist.collection_id,
      is_flagged: props.store.getState().document_update.is_flagged,
      document_filename: props.store.getState().document_update.document_filename,
      document_summary: props.store.getState().document_update.document_summary,
      document_tags: props.store.getState().document_update.document_tags,
    };

    const partner_id = props.store.getState().document_update.partner_datalist.partner_id;
    if (partner_id) {
      data["partner_id"] = partner_id;
    }

    axios({
      method: "put",
      url: config.server_host + "document/" + props.store.getState().document_update.document_id, 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      data: data,

    }).then(response => {
      log.debug(log_prefix, response);
      buttons_enable(offcanvas_id);
      offcanvas_hide();
      
      const action = DocumentUpdateOnupdateActionCreator(response.data, response.status);
      props.store.dispatch(action);

      DocumentListOnclear();

    }).catch(e => {
      log.error(log_prefix, e);
      buttons_enable(offcanvas_id);

      if (e.status === 422) {
        const action = DocumentUpdateOnupdateActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }
    });
  }

  const DocumentUpdateOnclear = () => {
    const action = DocumentUpdateOnclearActionCreator();
    props.store.dispatch(action);
  }

  const DocumentListOnclear = () => {
    const action = DocumentListOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <DocumentUpdateComponent
      dispatch={ props.store.dispatch }
      user_token={ props.store.getState().app.user_token }

      document_id={ props.store.getState().document_update.document_id }
      is_flagged={ props.store.getState().document_update.is_flagged }
      document_filename={ props.store.getState().document_update.document_filename }
      document_summary={ props.store.getState().document_update.document_summary }
      document_tags={ props.store.getState().document_update.document_tags }
      files={ props.store.getState().document_update.files }
      thumbnail_url={ props.store.getState().document_update.thumbnail_url }
      collection_datalist={ props.store.getState().document_update.collection_datalist }
      partner_datalist={ props.store.getState().document_update.partner_datalist }
      response_data={ props.store.getState().document_update.onupdate.response_data }
      response_code={ props.store.getState().document_update.onupdate.response_code }
      
      DocumentUpdateIsFlaggedOnchange={ DocumentUpdateIsFlaggedOnchange }
      DocumentUpdateDocumentFilenameOnchange={ DocumentUpdateDocumentFilenameOnchange }
      DocumentUpdateDocumentSummaryOnchange={ DocumentUpdateDocumentSummaryOnchange }
      DocumentUpdateDocumentTagsOnchange={ DocumentUpdateDocumentTagsOnchange }
      DocumentUpdateFilesOnchange={ DocumentUpdateFilesOnchange }
      DocumentUpdateOnselect={ DocumentUpdateOnselect }
      DocumentUpdateOnupdate={ DocumentUpdateOnupdate }
      DocumentUpdateOnclear={ DocumentUpdateOnclear }
      DocumentUpdateCollectionDatalistCollectionNameOnchange={ DocumentUpdateCollectionDatalistCollectionNameOnchange }
      DocumentUpdatePartnerDatalistPartnerNameOnchange={ DocumentUpdatePartnerDatalistPartnerNameOnchange }
    />
  );
}
  
export default DocumentUpdateMiddleware;
