import { offcanvas_hide } from "./offcanvas_helper";

const redirect = (exception, navigate) => {

  if (exception.status === 422) {
    navigate("/422");
    offcanvas_hide();

  } else if (exception.status === 423) {
    navigate("/423");
    offcanvas_hide();

  } else if (exception.status === 403) {
    navigate("/403");
    offcanvas_hide();

  } else if (exception.status === 404) {
    navigate("/404");
    offcanvas_hide();

  } else {
    navigate("/500");
    offcanvas_hide();
  }
}

export default redirect;
