const PARTNER_UPDATE_PARTNER_ID_ONCHANGE = "PARTNER_UPDATE_PARTNER_ID_ONCHANGE";
const PARTNER_UPDATE_PARTNER_NAME_ONCHANGE = "PARTNER_UPDATE_PARTNER_NAME_ONCHANGE";
const PARTNER_UPDATE_PARTNER_TYPE_ONCHANGE = "PARTNER_UPDATE_PARTNER_TYPE_ONCHANGE";
const PARTNER_UPDATE_PARTNER_REGION_ONCHANGE = "PARTNER_UPDATE_PARTNER_REGION_ONCHANGE";
const PARTNER_UPDATE_PARTNER_WEBSITE_ONCHANGE = "PARTNER_UPDATE_PARTNER_WEBSITE_ONCHANGE";
const PARTNER_UPDATE_PARTNER_CONTACTS_ONCHANGE = "PARTNER_UPDATE_PARTNER_CONTACTS_ONCHANGE";
const PARTNER_UPDATE_PARTNER_SUMMARY_ONCHANGE = "PARTNER_UPDATE_PARTNER_SUMMARY_ONCHANGE";
const PARTNER_UPDATE_FILES_ONCHANGE = "USER_UPDATE_FILES_ONCHANGE";
const PARTNER_UPDATE_ONSELECT = "PARTNER_UPDATE_ONSELECT";
const PARTNER_UPDATE_ONUPDATE = "PARTNER_UPDATE_ONUPDATE";
const PARTNER_UPDATE_ONCLEAR = "PARTNER_UPDATE_ONCLEAR";

const initial = {
  partner_id: 0,
  partner_name: "",
  partner_type: "",
  partner_region: "",
  partner_website: "",
  partner_contacts: "",
  partner_summary: "",
  files: [],
  onupdate: {
    response_data: {},
    response_code: 0,
  },
};

const PartnerUpdateReducer = (state = initial, action) => {

  if (action.type === PARTNER_UPDATE_PARTNER_ID_ONCHANGE) {
    state.partner_id = parseInt(action.partner_id);

  } else if (action.type === PARTNER_UPDATE_PARTNER_NAME_ONCHANGE) {
    state.partner_name = action.partner_name;

  } else if (action.type === PARTNER_UPDATE_PARTNER_TYPE_ONCHANGE) {
    state.partner_type = action.partner_type;

  } else if (action.type === PARTNER_UPDATE_PARTNER_REGION_ONCHANGE) {
    state.partner_region = action.partner_region;

  } else if (action.type === PARTNER_UPDATE_PARTNER_WEBSITE_ONCHANGE) {
    state.partner_website = action.partner_website;

  } else if (action.type === PARTNER_UPDATE_PARTNER_CONTACTS_ONCHANGE) {
    state.partner_contacts = action.partner_contacts;

  } else if (action.type === PARTNER_UPDATE_PARTNER_SUMMARY_ONCHANGE) {
    state.partner_summary = action.partner_summary;

  } else if (action.type === PARTNER_UPDATE_FILES_ONCHANGE) {
    state.files = action.files;

  } else if (action.type === PARTNER_UPDATE_ONSELECT) {
      state.partner_name = action.response_data.partner_name;
      state.partner_type = action.response_data.partner_type ? action.response_data.partner_type : "";
      state.partner_region = action.response_data.partner_region ? action.response_data.partner_region : "";
      state.partner_website = action.response_data.partner_website ? action.response_data.partner_website : "";
      state.partner_contacts = action.response_data.partner_contacts ? action.response_data.partner_contacts : "";
      state.partner_summary = action.response_data.partner_summary ? action.response_data.partner_summary : "";
      state.partnerpic_url = action.response_data.partnerpic_url;

  } else if (action.type === PARTNER_UPDATE_ONUPDATE) {
    state.onupdate.response_data = action.response_data;
    state.onupdate.response_code = action.response_code;

  } else if (action.type === PARTNER_UPDATE_ONCLEAR) {
    state.partner_id = 0;
    state.partner_name = "";
    state.partner_type = "";
    state.partner_region = "";
    state.partner_website = "";
    state.partner_contacts = "";
    state.partner_summary = "";
    state.partnerpic_url = "";

    state.onupdate = {
      response_data: {},
      response_code: 0,
    };
  }

  return state;
}

export const PartnerUpdatePartnerIdOnchangeActionCreator = (partner_id) => {
  return {
    type: PARTNER_UPDATE_PARTNER_ID_ONCHANGE, 
    partner_id: partner_id, 
  }
}

export const PartnerUpdatePartnerNameOnchangeActionCreator = (partner_name) => {
  return {
    type: PARTNER_UPDATE_PARTNER_NAME_ONCHANGE, 
    partner_name: partner_name, 
  }
}

export const PartnerUpdatePartnerTypeOnchangeActionCreator = (partner_type) => {
  return {
    type: PARTNER_UPDATE_PARTNER_TYPE_ONCHANGE, 
    partner_type: partner_type, 
  }
}

export const PartnerUpdatePartnerRegionOnchangeActionCreator = (partner_region) => {
  return {
    type: PARTNER_UPDATE_PARTNER_REGION_ONCHANGE, 
    partner_region: partner_region, 
  }
}

export const PartnerUpdatePartnerWebsiteOnchangeActionCreator = (partner_website) => {
  return {
    type: PARTNER_UPDATE_PARTNER_WEBSITE_ONCHANGE, 
    partner_website: partner_website, 
  }
}

export const PartnerUpdatePartnerContactsOnchangeActionCreator = (partner_contacts) => {
  return {
    type: PARTNER_UPDATE_PARTNER_CONTACTS_ONCHANGE, 
    partner_contacts: partner_contacts, 
  }
}

export const PartnerUpdatePartnerSummaryOnchangeActionCreator = (partner_summary) => {
  return {
    type: PARTNER_UPDATE_PARTNER_SUMMARY_ONCHANGE, 
    partner_summary: partner_summary, 
  }
}

export const PartnerUpdateFilesOnchangeActionCreator = (files) => {
  return {
    type: PARTNER_UPDATE_FILES_ONCHANGE,
    files: files,
  }
}

export const PartnerUpdateOnselectActionCreator = (response_data, response_code) => {
  return {
    type: PARTNER_UPDATE_ONSELECT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const PartnerUpdateOnupdateActionCreator = (response_data, response_code) => {
  return {
    type: PARTNER_UPDATE_ONUPDATE,
    response_data: response_data,
    response_code: response_code,
  }
}

export const PartnerUpdateOnclearActionCreator = () => {
  return {
    type: PARTNER_UPDATE_ONCLEAR,
  }
}

export default PartnerUpdateReducer;
