import { useTranslation } from "react-i18next";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { useEffect } from "react";
import config from "../../config";

const DocumentDeleteComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-document-delete";

  useEffect(() => {
    const offcanvas = document.getElementById(offcanvas_id);

    offcanvas.addEventListener("hide.bs.offcanvas", () => {
      setTimeout(() => { props.DocumentDeleteOnclear() },
      config.offcanvas_refresh_delay);
    });
  }, []);

  const DocumentDeleteOndelete = (event) => {
    event.preventDefault();
    props.DocumentDeleteOndelete();
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title">{ t("offcanvas-document-delete-title") }</h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

          <div className="form-text">
            { t("document-selected") }: { props.document_id ? 1 : props.document_ids.length }
          </div>

          <button onClick={ offcanvas_hide } className="btn btn-outline-primary mt-4" type="button">
            <i className="bi bi-arrow-left"></i> { t("button-cancel") }
          </button>

          <button onClick={ DocumentDeleteOndelete } className="btn btn-danger mt-4 ms-2" type="button" >
            <i className="bi bi-trash3"></i> { t("button-delete") }
          </button>

        </form>
      </div>
    </div>
  );
}

export default DocumentDeleteComponent;
