import { useTranslation } from "react-i18next";
import errors from "../../helpers/errors_helper";
import { useEffect } from "react";
import config from "../../config";

const UserRegisterComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-user-register";

  useEffect(() => {
    const offcanvas = document.getElementById(offcanvas_id);

    offcanvas.addEventListener("shown.bs.offcanvas", () => {
      offcanvas.querySelector(".focused").focus();
    });

    offcanvas.addEventListener("hide.bs.offcanvas", () => {
      setTimeout(() => { props.UserRegisterOnclear() },
      config.offcanvas_refresh_delay);
    });
  }, []);

  const UserRegisterUserLoginOnchange = (event) => {
    props.UserRegisterUserLoginOnchange(event.target.value);
  }

  const UserRegisterUserPasswordOnchange = (event) => {
    props.UserRegisterUserPasswordOnchange(event.target.value);
  }

  const UserRegisterFirstNameOnchange = (event) => {
    props.UserRegisterFirstNameOnchange(event.target.value);
  }

  const UserRegisterLastNameOnchange = (event) => {
    props.UserRegisterLastNameOnchange(event.target.value);
  }

  const UserRegisterAgreementOnclick = () => {
    props.UserRegisterAgreementOnclick();
  }

  const is_valid = (key) => {
    if (key === "user_login") {
      return props.user_login.length >= 2 && props.user_login.length <= 40;

    } else if (key === "user_password") {
      return props.user_password.length >= 6;

    } else if (key === "first_name") {
      return props.first_name.length >= 2 && props.first_name.length <= 40;

    } else if (key === "last_name") {
      return props.last_name.length >= 2 && props.last_name.length <= 40;
    }
  }
 
  const submit_enabled = is_valid("user_login") && is_valid("user_password") && is_valid("first_name") && is_valid("last_name") && props.agreement_accepted;
  const response_errors = errors(props.response_data);

  const UserRegisterOnsubmit = (event) => {
    event.preventDefault();
    if (submit_enabled) {
      props.UserRegisterOnsubmit();
    }
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title">
          { t("offcanvas-user-register-title") }
        </h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body  mb-4">
        <form>

          <div className="form-text">
            { t("offcanvas-user-register-user-login-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ UserRegisterUserLoginOnchange } value={ props.user_login } type="text" className={ "form-control focused" + ("user_login" in response_errors ? " border-danger glow-danger" : is_valid("user_login") ? " border-primary" : "") } placeholder={ t("user-login") } maxLength="40" />
            <label>{ t("user-login") }</label>
          </div>
          <div className="form-text text-danger">
            { "user_login" in response_errors && t("error_" + response_errors["user_login"]) }
          </div>

          <div className="form-text mt-4">
            { t("offcanvas-user-register-user-password-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ UserRegisterUserPasswordOnchange } value={ props.user_password } type="password" className={ "form-control" + ("user_password" in response_errors ? " border-danger glow-danger" : is_valid("user_password") ? " border-primary" : "") } placeholder={ t("user-password") } />
            <label>{ t("user-password") }</label>
          </div>
          <div className="form-text text-danger">
            { "user_password" in response_errors && t("error_" + response_errors["user_password"]) }
          </div>

          <div className="form-text mt-4">
            { t("offcanvas-user-register-full-name-text") }
          </div>

          <div className="form-floating mt-2">
            <input onChange={ UserRegisterFirstNameOnchange } value={ props.first_name } type="text" className={ "form-control" + ("first_name" in response_errors ? " border-danger glow-danger" : is_valid("first_name") ? " border-primary" : "") } placeholder={ t("user-first-name") } maxLength="40" />
            <label>{ t("user-first-name") }</label>
          </div>
          <div className="form-text text-danger">
            { "first_name" in response_errors && t("error_" + response_errors["first_name"]) }
          </div>

          <div className="form-floating mt-2">
            <input onChange={ UserRegisterLastNameOnchange } value={ props.last_name } type="text" className={ "form-control" + ("last_name" in response_errors ? " border-danger glow-danger" : is_valid("last_name") ? " border-primary" : "") } placeholder={ t("user-last-name") } maxLength="40" />
            <label>{ t("user-last-name") }</label>
          </div>
          <div className="form-text text-danger">
            { "last_name" in response_errors && t("error_" + response_errors["last_name"]) }
          </div>

          <div className="form-floating mt-4">
            <div className="form-check">
              <input onChange={ UserRegisterAgreementOnclick } checked={ props.agreement_accepted } className="form-check-input" type="checkbox" value="" id="user-register-agreement" />
              <label className="form-check-label form-text" htmlFor="user-register-agreement">
                { t("offcanvas-user-register-agreement-text") }
              </label>
            </div>
          </div>

          <button className="btn btn-outline-primary mt-4" type="button">
            <i className="bi bi-arrow-left"></i> { t("button-cancel") }
          </button>

          <button onClick={ UserRegisterOnsubmit } className={"btn btn-primary mt-4 ms-2 " + (!submit_enabled ? "disabled" : "")} type="submit">
            <i className="bi bi-check2"></i> { t("button-submit") }
          </button>

        </form>
      </div>
    </div>
  );
}

export default UserRegisterComponent;
