const DOCUMENT_UPDATE_DOCUMENT_ID_ONCHANGE = "DOCUMENT_UPDATE_DOCUMENT_ID_ONCHANGE";
const DOCUMENT_UPDATE_IS_FLAGGED_ONCHANGE = "DOCUMENT_UPDATE_IS_FLAGGED_ONCHANGE";
const DOCUMENT_UPDATE_DOCUMENT_FILENAME_ONCHANGE = "DOCUMENT_UPDATE_DOCUMENT_FILENAME_ONCHANGE";
const DOCUMENT_UPDATE_DOCUMENT_SUMMARY_ONCHANGE = "DOCUMENT_UPDATE_DOCUMENT_SUMMARY_ONCHANGE";
const DOCUMENT_UPDATE_DOCUMENT_TAGS_ONCHANGE = "DOCUMENT_UPDATE_DOCUMENT_TAGS_ONCHANGE";
const DOCUMENT_UPDATE_FILES_ONCHANGE = "DOCUMENT_UPDATE_FILES_ONCHANGE";
const DOCUMENT_UPDATE_COLLECTION_DATALIST_COLLECTION_NAME_ONCHANGE = "DOCUMENT_UPDATE_COLLECTION_DATALIST_COLLECTION_NAME_ONCHANGE";
const DOCUMENT_UPDATE_COLLECTION_DATALIST_COLLECTION_ID_ONCHANGE = "DOCUMENT_UPDATE_COLLECTION_DATALIST_COLLECTION_ID_ONCHANGE";
const DOCUMENT_UPDATE_COLLECTION_DATALIST_ONLOAD = "DOCUMENT_UPDATE_COLLECTION_DATALIST_ONLOAD";
const DOCUMENT_UPDATE_PARTNER_DATALIST_PARTNER_NAME_ONCHANGE = "DOCUMENT_UPDATE_PARTNER_DATALIST_PARTNER_NAME_ONCHANGE";
const DOCUMENT_UPDATE_PARTNER_DATALIST_PARTNER_ID_ONCHANGE = "DOCUMENT_UPDATE_PARTNER_DATALIST_PARTNER_ID_ONCHANGE";
const DOCUMENT_UPDATE_PARTNER_DATALIST_ONLOAD = "DOCUMENT_UPDATE_PARTNER_DATALIST_ONLOAD";
const DOCUMENT_UPDATE_ONSELECT = "DOCUMENT_UPDATE_ONSELECT";
const DOCUMENT_UPDATE_ONUPDATE = "DOCUMENT_UPDATE_ONUPDATE";
const DOCUMENT_UPDATE_ONCLEAR = "DOCUMENT_UPDATE_ONCLEAR";

const initial = {
  document_id: 0,
  is_flagged: false,
  document_filename: "",
  document_summary: "",
  document_tags: "",
  files: [],
  thumbnail_url: "",
  collection_datalist: {
    collection_name: "",
    collection_id: 0,
    response_data: {},
    response_code: 0,
  },
  partner_datalist: {
    partner_name: "",
    partner_id: 0,
    response_data: {},
    response_code: 0,
  },
  onupdate: {
    response_data: {},
    response_code: 0,
  },
};

const DocumentUpdateReducer = (state = initial, action) => {
  
  if (action.type === DOCUMENT_UPDATE_DOCUMENT_ID_ONCHANGE) {
    state.document_id = parseInt(action.document_id);
    
  } else if (action.type === DOCUMENT_UPDATE_IS_FLAGGED_ONCHANGE) {
    state.is_flagged = !state.is_flagged;

  } else if (action.type === DOCUMENT_UPDATE_DOCUMENT_FILENAME_ONCHANGE) {
    state.document_filename = action.document_filename;
    
  } else if (action.type === DOCUMENT_UPDATE_DOCUMENT_SUMMARY_ONCHANGE) {
    state.document_summary = action.document_summary;
    
  } else if (action.type === DOCUMENT_UPDATE_DOCUMENT_TAGS_ONCHANGE) {
    state.document_tags = action.document_tags;
    
  } else if (action.type === DOCUMENT_UPDATE_FILES_ONCHANGE) {
    state.files = action.files;

  } else if (action.type === DOCUMENT_UPDATE_COLLECTION_DATALIST_COLLECTION_NAME_ONCHANGE) {
    state.collection_datalist.collection_name = action.collection_name;

  } else if (action.type === DOCUMENT_UPDATE_COLLECTION_DATALIST_COLLECTION_ID_ONCHANGE) {
    state.collection_datalist.collection_id = action.collection_id;
    state.collection_datalist.collection_name = action.collection_name;

  } else if (action.type === DOCUMENT_UPDATE_COLLECTION_DATALIST_ONLOAD) {
    state.collection_datalist.response_data = action.response_data;
    state.collection_datalist.response_code = action.response_code;

    const collection = Array.prototype.find.call(action.response_data.collections, el => {
      return el.collection_name.toLocaleLowerCase() === state.collection_datalist.collection_name.toLocaleLowerCase();
    });
    state.collection_datalist.collection_id = collection ? collection.id : 0;

  } else if (action.type === DOCUMENT_UPDATE_PARTNER_DATALIST_PARTNER_NAME_ONCHANGE) {
    state.partner_datalist.partner_name = action.partner_name;

  } else if (action.type === DOCUMENT_UPDATE_PARTNER_DATALIST_PARTNER_ID_ONCHANGE) {
    state.partner_datalist.partner_id = action.partner_id;
    state.partner_datalist.partner_name = action.partner_name;

  } else if (action.type === DOCUMENT_UPDATE_PARTNER_DATALIST_ONLOAD) {
    state.partner_datalist.response_data = action.response_data;
    state.partner_datalist.response_code = action.response_code;

    const partner = Array.prototype.find.call(action.response_data.partners, el => {
      return el.partner_name.toLocaleLowerCase() === state.partner_datalist.partner_name.toLocaleLowerCase();
    });
    state.partner_datalist.partner_id = partner ? partner.id : 0;

  } else if (action.type === DOCUMENT_UPDATE_ONSELECT) {
    state.is_flagged = action.response_data.is_flagged;
    state.document_filename = action.response_data.document_filename;
    state.document_summary = action.response_data.document_summary;
    state.document_tags = action.response_data.document_tags.join(", ");
    state.thumbnail_url = action.response_data.thumbnail_url;

    state.collection_datalist.collection_id = action.response_data.collection_id;
    state.collection_datalist.collection_name = action.response_data.collection_name;

    if (action.response_data.partner_id) {
      state.partner_datalist.partner_id = action.response_data.partner_id;
      state.partner_datalist.partner_name = action.response_data.partner_name;
    }

  } else if (action.type === DOCUMENT_UPDATE_ONUPDATE) {
    state.onupdate.response_data = action.response_data;
    state.onupdate.response_code = action.response_code;

  } else if (action.type === DOCUMENT_UPDATE_ONCLEAR) {
    state.document_id = 0;
    state.is_flagged = false;
    state.document_filename = "";
    state.document_summary = "";
    state.document_tags = "";
    state.thumbnail_url = "";

    state.onupdate.response_data = {};
    state.onupdate.response_code = 0;

    state.collection_datalist.collection_name = "";
    state.collection_datalist.collection_id = 0;
    state.collection_datalist.response_data = {};
    state.collection_datalist.response_code = 0;

    state.partner_datalist.partner_name = "";
    state.partner_datalist.partner_id = 0;
    state.partner_datalist.response_data = {};
    state.partner_datalist.response_code = 0;
  }

  return state;
}

export const DocumentUpdateDocumentIdOnchangeActionCreator = (document_id) => {
  return {
    type: DOCUMENT_UPDATE_DOCUMENT_ID_ONCHANGE,
    document_id: document_id, 
  }
}

export const DocumentUpdateIsFlaggedOnchangeActionCreator = () => {
  return {
    type: DOCUMENT_UPDATE_IS_FLAGGED_ONCHANGE,
  }
}

