export const DocumentUpdateOnselectActionCreator = (response_data, response_code) => {
  return {
    type: DOCUMENT_UPDATE_ONSELECT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const DocumentUpdateOnupdateActionCreator = (response_data, response_code) => {
  return {
    type: DOCUMENT_UPDATE_ONUPDATE,
    response_data: response_data,
    response_code: response_code,
  }
}

export const DocumentUpdateOnclearActionCreator = () => {
  return {
    type: DOCUMENT_UPDATE_ONCLEAR,
  }
}

export default DocumentUpdateReducer;
