import {
  PartnerSelectOnselectActionCreator,
  PartnerSelectOnclearActionCreator } from "../../reducers/partner_select_reducer";
import { PartnerUpdatePartnerIdOnchangeActionCreator } from "../../reducers/partner_update_reducer";
import { PartnerDeletePartnerIdOnchangeActionCreator } from "../../reducers/partner_delete_reducer";
import { UserSelectUserIdOnchangeActionCreator } from "../../reducers/user_select_reducer";
import PartnerSelectComponent from "../../components/partner/partner_select_component";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { log } from "../../helpers/log_helper";
import redirect from "../../helpers/redirect_helper";

const PartnerSelectMiddleware = (props) => {
  const navigate = useNavigate();

  const PartnerSelectOnselect = () => {
    const log_prefix = "partner-select-onselect";

    axios({
      method: "get",
      url: config.server_host + "partner/" + props.store.getState().partner_select.partner_id, 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      params: {},

    }).then((response) => {
      log.debug(log_prefix, response);

      const action = PartnerSelectOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);
      
    }).catch(e => {
      log.error(log_prefix, e);
      redirect(e, navigate);
    });
  }

  const PartnerSelectOnclear = () => {
    const action = PartnerSelectOnclearActionCreator();
    props.store.dispatch(action);
  }

  const PartnerUpdatePartnerIdOnchange = (partner_id) => {
    const action = PartnerUpdatePartnerIdOnchangeActionCreator(partner_id);
    props.store.dispatch(action);
  }

  const PartnerDeletePartnerIdOnchange = (partner_id) => {
    const action = PartnerDeletePartnerIdOnchangeActionCreator(partner_id);
    props.store.dispatch(action);
  }

  const UserSelectUserIdOnchange = (user_id) => {
    const action = UserSelectUserIdOnchangeActionCreator(user_id);
    props.store.dispatch(action);
  }

  return (
    <PartnerSelectComponent
      user_timezone={ props.store.getState().app.user_timezone }
      user_role={ props.store.getState().app.token_payload.user_role }

      partner_id={ props.store.getState().partner_select.partner_id }
      response_data={ props.store.getState().partner_select.onselect.response_data }
      response_code={ props.store.getState().partner_select.onselect.response_code }

      PartnerSelectOnselect={ PartnerSelectOnselect }
      PartnerSelectOnclear={ PartnerSelectOnclear }
      PartnerUpdatePartnerIdOnchange={ PartnerUpdatePartnerIdOnchange }
      PartnerDeletePartnerIdOnchange={ PartnerDeletePartnerIdOnchange }
      UserSelectUserIdOnchange={ UserSelectUserIdOnchange }
    />
  );
}
  
export default PartnerSelectMiddleware;
