const USER_TOTP_USER_LOGIN_ONCHANGE = "USER_TOTP_USER_LOGIN_ONCHANGE";
const USER_TOTP_USER_TOTP_ONCHANGE = "USER_TOTP_USER_TOTP_ONCHANGE";
const USER_TOTP_TOKEN_UNEXPIRED_ONCLICK = "USER_TOTP_TOKEN_UNEXPIRED_ONCLICK";
const USER_TOTP_ONSUBMIT = "USER_TOTP_ONSUBMIT";
const USER_TOTP_ONCLEAR = "USER_TOTP_ONCLEAR";

const initial = {
  user_login: "",
  user_totp: "",
  token_unexpired: false,
  ontotp: {
    response_data: {},
    response_code: {},
  },
};

const UserTotpReducer = (state = initial, action) => {

  if (action.type === USER_TOTP_USER_LOGIN_ONCHANGE) {
    state.user_login = action.user_login;

  } else if (action.type === USER_TOTP_USER_TOTP_ONCHANGE) {
    state.user_totp = action.user_totp;

  } else if (action.type === USER_TOTP_TOKEN_UNEXPIRED_ONCLICK) {
    state.token_unexpired = !state.token_unexpired;

  } else if (action.type === USER_TOTP_ONSUBMIT) {
    state.ontotp.response_data = action.response_data;
    state.ontotp.response_code = action.response_code;

  } else if (action.type === USER_TOTP_ONCLEAR) {
    state.user_login = "";
    state.user_totp = "";
    state.token_unexpired = false;

    state.ontotp.response_data = {};
    state.ontotp.response_code = 0;
  }

  return state;
}

export const UserTotpUserLoginOnchangeActionCreator = (user_login) => {
  return {
    type: USER_TOTP_USER_LOGIN_ONCHANGE,
    user_login: user_login,
  }
}

export const UserTotpUserTotpOnchangeActionCreator = (user_totp) => {
  return {
    type: USER_TOTP_USER_TOTP_ONCHANGE,
    user_totp: user_totp,
  }
}

export const UserTotpTokenUnexpiredOnclickActionCreator = () => {
  return {
    type: USER_TOTP_TOKEN_UNEXPIRED_ONCLICK,
  }
}

export const UserTotpOnsubmitActionCreator = (response_data, response_code) => {
  return {
    type: USER_TOTP_ONSUBMIT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const UserTotpOnclearActionCreator = () => {
  return {
    type: USER_TOTP_ONCLEAR,
  }
}

export default UserTotpReducer;
