const TELEMETRY_ONSELECT = "TELEMETRY_ONSELECT";
const TELEMETRY_ONCLEAR = "TELEMETRY_ONCLEAR";

const initial = {
  onselect: {
    response_data: {},
    response_code: 0,
  },
};

const TelemetrySelectReducer = (state = initial, action) => {

  if (action.type === TELEMETRY_ONSELECT) {
    state.onselect.response_data = action.response_data;
    state.onselect.response_code = action.response_code;

  } else if (action.type === TELEMETRY_ONCLEAR) {
    state.onselect.response_data = {};
    state.onselect.response_code = 0;
  }

  return state;
}

export const TelemetryOnselectActionCreator = (response_data, response_code) => {
  return {
      type: TELEMETRY_ONSELECT,
      response_data: response_data,
      response_code: response_code,
    }
}

export const TelemetryOnclearActionCreator = () => {
  return {
    type: TELEMETRY_ONCLEAR,
  }
}

export default TelemetrySelectReducer;
