import { useTranslation } from "react-i18next";
import config from "../../config";
import empty from "../../helpers/empty_helper";
import { NavLink } from 'react-router-dom';
import datetime from "../../helpers/datetime_helper";
import { can_read, can_write, can_edit, can_admin } from "../../helpers/role_helper"
import DatatableComponent from "../datatable_component";
import DatacardsComponent from "../datacards_component";
import PaginationComponent from "../pagination_component";
import DatalistMiddleware from "../../middleware/datalist_middleware";
import {
  DocumentFilterUserDatalistOnloadActionCreator,
  DocumentFilterCollectionDatalistOnloadActionCreator,
  DocumentFilterPartnerDatalistOnloadActionCreator,
  DocumentFilterOnresetActionCreator } from "../../reducers/document_list_reducer";
import { useNavigate } from "react-router-dom";
import filesize from "../../helpers/filesize_helper";
import { offcanvas_show } from "../../helpers/offcanvas_helper";

let timer;

const DocumentsListComponent = (props) => {
  const { t } = useTranslation();
  const navigate = useNavigate();

  // Load documents
  const DocumentListOnselect = () => {
    props.DocumentListOnselect();
  }

  // Initial documents loading
  if (empty(props.response_data) && !empty(props.user_token)) {
    DocumentListOnselect();
  }

  // Clear list
  const DocumentListOnclear = () => {
    props.DocumentListOnclear();
  }

  // Change limit
  const DocumentListLimitOnchange = (limit) => {
    props.DocumentListLimitOnchange(limit);
  }

  // Change offset
  const DocumentListOffsetOnchange = (offset) => {
    props.DocumentListOffsetOnchange(offset);
  }

  // Change order
  const DocumentListOrderOnchange = (event) => {
    const order_by = event.target.dataset.order_by;
    props.DocumentListOrderOnchange(order_by);
    DocumentListOnclear();
  }

  // Change view
  const DocumentListViewOnchange = (event) => {
    const view = event.target.dataset.view;
    props.DocumentListViewOnchange(view);
  }

  // search delay
  const TimerStart = () => {
    clearTimeout(timer);
    timer = setTimeout(() => {
      DocumentListOnclear();
    }, config.input_latency);
  }

  // Filter by document name.
  const DocumentFilterDocumentFilenameOnchange = (event) => {
    const document_filename = event.target.value;
    props.DocumentFilterDocumentFilenameOnchange(document_filename);
    TimerStart();
  }

  // Filter by document mimetype.
  const DocumentFilterDocumentMimetypeOnchange = (event) => {
    const document_mimetype = event.target.value;
    props.DocumentFilterDocumentMimetypeOnchange(document_mimetype);
    TimerStart();
  }

  // Click document link
  const DocumentSelectDocumentIdOnchange = (event) => {
    const document_id = event.target.dataset.document_id;
    props.DocumentSelectDocumentIdOnchange(document_id);
    offcanvas_show("offcanvas-document-select");
  }

  const filters_count = ((props.filter.user_datalist.user_id > 0) + (props.filter.collection_datalist.collection_id > 0) + (props.filter.partner_datalist.partner_id > 0) + (props.filter.document_mimetype !== "") + (props.filter.document_filename !== "")) || null;

  const columns = [
    { name: t("id"), order_by: "id" },
    { name: "" },
    { name: t("created-date"), order_by: "created_date" },
    { name: t("document-user") },
    { name: t("document-filename"), order_by: "document_filename" },
    { name: t("document-mimetype"), order_by: "document_mimetype" },
    { name: t("document-size"), order_by: "document_size" },
    { name: t("document-comments-count"), order_by: "comments_count" },
  ];

  const rows = props.response_data?.documents?.map(document => { 
    return [
      document.id,
      document.is_flagged ? <i className="bi bi-flag-fill"></i> : "",
      datetime(document.created_date, props.user_timezone, t),
      document.user_name,
      <span role="button" className="link-primary" data-document_id={ document.id } onClick={ DocumentSelectDocumentIdOnchange }>{ document.document_filename }</span>,
      document.document_mimetype,
      filesize(document.document_size, t),
      document.comments_count,
    ];
  });

  const cards = props.response_data?.documents?.map(document => { 
    return {
      user_id: document.user_id,
      user_name: document.user_name,
      id: document.id,
      document_filename: document.document_filename,
      document_size: document.document_size,
      comments_count: document.comments_count,
      thumbnail_url: document.thumbnail_url,
    };
  });

  // // categories error
  // let categories_error;
  // if (!empty(props.response_data) && props.count === 0 ) {
  //   categories_error = t("list-empty");

  // } else if (!empty(props.response_code)) {
  //   categories_error = t("list-error");
  // }

  const CollectionSelectCollectionIdOnchange = (event) => {
    const collection_id = event.target.dataset.collection_id;
    props.CollectionSelectCollectionIdOnchange(collection_id);
    offcanvas_show("offcanvas-collection-select");
  }

  // Reset filters.
  const ResetFilters = () => {
    props.DocumentListOffsetOnchange(0);
    props.DocumentFilterOnreset();
    props.DocumentListOnclear();
  }

  return <>
    <h1 className="mb-4">
      { t("page-documents-title") }
      <i className={ "bi bi-arrow-right-short" + (props.filter.collection_datalist.collection_id > 0 ? "" : " d-none") }></i>
      { props.filter.collection_datalist.collection_id > 0 ? <a href="#" className="text-decoration-none" data-collection_id={ props.filter.collection_datalist.collection_id } onClick={ event => { CollectionSelectCollectionIdOnchange(event) } }>{ props.filter.collection_datalist.collection_name }</a> : "" }
    </h1>

    <div className="d-flex d-inline align-items-center mb-4">
      <div className="btn-group btn-group-outline">
        <button type="button" className="btn btn-outline-primary" data-bs-toggle="collapse" href="#documents-filters">
          <i className="bi bi-sliders2"></i> { t("button-filters") } <span className="badge text-bg-primary">{ filters_count }</span>
        </button>

        <button type="button" className="btn btn-outline-primary" onClick={ ResetFilters }>
          <i className="bi bi-x-lg"></i> { t("button-reset") }
        </button>
      </div>

      <a type="button" className="btn btn-outline-primary ms-3" href="#offcanvas-document-insert" data-bs-toggle="offcanvas">
        <i className="bi bi-plus-lg"></i> { t("page-documents-add") }
      </a>

      <div className="dropdown ms-3">
        <a href="#" className="link link-primary text-decoration-none dropdown-toggle" type="button" data-bs-toggle="dropdown" aria-expanded="false">
          <i className="bi bi-arrow-down-up"></i> { t("page-documents-sort") }
        </a>
        <ul className="dropdown-menu" style={{ margin:0, "--bs-dropdown-min-width": "6rem" }}>
          <li>
            <a href="#" onClick={ DocumentListOrderOnchange } data-order_by="id" className="dropdown-item link-primary me-1" role="button">
              { t("id") }
              <span className="text-secondary ms-1">
                { props.order_by === "id" && (props.order === "asc" ? <i className="bi bi-arrow-down"></i> : <i className="bi bi-arrow-up"></i>) }
              </span>
            </a>
          </li>
          <li>
            <a href="#" onClick={ DocumentListOrderOnchange } data-order_by="created_date" className="dropdown-item link-primary me-1" role="button">
              created_date
              <span className="text-secondary ms-1">
                { props.order_by === "created_date" && (props.order === "asc" ? <i className="bi bi-arrow-down"></i> : <i className="bi bi-arrow-up"></i>) }
              </span>
            </a>
          </li>
          <li>
            <a href="#" onClick={ DocumentListOrderOnchange } data-order_by="document_filename" className="dropdown-item link-primary me-1" role="button">
              document_filename
              <span className="text-secondary ms-1">
                { props.order_by === "document_filename" && (props.order === "asc" ? <i className="bi bi-arrow-down"></i> : <i className="bi bi-arrow-up"></i>) }
              </span>
            </a>
          </li>
          <li>
            <a href="#" onClick={ DocumentListOrderOnchange } data-order_by="document_size" className="dropdown-item link-primary me-1" role="button">
              document_size
              <span className="text-secondary ms-1">
                { props.order_by === "document_size" && (props.order === "asc" ? <i className="bi bi-arrow-down"></i> : <i className="bi bi-arrow-up"></i>) }
              </span>
            </a>
          </li>
          <li>
            <a href="#" onClick={ DocumentListOrderOnchange } data-order_by="document_mimetype" className="dropdown-item link-primary me-1" role="button">
              document_mimetype
              <span className="text-secondary ms-1">
                { props.order_by === "document_mimetype" && (props.order === "asc" ? <i className="bi bi-arrow-down"></i> : <i className="bi bi-arrow-up"></i>) }
              </span>
            </a>
          </li>
          <li>
            <a href="#" onClick={ DocumentListOrderOnchange } data-order_by="comments_count" className="dropdown-item link-primary me-1" role="button">
              comments_count
              <span className="text-secondary ms-1">
                { props.order_by === "comments_count" && (props.order === "asc" ? <i className="bi bi-arrow-down"></i> : <i className="bi bi-arrow-up"></i>) }
              </span>
            </a>
          </li>
        </ul>
      </div>

      <div className="dropdown ms-3">
        <a href="#" className="link link-primary text-decoration-none dropdown-toggle" type="button" data-bs-toggle="dropdown" aria-expanded="false">
          <i className={"bi " + ( props.view === "list" ? "bi-list" : "bi-grid" ) }></i> { t("page-documents-view") }
        </a>
        <ul className="dropdown-menu" style={{ margin:0, "--bs-dropdown-min-width": "6rem" }}>
          <li><a className="dropdown-item" href="#" onClick={ DocumentListViewOnchange } data-view="cards"><i className="bi bi-grid"></i> Cards</a></li>
          <li><a className="dropdown-item" href="#" onClick={ DocumentListViewOnchange } data-view="list"><i className="bi bi-list"></i> List</a></li>
        </ul>
      </div>

      <a href="#" className="link-primary text-decoration-none ms-3" onClick={ DocumentListOnclear }>
        <i className="bi bi-arrow-clockwise"></i> { t("button-refresh") }
      </a>

      <div className={ "ms-5" + (props.document_ids.length > 0 ? "" : " d-none") }>
        Selected documents <span className="badge text-bg-primary">{ props.document_ids.length }</span>
      </div>

      <a type="button" className={ "btn btn-outline-primary ms-3" + ( props.document_ids.length > 0 && can_edit(props.token_payload.user_role) ? "" : " d-none" ) } data-bs-toggle="offcanvas" href="#offcanvas-document-move">
        <i className="bi bi-arrow-left-right"></i> Move
      </a>

      <a type="button" className={ "btn btn-outline-danger ms-3" + ( props.document_ids.length > 0 && can_admin(props.token_payload.user_role) ? "" : " d-none" ) } data-bs-toggle="offcanvas" href="#offcanvas-document-delete">
        <i className="bi bi-trash3"></i> Delete
      </a>

    </div>

    <div className="collapse" id="documents-filters">
      <div className="row">
        <div className="col-12 mb-4">
          <div className="form-floating">
            <input onChange={ DocumentFilterDocumentFilenameOnchange } type="search" className={ "form-control" + (props.filter.document_filename ? " border-primary" : "") } id="floatingInput" placeholder={ t("filter-document-filename") } value={ props.filter.document_filename } />
            <label htmlFor="floatingInput">{ t("filter-document-filename") }</label>
          </div>
        </div>
      </div>

      <div className="row">
        <div className="col-3 mb-4">
          <DatalistMiddleware
            dispatch={ props.dispatch }
            user_token={ props.user_token }
            // datalist data
            datalist_name="document-list-collection-datalist"
            datalist_placeholder={ t("filter-document-collection") }
            datalist_value={ props.filter.collection_datalist.collection_name }
            datalist_id={ props.filter.collection_datalist.collection_id }
            response_data={ props.filter.collection_datalist.response_data }
            response_code={ props.filter.collection_datalist.response_code }
            datalist_options={ !empty(props.filter.collection_datalist.response_data) ? props.filter.collection_datalist.response_data.collections.map(el => { return { id: el.id, value: el.collection_name } }) : [] }
            // // request
            request_url={ config.server_host + "collections" }
            request_param="collection_name__ilike"
            request_order_by="collection_name"
            request_order="asc"
            // // datalist actions
            datalist_onchange={ props.DocumentFilterCollectionDatalistCollectionNameOnchange }
            datalist_onload_action_creator={ DocumentFilterCollectionDatalistOnloadActionCreator }
            onupdate={ () => { DocumentListOffsetOnchange(0); DocumentListOnclear(); } }
          />
        </div>

        <div className="col-3 mb-4">
          <DatalistMiddleware
            dispatch={ props.dispatch }
            user_token={ props.user_token }
            // datalist data
            datalist_name="document-list-partner-datalist"
            datalist_placeholder={ t("filter-document-partner") }
            datalist_value={ props.filter.partner_datalist.partner_name }
            datalist_id={ props.filter.partner_datalist.partner_id }
            response_data={ props.filter.partner_datalist.response_data }
            response_code={ props.filter.partner_datalist.response_code }
            datalist_options={ !empty(props.filter.partner_datalist.response_data) ? props.filter.partner_datalist.response_data.partners.map(el => { return { id: el.id, value: el.partner_name } }) : [] }
            // // request
            request_url={ config.server_host + "partners" }
            request_param="partner_name__ilike"
            request_order_by="partner_name"
            request_order="asc"
            // // datalist actions
            datalist_onchange={ props.DocumentFilterPartnerDatalistPartnerNameOnchange }
            datalist_onload_action_creator={ DocumentFilterPartnerDatalistOnloadActionCreator }
            onupdate={ () => { DocumentListOffsetOnchange(0); DocumentListOnclear(); } }
          />
        </div>

        <div className="col-3 mb-4">
          <DatalistMiddleware
            dispatch={ props.dispatch }
            user_token={ props.user_token }
            // datalist data
            datalist_name="document-list-user-datalist"
            datalist_placeholder={ t("filter-document-user") }
            datalist_value={ props.filter.user_datalist.user_name }
            datalist_id={ props.filter.user_datalist.user_id }
            response_data={ props.filter.user_datalist.response_data }
            response_code={ props.filter.user_datalist.response_code }
            datalist_options={ !empty(props.filter.user_datalist.response_data) ? props.filter.user_datalist.response_data.users.map(el => { return { id: el.id, value: el.first_name + " " + el.last_name } }) : [] }
            // // request
            request_url={ config.server_host + "users" }
            request_param="full_name__ilike"
            request_order_by="full_name"
            request_order="asc"
            // // datalist actions
            datalist_onchange={ props.DocumentFilterUserDatalistUserNameOnchange }
            datalist_onload_action_creator={ DocumentFilterUserDatalistOnloadActionCreator }
            onupdate={ () => { DocumentListOffsetOnchange(0); DocumentListOnclear(); } }
          />
        </div>

        <div className="col-3 mb-4">
          <div className="form-floating">
            <input onChange={ DocumentFilterDocumentMimetypeOnchange } type="search" className={ "form-control" + (props.filter.document_mimetype ? " border-primary" : "") } id="floatingInput" placeholder={ t("filter-document-mimetype") } value={ props.filter.document_mimetype } />
            <label htmlFor="floatingInput">{ t("filter-document-mimetype") }</label>
          </div>
        </div>
      </div>
    </div>

    { props.view === "list" ?
      <DatatableComponent
        limit={ props.limit }
        order_by={ props.order_by }
        order={ props.order }
        order_onchange={ DocumentListOrderOnchange }
        columns={ columns }
        rows={ rows }
        onselect={ (id) => { props.DocumentDeleteDocumentIdsOnshift(id); props.DocumentMoveDocumentIdsOnshift(id); } }
        selected_rows={ props.document_ids }
        can_select={ can_edit(props.token_payload.user_role) }
      />
    :
      <DatacardsComponent
        limit={ props.limit }
        cards={ cards }
        onselect={ (id) => { props.DocumentDeleteDocumentIdsOnshift(id); props.DocumentMoveDocumentIdsOnshift(id); } }
        selected_elements={ props.document_ids }
        can_select={ can_edit(props.token_payload.user_role) }
        onclick={ DocumentSelectDocumentIdOnchange }
      />
    }

    <PaginationComponent
      offset={ props.offset } 
      limit={ props.limit }
      limit_values={ config.allowed_documents_limit }
      count={ props.response_data.documents_count }
      offset_onchange={ DocumentListOffsetOnchange } 
      limit_onchange={ DocumentListLimitOnchange }
      onclear={ DocumentListOnclear }
    />

  </>;
}

export default DocumentsListComponent;
