const USER_SELECT_USER_ID_ONCHANGE = "USER_SELECT_USER_ID_ONCHANGE";
const USER_SELECT_ONSELECT = "USER_SELECT_ONSELECT";
const USER_SELECT_ONCLEAR = "USER_SELECT_ONCLEAR";

const initial = {
  user_id: 0,
  onselect: {
    response_data: {},
    response_code: 0,
  },
};

const UserSelectReducer = (state = initial, action) => {

  if (action.type === USER_SELECT_USER_ID_ONCHANGE) {
    state.user_id = parseInt(action.user_id);
  
  } else if (action.type === USER_SELECT_ONSELECT) {
    state.onselect.response_data = action.response_data;
    state.onselect.response_code = action.response_code;
  
  } else if (action.type === USER_SELECT_ONCLEAR) {
    state.user_id = 0;
    state.onselect.response_data = {};
    state.onselect.response_code = 0;
  }

  return state;
}

export const UserSelectUserIdOnchangeActionCreator = (user_id) => {
  return {
    type: USER_SELECT_USER_ID_ONCHANGE,
    user_id: user_id,
  }
}

export const UserSelectOnselectActionCreator = (response_data, response_code) => {
  return {
    type: USER_SELECT_ONSELECT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const UserSelectOnclearActionCreator = () => {
  return {
    type: USER_SELECT_ONCLEAR,
  }
}

export default UserSelectReducer;
