const COLLECTION_INSERT_COLLECTION_NAME_ONCHANGE = "COLLECTION_INSERT_COLLECTION_NAME_ONCHANGE";
const COLLECTION_INSERT_COLLECTION_SUMMARY_ONCHANGE = "COLLECTION_INSERT_COLLECTION_SUMMARY_ONCHANGE";
const COLLECTION_INSERT_IS_LOCKED_ONCHANGE = "COLLECTION_INSERT_IS_LOCKED_ONCHANGE";
const COLLECTION_INSERT_ONINSERT = "COLLECTION_INSERT_ONINSERT";
const COLLECTION_INSERT_ONCLEAR = "COLLECTION_INSERT_ONCLEAR";

const initial = {
  collection_name: "",
  collection_summary: "",
  is_locked: false,
  oninsert: {
    response_data: {},
    response_code: 0,
  },
};

const CollectionInsertReducer = (state = initial, action) => {

  if (action.type === COLLECTION_INSERT_COLLECTION_NAME_ONCHANGE) {
    state.collection_name = action.collection_name;

  } else if (action.type === COLLECTION_INSERT_COLLECTION_SUMMARY_ONCHANGE) {
    state.collection_summary = action.collection_summary;

  } else if (action.type === COLLECTION_INSERT_IS_LOCKED_ONCHANGE) {
    state.is_locked = !state.is_locked;

  } else if (action.type === COLLECTION_INSERT_ONINSERT) {
    state.oninsert.response_data = action.response_data;
    state.oninsert.response_code = action.response_code;

  } else if (action.type === COLLECTION_INSERT_ONCLEAR) {
    state.collection_name = "";
    state.collection_summary = "";
    state.is_locked = false;
    state.response_data = {};
    state.response_code = 0;
  }

  return state;
}

export const CollectionInsertCollectionNameOnchangeActionCreator = (collection_name) => {
  return {
    type: COLLECTION_INSERT_COLLECTION_NAME_ONCHANGE, 
    collection_name: collection_name, 
  }
}

export const CollectionInsertCollectionSummaryOnchangeActionCreator = (collection_summary) => {
  return {
    type: COLLECTION_INSERT_COLLECTION_SUMMARY_ONCHANGE,
    collection_summary: collection_summary, 
  }
}

export const CollectionInsertIsLockedOnchangeActionCreator = (is_locked) => {
  return {
    type: COLLECTION_INSERT_IS_LOCKED_ONCHANGE,
    is_locked: is_locked, 
  }
}

export const CollectionInsertOninsertActionCreator = (response_data, response_code) => {
  return {
    type: COLLECTION_INSERT_ONINSERT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const CollectionInsertOnclearActionCreator = () => {
  return {
    type: COLLECTION_INSERT_ONCLEAR,
  }
}

export default CollectionInsertReducer;
