import { useTranslation } from "react-i18next";

const UserSecretComponent = (props) => {
  const { t } = useTranslation();

  const UserSecretOncopy = () => {
    navigator.clipboard.writeText(props.mfa_secret);
  }
  const UserSecretOnclear = () => {
    props.UserSecretOnclear();
  }

  return (
    <div id="offcanvas-user-secret" className="offcanvas offcanvas-start w-35" tabIndex="-1" data-bs-backdrop="static" data-bs-keyboard="false">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title">{ t("offcanvas-user-secret-title") }</h5>
        <button type="button" className="btn-close d-none" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href="#offcanvas-user-secret" ></button>
      </div>
      <div className="offcanvas-body mb-4">

        <div className="form-text">
          { t("offcanvas-user-secret-mfa-image-text") }
        </div>

        <div className="form-text text-center mt-3">
          <img src={ props.mfa_url } alt="MFA" />
        </div>

        <div className="form-text mt-3">
          { t("offcanvas-user-secret-mfa-secret-text") }
        </div>

        <div className="form-text text-center fw-bold mt-3">
          { props.mfa_secret }
        </div>

        <div className="form-text text-center mt-1">
          <span onClick={ UserSecretOncopy } type="button" className="link-secondary">
            { t("button-copy") }
          </span>
        </div>

        <div className="form-text mt-3">
          { t("offcanvas-user-secret-submit-text") }
        </div>

        <button onClick={ UserSecretOnclear } className="btn btn-primary mt-4" type="button">
          <i className="bi bi-check2"></i> { t("button-submit") }
        </button>

      </div>
    </div>
  );
}

export default UserSecretComponent;
