import {
  UserUpdateFirstNameOnchangeActionCreator,
  UserUpdateLastNameOnchangeActionCreator,
  UserUpdateUserContactsOnchangeActionCreator,
  UserUpdateUserCaptionOnchangeActionCreator,
  UserUpdateFilesOnchangeActionCreator,
  UserUpdateOnselectActionCreator,
  UserUpdateOnupdateActionCreator,
  UserUpdateOnclearActionCreator } from "../../reducers/user_update_reducer";
import UserUpdateComponent from "../../components/user/user_update_component";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import { log } from "../../helpers/log_helper";
import redirect from "../../helpers/redirect_helper";
import { UserListOnclearActionCreator } from "../../reducers/user_list_reducer";

const UserUpdateMiddleware = (props) => {
  const navigate = useNavigate();

  const UserUpdateFirstNameOnchange = (first_name) => {
    const action = UserUpdateFirstNameOnchangeActionCreator(first_name);
    props.store.dispatch(action);
  }

  const UserUpdateLastNameOnchange = (last_name) => {
    const action = UserUpdateLastNameOnchangeActionCreator(last_name);
    props.store.dispatch(action);
  }

  const UserUpdateUserContactsOnchange = (user_contacts) => {
    const action = UserUpdateUserContactsOnchangeActionCreator(user_contacts);
    props.store.dispatch(action);
  }

  const UserUpdateUserCaptionOnchange = (user_caption) => {
    const action = UserUpdateUserCaptionOnchangeActionCreator(user_caption);
    props.store.dispatch(action);
  }

  const UserUpdateFilesOnchange = (files) => {
    const log_prefix = "user-update-onuserpic";

    const formData = new FormData();
    formData.append("file", Array.from(files)[0]);

    axios({
      method: "post",
      url: config.server_host + "user/" + props.store.getState().app.token_payload.user_id + "/userpic", 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      data: formData,

    }).then(response => {
      log.debug(log_prefix, response);

      const action = UserUpdateFilesOnchangeActionCreator("");
      props.store.dispatch(action);

      UserUpdateOnselect();
      
    }).catch(e => {
      log.error(log_prefix, e);
    });
  }

  const UserUpdateOnselect = () => {
    const log_prefix = "user-update-onselect";

    axios({
      method: "get",
      url: config.server_host + "user/" + props.store.getState().app.token_payload.user_id,
      headers: { Authorization : "Bearer " + props.store.getState().app.user_token },

    }).then(response => {
      let action = UserUpdateOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);

    }).catch(e => {
      log.error(log_prefix, e);
      redirect(e, navigate);
    });
  }


  const UserUpdateOnupdate = () => {
    const offcanvas_name = "offcanvas-user-update";
    const log_prefix = "user-update-onupdate";
    buttons_disable(offcanvas_name);

    axios({
      method: "put",
      url: config.server_host + "user/" + props.store.getState().app.token_payload.user_id,
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      data: {
        first_name: props.store.getState().user_update.first_name,
        last_name: props.store.getState().user_update.last_name,
        user_contacts: props.store.getState().user_update.user_contacts,
        user_caption: props.store.getState().user_update.user_caption,
      },

    }).then(response => {
      log.debug(log_prefix, response);

      buttons_enable(offcanvas_name);
      offcanvas_hide();
      
      let action = UserUpdateOnupdateActionCreator(response.data, response.status);
      props.store.dispatch(action);

      UserListOnclear();

    }).catch(e => {
      log.error(log_prefix, e);

      buttons_enable(offcanvas_name);

      if (e.status === 422) {
        const action = UserUpdateOnupdateActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }

    });
  }

  const UserUpdateOnclear = () => {
    const action = UserUpdateOnclearActionCreator();
    props.store.dispatch(action);
  }

  const UserListOnclear = () => {
    const action = UserListOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <UserUpdateComponent
      user_id={ props.store.getState().user_update.user_id }
      user_login={ props.store.getState().user_update.user_login }
      user_role={ props.store.getState().user_update.user_role }
      first_name={ props.store.getState().user_update.first_name }
      last_name={ props.store.getState().user_update.last_name }
      user_contacts={ props.store.getState().user_update.user_contacts }
      user_caption={ props.store.getState().user_update.user_caption }
      userpic_url={ props.store.getState().user_update.userpic_url }
      files={ props.store.getState().user_update.files }

      response_data={ props.store.getState().user_update.onupdate.response_data }
      response_code={ props.store.getState().user_update.onupdate.response_code }

      UserUpdateFirstNameOnchange={ UserUpdateFirstNameOnchange }
      UserUpdateLastNameOnchange={ UserUpdateLastNameOnchange }
      UserUpdateUserContactsOnchange={ UserUpdateUserContactsOnchange }
      UserUpdateUserCaptionOnchange={ UserUpdateUserCaptionOnchange }
      UserUpdateFilesOnchange={ UserUpdateFilesOnchange }
      UserUpdateOnselect={ UserUpdateOnselect }
      UserUpdateOnupdate={ UserUpdateOnupdate }
      UserUpdateOnclear={ UserUpdateOnclear }
    />
  );
}
  
export default UserUpdateMiddleware;
