import { useTranslation } from "react-i18next";
import { useEffect } from "react";
import config from "../../config";
import empty from "../../helpers/empty_helper";
import datetime from "../../helpers/datetime_helper";
import { can_edit, can_admin } from "../../helpers/role_helper"
import { offcanvas_hide, offcanvas_show } from "../../helpers/offcanvas_helper";
import PaginationShortComponent from "../pagination_short_component";
import errors from "../../helpers/errors_helper";

const DocumentSelectComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-document-select";

  useEffect(() => {
    document.getElementById(offcanvas_id).addEventListener("show.bs.offcanvas", () => {
      props.DocumentSelectOnselect();
      props.DocumentSelectRevisionsOnload();
      props.CommentListOnselect();
    });

    document.getElementById(offcanvas_id).addEventListener("hide.bs.offcanvas", () => {
      setTimeout(() => {
        props.DocumentSelectOnclear();
        props.CommentInsertOnclear();
        props.CommentListOnclear();
      }, config.offcanvas_latency);
    });
  }, []);

  const DocumentUpdateDocumentIdOnchange = (event) => {
    event.preventDefault();
    props.DocumentUpdateDocumentIdOnchange(props.document_id);

    offcanvas_hide();
    offcanvas_show("offcanvas-document-update");
  }

  const DocumentDeleteDocumentIdOnchange = (event) => {
    event.preventDefault();
    props.DocumentDeleteDocumentIdOnchange(props.document_id);

    offcanvas_hide();
    offcanvas_show("offcanvas-document-delete");
  }

  const CommentInsertCommentContentOnchange = (event) => {
    props.CommentInsertCommentContentOnchange(event.target.value);
  }

  const CommentDeleteOndelete = (event) => {
    props.CommentDeleteOndelete(event.target.dataset.comment_id);
  }

  const is_valid = (key, value) => {
    if (key === "comment_content") {
      return props.comment_content.length >= 1 && props.comment_content.length <= 512;
    }
  }

  const download = (event) => {
    event.preventDefault();
    const revision_id = event.target.dataset.revision_id;
    props.download(revision_id);
  }

  const revisions = props.revisions.response_data?.revisions?.map(revision => { 
    return <li key={ revision.id }><a className="dropdown-item" href="#" onClick={ download } data-revision_id={ revision.id }>{ datetime(revision.created_date, props.user_timezone, t) }</a></li>;
  });

  const submit_enabled = is_valid("comment_content");
  const response_errors = errors(props.comment_oninsert.response_data);

  const comments = props.comment_list_onselect.response_data?.comments?.map(comment => { 
    return (
      <div key={comment.id} className="mt-3">
        <div className="text-secondary">
          <small>
            { comment.user_name } { datetime(comment.created_date, props.user_timezone, t) }
            { props.token_payload.user_id === comment.user_id ? <a href="#" className="link-secondary" onClick={ CommentDeleteOndelete }><i data-comment_id={ comment.id } className="bi bi-x-lg ms-2"></i></a> : "" }
          </small>
        </div>
        <div>
          { comment.comment_content }
        </div>
      </div>
    );
  });

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title d-flex">
          { t("offcanvas-document-select-title") }

          <div className="dropdown ms-2">
            <a href="#" className="link link-primary dropdown-toggle no-after" type="button" data-bs-toggle="dropdown">
              <i className="bi bi-list"></i>
            </a>
            <ul className="dropdown-menu">
              <li><a className="dropdown-item" href="#" onClick={ offcanvas_hide }>{ t("button-cancel") }</a></li>
              <li><a className={ "dropdown-item" + (can_edit(props.user_role) ? "" : " d-none") } href="#" onClick={ DocumentUpdateDocumentIdOnchange }>{ t("button-edit") }</a></li>
              <li><a className={ "dropdown-item" + (can_admin(props.user_role) ? "" : " d-none") } href="#" onClick={ DocumentDeleteDocumentIdOnchange }>{ t("button-delete") }</a></li>
            </ul>
          </div>

        </h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

          <div className="form-text">
            { t("id") }
          </div>
          <div>
            { props.response_code === 200 ? props.response_data.id : <span className="placeholder placeholder-lg col-2"></span> }
          </div>

          <div className="form-text mt-4">
            { t("document-filename") }
          </div>
          <div>
            { props.response_code === 200 ? props.response_data.document_filename : <span className="placeholder placeholder-lg col-8"></span> }
          </div>

          { props.response_code === 200 && props.response_data.thumbnail_url && <>
            <div className="form-text d-flex justify-content-center align-items-center mt-4">
              <img src={ props.response_data.thumbnail_url } style={{ width: "auto", height: "auto" }} className="card-img-top" alt={ props.response_data.document_filename } />
            </div>
          </> }

          <div className="form-text mt-4">
            { t("document-revisions-text") }
          </div>
          <div className="text-center">
            <div className="dropdown">
              <button className="btn btn-secondary dropdown-toggle" type="button" data-bs-toggle="dropdown" aria-expanded="false">
                { t("document-revisions") }
              </button>
              <ul className="dropdown-menu">
                { revisions }
              </ul>
            </div>
          </div>

          <div className="form-text mt-4">
            { t("document-collection") }
          </div>
          <div>
            { props.response_code === 200 ? props.response_data.collection_name : <span className="placeholder placeholder-lg col-8"></span> }
          </div>

          { props.response_code === 200 && props.response_data.document_summary && <>
            <div className="form-text mt-4">
              { t("document-partner") }
            </div>
            <div>
              { props.response_code === 200 ? props.response_data.partner_name : <span className="placeholder placeholder-lg col-8"></span> }
            </div>
          </>}

          { props.response_code === 200 && props.response_data.document_summary && <>
            <div className="form-text mt-4">
              { t("document-summary") }
            </div>
            <div>
              { props.response_code === 200 ? props.response_data.document_summary : <span className="placeholder placeholder-lg col-12"></span> }
            </div>
          </> }

          { props.response_code === 200 && !empty(props.response_data.document_tags) && <>
            <div className="form-text mt-4">
              { t("document-tags") }
            </div>
            <div>
              { props.response_code === 200 ? props.response_data.document_tags.join(", ") : <span className="placeholder placeholder-lg col-12"></span> }
            </div>
          </> }

          <div className="form-text mt-4">
            { t("document-comments-count") }
          </div>
          <div>
            { props.response_code === 200 ? props.response_data.comments_count : <span className="placeholder placeholder-lg col-2"></span> }
          </div>

          <div className="form-text mt-4">
            { t("document-user") }
          </div>
          <div>
            { props.response_code === 200 ? props.response_data.user_name : <span className="placeholder placeholder-lg col-8"></span> }
          </div>

          <div className="form-text mt-4">
            { t("created-date") }
          </div>
          <div>
            { props.response_code === 200 ? datetime(props.response_data.created_date, props.user_timezone, t) : <span className="placeholder placeholder-lg col-8"></span> }
          </div>

          <div className="form-text mt-4">
            { t("updated-date") }
          </div>
          <div>
            { props.response_code === 200 ? datetime(props.response_data.updated_date, props.user_timezone, t) : <span className="placeholder placeholder-lg col-8"></span> }
          </div>

          <h2 className="mt-4">
            { t("comment-title") }
          </h2>

          { comments }

          <PaginationShortComponent
            offset={ props.store.getState().comment_list.offset } 
            limit={ config.default_comments_limit }
            count={ props.response_data.comments_count }
            offset_onchange={ props.CommentListOffsetOnchange } 
            limit_onchange={ () => {} }
            onclear={ () => { props.CommentListOnclear(); props.CommentListOnselect(); } }
          />

          <div className="form-floating mt-4">
            <textarea onChange={ CommentInsertCommentContentOnchange } className={ "form-control" + ("comment_content" in response_errors ? " border-danger glow-danger" : is_valid("comment_content") ? " border-primary" : "") } value={ props.comment_content } style={{ height: "8rem" }} maxLength={ 512 }>
            </textarea>
            <label>{ t("comment-content") }</label>
          </div>

          <div className="form-text text-danger">
            { "comment_content" in response_errors && t("error_" + response_errors["comment_content"]) }
          </div>

          <button onClick={ props.CommentInsertOninsert } className={"btn btn-primary mt-4 ms-2 " + (!submit_enabled ? "disabled" : "")} type="submit">
            <i className="bi bi-check2"></i> { t("button-submit") }
          </button>

        </form>
      </div>
    </div>
  );
}

export default DocumentSelectComponent;
