import { 
  UserRegisterUserLoginOnchangeActionCreator,
  UserRegisterUserPasswordOnchangeActionCreator,
  UserRegisterFirstNameOnchangeActionCreator,
  UserRegisterLastNameOnchangeActionCreator,
  UserRegisterAgreementOnclickActionCreator,
  UserRegisterOnsubmitActionCreator,
  UserRegisterOnclearActionCreator } from "../../reducers/user_register_reducer";
import { 
  UserSecretUserIdOnchangeActionCreator,
  UserSecretMfaSecretOnchangeActionCreator,
  UserSecretMfaUrlOnchangeActionCreator } from "../../reducers/user_secret_reducer";
import UserRegisterComponent from "../../components/user/user_register_component";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { offcanvas_hide, offcanvas_show } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import redirect from "../../helpers/redirect_helper";
import { log } from "../../helpers/log_helper";


const UserRegisterMiddleware = (props) => {
  const navigate = useNavigate();

  const UserRegisterUserLoginOnchange = (user_login) => {
    const action = UserRegisterUserLoginOnchangeActionCreator(user_login);
    props.store.dispatch(action);
  }

  const UserRegisterUserPasswordOnchange = (user_password) => {
    const action = UserRegisterUserPasswordOnchangeActionCreator(user_password);
    props.store.dispatch(action);
  }

  const UserRegisterFirstNameOnchange = (first_name) => {
    const action = UserRegisterFirstNameOnchangeActionCreator(first_name);
    props.store.dispatch(action);
  }

  const UserRegisterLastNameOnchange = (last_name) => {
    const action = UserRegisterLastNameOnchangeActionCreator(last_name);
    props.store.dispatch(action);
  }

  const UserRegisterAgreementOnclick = () => {
    const action = UserRegisterAgreementOnclickActionCreator();
    props.store.dispatch(action);
  }

  const UserRegisterOnsubmit = () => {
    const offcanvas_id = "offcanvas-user-register";
    const log_prefix = "user-register";
    buttons_disable(offcanvas_id);

    axios({
      method: "post",
      url: config.server_host + "user", 
      data: {
        user_login: props.store.getState().user_register.user_login,
        user_password: props.store.getState().user_register.user_password,
        first_name: props.store.getState().user_register.first_name,
        last_name: props.store.getState().user_register.last_name,
      },

    }).then(response => {
      log.debug(log_prefix, response);
      buttons_enable(offcanvas_id);
      offcanvas_hide();

      let action = UserRegisterOnsubmitActionCreator(response.data, response.status);
      props.store.dispatch(action);

      action = UserSecretUserIdOnchangeActionCreator(response.data.user_id);
      props.store.dispatch(action);

      action = UserSecretMfaSecretOnchangeActionCreator(response.data.mfa_secret);
      props.store.dispatch(action);

      action = UserSecretMfaUrlOnchangeActionCreator(response.data.mfa_url);
      props.store.dispatch(action);

      setTimeout(() => { offcanvas_show("offcanvas-user-secret") }, config.offcanvas_latency);
      
    }).catch(e => {
      log.debug(log_prefix, e);
      buttons_enable(offcanvas_id);

      if (e.status === 422) {
        const action = UserRegisterOnsubmitActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }

    });
  }

  const UserRegisterOnclear = () => {
    const action = UserRegisterOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <UserRegisterComponent
      user_login={ props.store.getState().user_register.user_login }
      user_password={ props.store.getState().user_register.user_password }
      password_shown={ props.store.getState().user_register.password_shown }
      first_name={ props.store.getState().user_register.first_name }
      last_name={ props.store.getState().user_register.last_name }
      agreement_accepted={ props.store.getState().user_register.agreement_accepted }

      response_data={ props.store.getState().user_register.onregister.response_data }
      response_code={ props.store.getState().user_register.onregister.response_code }

      UserRegisterUserLoginOnchange={ UserRegisterUserLoginOnchange }
      UserRegisterUserPasswordOnchange={ UserRegisterUserPasswordOnchange }
      UserRegisterFirstNameOnchange={ UserRegisterFirstNameOnchange }
      UserRegisterLastNameOnchange={ UserRegisterLastNameOnchange }
      UserRegisterAgreementOnclick={ UserRegisterAgreementOnclick }
      UserRegisterOnsubmit={ UserRegisterOnsubmit }
      UserRegisterOnclear={ UserRegisterOnclear }
    />
  );
}
  
export default UserRegisterMiddleware;
