import { useTranslation } from "react-i18next";
import i18n from "i18next";
import empty from "../helpers/empty_helper";
import { NavLink } from "react-router-dom";
import { can_admin } from "../helpers/role_helper";
import { offcanvas_hide, offcanvas_show } from "../helpers/offcanvas_helper";

const NavbarComponent = (props) => {
  const { t } = useTranslation();

  const SearchOnchange = (event) => {
    props.SearchOnchange(event.target.value);
  }

  const SearchOnsubmit = (event) => {
    if (event.keyCode === 13) {
      props.SearchOnsubmit(event.target.value);
    }
  }

  const AppTokenOndelete = () => {
    props.AppTokenOndelete();
  }

  const UserSelectUserIdOnchange = (event) => {
    const user_id = event.target.dataset.user_id;
    props.UserSelectUserIdOnchange(user_id);

    offcanvas_hide();
    offcanvas_show("offcanvas-user-select");
  }

  return (
    <nav className="navbar navbar-expand-lg bg-body-tertiary">
      <div className="container-fluid">
        <NavLink className="navbar-brand fw-bolder" to="/">Hidden</NavLink>

        <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbar-dropdown">
          <span className="navbar-toggler-icon"></span>
        </button>
        <div className="collapse navbar-collapse" id="navbar-dropdown">
          <ul className="navbar-nav me-auto">
            { !empty(props.token_payload) &&
              <>
                <li className="nav-item dropdown me-2">
                  <a className="nav-link dropdown-toggle" href="#" role="button" data-bs-toggle="dropdown">
                    { t("navbar-workspace") }
                  </a>
                  <ul className="dropdown-menu">
                    <li><NavLink className="dropdown-item" to="/collections">{ t("navbar-collections") }</NavLink></li>
                    <li><NavLink className="dropdown-item" to="/documents">{ t("navbar-documents") }</NavLink></li>
                    <li><NavLink className="dropdown-item" to="/partners">{ t("navbar-partners") }</NavLink></li>
                    <li><NavLink className="dropdown-item" to="/users">{ t("navbar-users") }</NavLink></li>
                    <li><hr className={ "dropdown-divider" + (can_admin(props.token_payload.user_role) ? "" : " d-none")} /></li>
                    <li><a className={ "dropdown-item" + (can_admin(props.token_payload.user_role) ? "" : " d-none") } href="#offcanvas-telemetry-select" data-bs-toggle="offcanvas">{ t("navbar-telemetry") }</a></li>
                  </ul>
                </li>

                <li className="nav-item me-2">
                  <NavLink className="nav-link" to="/collections">
                    { t("navbar-collections") }
                  </NavLink>
                </li>

                <li className="nav-item me-3">
                  <NavLink className="nav-link" to="/documents">
                    { t("navbar-documents") }
                  </NavLink>
                </li>

                <li className="nav-item dropdown me-5">
                  <a className="btn btn-primary" href="#offcanvas-document-insert" data-bs-toggle="offcanvas" role="button">
                    <i className="bi bi-plus-lg"></i> { t("navbar-upload") }
                  </a>
                </li>

                <li className="nav-item">
                  <div className="input-group">
                    <input onChange={ SearchOnchange } onKeyUp={ SearchOnsubmit } value={ props.search } className="form-control" id="navbar-search" type="search" style={{ minWidth: "16rem" }} placeholder={ t("navbar-search-input") + (props.user_tips ? " Ctrl+K" : "") } />
                    <button onClick={ SearchOnsubmit } className="btn btn-primary" type="button" id="button-addon2">
                      { t("navbar-search-submit") } <i className="bi bi-arrow-right"></i>
                    </button>
                  </div>
                </li>

              </>
            }              
          </ul>
          <ul className="navbar-nav ml-auto">

            <li className="nav-item">
              <a className="nav-link" href="#">
              <i className={ "bi " + (props.is_locked ? "bi-lock-fill" : "bi-unlock")} ></i>
              </a>
            </li>

            <li className="nav-item">
              <a className="nav-link" href="#offcanvas-user-adjustments" data-bs-toggle="offcanvas">
                <i className="bi bi-toggles"></i>
              </a>
            </li>

            { empty(props.token_payload) &&
              <>
                <li className="nav-item me-2">
                  <a className="nav-link" href="#offcanvas-user-register" data-bs-toggle="offcanvas">{ t("navbar-register") }</a>
                </li>
                <li className="nav-item">
                  <a className="nav-link" href="#offcanvas-user-login" data-bs-toggle="offcanvas">{ t("navbar-login") }</a>
                </li>
              </>
            }

            { !empty(props.token_payload) &&
              <li className="nav-item dropdown">
                <a className="nav-link dropdown-toggle" href="#" role="button" data-bs-toggle="dropdown">
                  { props.token_payload.user_login }
                </a>
                <ul className="dropdown-menu dropdown-menu-end">
                  <li>
                    <a className="dropdown-item" href="#" onClick={ UserSelectUserIdOnchange } data-user_id={ props.token_payload.user_id }>
                      { t("navbar-user-select") }
                    </a>
                  </li>
                  <li>
                    <a className="dropdown-item" href="#offcanvas-user-update" data-bs-toggle="offcanvas">
                      { t("navbar-user-update") }
                    </a>
                  </li>
                  <li>
                    <a className="dropdown-item" href="#offcanvas-user-password" data-bs-toggle="offcanvas">
                      { t("navbar-user-password") }
                    </a>
                  </li>
                  <li><hr className="dropdown-divider" /></li>
                  <li>
                    <a onClick={ AppTokenOndelete } className="dropdown-item d-flex justify-content-between" href="#">
                      <span>{ t("navbar-user-logout") }</span>
                      <span className={ "ms-2 text-secondary" + (!props.user_tips ? " d-none" : "") }>Ctrl+L</span>
                    </a>
                  </li>

                </ul>
              </li>
            }

          </ul>
        </div>
      </div>
    </nav>
  );
}

export default NavbarComponent;
