import { useTranslation } from "react-i18next";
import config from "../../config";
import empty from "../../helpers/empty_helper";
import datetime from "../../helpers/datetime_helper";
import PaginationComponent from "../pagination_component";
import DatatableComponent from "../datatable_component";
import DropdownComponent from "../dropdown_component";
import { offcanvas_show } from "../../helpers/offcanvas_helper";

let timer;

const UserListComponent = (props) => {
  const { t } = useTranslation();

  if (empty(props.response_data) && !empty(props.user_token)) {
    props.UserListOnselect();
  }

  const UserListOrderOnchange = (event) => {
    const order_by = event.target.dataset.order_by;
    props.UserListOrderOnchange(order_by);
    props.UserListOnclear();
  }

  const UserSelectUserIdOnchange = (event) => {
    const user_id = event.target.dataset.user_id;
    props.UserSelectUserIdOnchange(user_id);
    offcanvas_show("offcanvas-user-select");
  }

  const filters_count = (!empty(props.filter.full_name) + !empty(props.filter.user_role) + !empty(props.filter.is_active)) || null;
  const filters_reset = () => {
    props.UserListOffsetOnchange(0);
    props.UserFilterOnreset();
    props.UserListOnclear();
  }

  const columns = [
    { name: t("id"), order_by: "id" },
    { name: t("user-created-date"), order_by: "created_date" },
    { name: t("user-last-login-date"), order_by: "last_login_date" },
    { name: "" },
    { name: t("user-login"), order_by: "user_login" },
    { name: t("user-role"), order_by: "user_role" },
    { name: t("user-first-name"), order_by: "first_name" },
    { name: t("user-last-name"), order_by: "last_name" },
  ];

  const rows = props.response_data?.users?.map(user => { 
    return [
      user.id,
      datetime(user.created_date, props.user_timezone, t),
      datetime(user.last_login_date, props.user_timezone, t),
      user.is_active ? <i className="bi bi-check"></i> : <i className="bi bi-dot"></i>,
      <span role="button" className="link-primary" data-user_id={ user.id } onClick={ UserSelectUserIdOnchange }>{ user.user_login }</span>,
      user.user_role,
      user.first_name,
      user.last_name,
    ];
  });

  const TimerStart = () => {
    clearTimeout(timer);
    timer = setTimeout(() => {
      props.UserListOffsetOnchange(0);
      props.UserListOnclear();
    }, config.input_latency);
  }

  const UserFilterFullNameOnchange = (event) => {
    const full_name = event.target.value;
    props.UserFilterFullNameOnchange(full_name);
    TimerStart();
  }

  const UserFilterUserRoleOnchange = (event) => {
    const user_role = event.target.value;
    props.UserFilterUserRoleOnchange(user_role);
  }

  const UserFilterIsActiveOnchange = (event) => {
    const is_active = event.target.value;
    props.UserFilterIsActiveOnchange(is_active);
  }

  return (<>
    <h1 className="mb-4">{ t("page-users-title") }</h1>

    <div className="d-flex d-inline align-items-center mb-4">
      <div className="btn-group btn-group-outline">
        <button type="button" className="btn btn-outline-primary" data-bs-toggle="collapse" href="#user-filter">
          <i className="bi bi-sliders2"></i> { t("button-filters") } <span className="badge text-bg-primary">{ filters_count }</span>
        </button>

        <button type="button" className="btn btn-outline-primary" onClick={ filters_reset }>
          <i className="bi bi-x-lg"></i> { t("button-reset") }
        </button>
      </div>

      <a href="#" className="link-primary text-decoration-none ms-3" onClick={ props.UserListOnclear }>
        <i className="bi bi-arrow-clockwise"></i> { t("button-refresh") }
      </a>
    </div>

    <div className="row collapse" id="user-filter">
      <div className="col-6 mb-4">
        <div className="form-floating">
          <input onChange={ UserFilterFullNameOnchange } type="search" className={ "form-control" + (props.filter.full_name ? " border-primary" : "") } id="user-filter-full-name" placeholder={ t("filter-user-name") } value={ props.filter.full_name } />
          <label htmlFor="user-filter-full-name">{ t("filter-user-name") }</label>
        </div>
      </div>

      <div className="col-3 mb-4">
        <DropdownComponent
          options={[
            { value: "", text: "" },
            { value: "reader", text: t("role-reader") },
            { value: "writer", text: t("role-writer") },
            { value: "editor", text: t("role-editor") },
            { value: "admin", text: t("role-admin") },
          ]}
          dispatch={ props.dispatch }
          dropdown_placeholder={ t("user-role") }
          value={ props.filter.user_role }
          onchange={ UserFilterUserRoleOnchange }
          onupdate={ () => { props.UserListOffsetOnchange(0); props.UserListOnclear(); } }
        />
      </div>

      <div className="col-3 mb-4">
        <DropdownComponent
          options={[
            { value: "", text: "" },
            { value: 1, text: t("activity-active") },
            { value: 0, text: t("activity-inactive") },
          ]}
          dispatch={ props.dispatch }
          dropdown_placeholder={ t("filter-user-active") }
          value={ props.filter.is_active }
          onchange={ UserFilterIsActiveOnchange }
          onupdate={ () => { props.UserListOffsetOnchange(0); props.UserListOnclear(); } }
        />
      </div>
    </div>

    <DatatableComponent
      limit={ props.limit }
      order_by={ props.order_by }
      order={ props.order }
      order_onchange={ UserListOrderOnchange }
      columns={ columns }
      rows={ rows }
      selected_rows={ [] }
      can_select={ false }
      onselect={ () => {} }
    />

    <PaginationComponent
      offset={ props.offset } 
      limit={ props.limit }
      limit_values={ config.allowed_users_limit }
      count={ props.response_data.users_count }
      offset_onchange={ props.UserListOffsetOnchange } 
      limit_onchange={ props.UserListLimitOnchange }
      onclear={ props.UserListOnclear }
    />

  </>);
}

export default UserListComponent;
