import {
  UserRoleUserIdOnchangeActionCreator,
  UserRoleUserRoleOnchangeActionCreator,
  UserRoleIsActiveOnchangeActionCreator,
  UserRoleOnselectActionCreator,
  UserRoleOnupdateActionCreator,
  UserRoleOnclearActionCreator } from "../../reducers/user_role_reducer";
import UserRoleComponent from "../../components/user/user_role_component";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import { log } from "../../helpers/log_helper";
import redirect from "../../helpers/redirect_helper";
import { UserListOnclearActionCreator } from "../../reducers/user_list_reducer";

const UserRoleMiddleware = (props) => {
  const navigate = useNavigate();

  const UserRoleUserIdOnchange = (user_id) => {
    const action = UserRoleUserIdOnchangeActionCreator(user_id);
    props.store.dispatch(action);
  }

  const UserRoleUserRoleOnchange = (user_role) => {
    const action = UserRoleUserRoleOnchangeActionCreator(user_role);
    props.store.dispatch(action);
  }

  const UserRoleIsActiveOnchange = (is_active) => {
    const action = UserRoleIsActiveOnchangeActionCreator(is_active);
    props.store.dispatch(action);
  }

  const UserRoleOnselect = () => {
    const log_prefix = "user-role-select";

    axios({
      method: "get",
      url: config.server_host + "user/" + props.store.getState().user_role.user_id, 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },

    }).then((response) => {
      log.debug(log_prefix, response);

      const action = UserRoleOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);
      
    }).catch(e => {
      log.error(log_prefix, e);
      redirect(e, navigate);
    });
  }

  const UserRoleOnupdate = () => {
    const offcanvas_id = "offcanvas-user-role";
    const log_prefix = "user-role-update";
    buttons_disable(offcanvas_id);

    axios({
      method: "put",
      url: config.server_host + "user/" + props.store.getState().user_role.user_id + "/role", 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      data: {
        user_role: props.store.getState().user_role.user_role,
        is_active: props.store.getState().user_role.is_active,
      },

    }).then(response => {
      log.debug(log_prefix, response);

      buttons_enable(offcanvas_id);
      offcanvas_hide();
      
      let action = UserRoleOnupdateActionCreator(response.data, response.status);
      props.store.dispatch(action);

      UserListOnclear();

    }).catch(e => {
      log.error(log_prefix, e);

      buttons_enable(offcanvas_id);

      if (e.status === 422) {
        const action = UserRoleOnupdateActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }

    });
  }

  const UserRoleOnclear = () => {
    const action = UserRoleOnclearActionCreator();
    props.store.dispatch(action);
  }

  const UserListOnclear = () => {
    const action = UserListOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <UserRoleComponent
      user_id={ props.store.getState().user_role.user_id }
      user_login={ props.store.getState().user_role.user_login }
      user_role={ props.store.getState().user_role.user_role }
      is_active={ props.store.getState().user_role.is_active }

      response_data={ props.store.getState().user_role.onupdate.response_data }
      response_code={ props.store.getState().user_role.onupdate.response_code }

      UserRoleUserIdOnchange={ UserRoleUserIdOnchange }
      UserRoleUserRoleOnchange={ UserRoleUserRoleOnchange }
      UserRoleIsActiveOnchange={ UserRoleIsActiveOnchange }
      UserRoleOnselect={ UserRoleOnselect }
      UserRoleOnupdate={ UserRoleOnupdate }
      UserRoleOnclear={ UserRoleOnclear }
    />
  );
}
  
export default UserRoleMiddleware;
