const USER_PASSWORD_CURRENT_PASSWORD_ONCHANGE = "USER_PASSWORD_CURRENT_PASSWORD_ONCHANGE";
const USER_PASSWORD_UPDATED_PASSWORD_ONCHANGE = "USER_PASSWORD_UPDATED_PASSWORD_ONCHANGE";
const USER_PASSWORD_ONUPDATE = "USER_PASSWORD_ONUPDATE";
const USER_PASSWORD_ONCLEAR = "USER_PASSWORD_ONCLEAR";

const initial = {
  current_password: "",
  updated_password: "",
  onupdate: {
    response_data: {},
    response_code: 0,
  },
};

const UserPasswordReducer = (state = initial, action) => {

  if (action.type === USER_PASSWORD_CURRENT_PASSWORD_ONCHANGE) {
    state.current_password = action.current_password;

  } else if (action.type === USER_PASSWORD_UPDATED_PASSWORD_ONCHANGE) {
    state.updated_password = action.updated_password;

  } else if (action.type === USER_PASSWORD_ONUPDATE) {
    state.onupdate.response_data = action.response_data;
    state.onupdate.response_code = action.response_code;

  } else if (action.type === USER_PASSWORD_ONCLEAR) {
    state.current_password = "";
    state.updated_password = "";
    state.onupdate.response_data = {};
    state.onupdate.response_code = 0;
  }

  return state;
}

export const UserPasswordCurrentPasswordOnchangeActionCreator = (current_password) => {
  return {
    type: USER_PASSWORD_CURRENT_PASSWORD_ONCHANGE,
    current_password: current_password,
  }
}

export const UserPasswordUpdatedPasswordOnchangeActionCreator = (updated_password) => {
  return {
    type: USER_PASSWORD_UPDATED_PASSWORD_ONCHANGE,
    updated_password: updated_password,
  }
}

export const UserPasswordOnupdateActionCreator = (response_data, response_code) => {
  return {
    type: USER_PASSWORD_ONUPDATE,
    response_data: response_data,
    response_code: response_code,
  }
}

export const UserPasswordOnclearActionCreator = () => {
  return {
    type: USER_PASSWORD_ONCLEAR,
  }
}

export default UserPasswordReducer;
