import { useTranslation } from "react-i18next";
import { useEffect } from "react";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import config from "../../config";

const UserRoleComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-user-role";

  useEffect(() => {
    document.getElementById(offcanvas_id).addEventListener("show.bs.offcanvas", () => {
      props.UserRoleOnselect();
    });

    document.getElementById(offcanvas_id).addEventListener("hide.bs.offcanvas", () => {
      setTimeout(
        () => { props.UserRoleOnclear() },
        config.offcanvas_latency);
    });
  }, []);

  const UserRoleUserRoleOnchange = (event) => {
    props.UserRoleUserRoleOnchange(event.target.dataset.user_role);
  }

  const UserRoleIsActiveOnchange = (event) => {
    props.UserRoleIsActiveOnchange(event.target.checked);
  }

  const UserRoleOnupdate = (event) => {
    event.preventDefault();
    props.UserRoleOnupdate();
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title">{ t("offcanvas-user-role-title") }</h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

          <div className="form-text">
            { t("id") }
          </div>
          <div>
            { props.user_id }
          </div>

          <div className="form-text mt-4">
            { t("user-login") }
          </div>
          <div>
            { props.user_login }
          </div>

          <div className="form-check mt-4">
            <input onChange={ UserRoleUserRoleOnchange } data-user_role="admin" className="form-check-input" type="radio" name="flexRadioDefault" id="role-admin" checked={ props.user_role === "admin" } />
            <label className="form-check-label" htmlFor="role-admin">
              admin
            </label>
          </div>

          <div className="form-check">
            <input onChange={ UserRoleUserRoleOnchange } data-user_role="editor" className="form-check-input" type="radio" name="flexRadioDefault" id="role-editor" checked={ props.user_role === "editor" } />
            <label className="form-check-label" htmlFor="role-editor">
              editor
            </label>
          </div>

          <div className="form-check">
            <input onChange={ UserRoleUserRoleOnchange } data-user_role="writer" className="form-check-input" type="radio" name="flexRadioDefault" id="role-writer" checked={ props.user_role === "writer" } />
            <label className="form-check-label" htmlFor="role-writer">
              writer
            </label>
          </div>

          <div className="form-check">
            <input onChange={ UserRoleUserRoleOnchange } data-user_role="reader" className="form-check-input" type="radio" name="flexRadioDefault" id="role-reader" checked={ props.user_role === "reader" } />
            <label className="form-check-label" htmlFor="role-reader">
              reader
            </label>
          </div>

          <div className="form-floating mt-4">
            <div className="form-check">
              <input onChange={ UserRoleIsActiveOnchange } checked={ props.is_active } className="form-check-input" type="checkbox" value="" id="is-active" />
              <label className="form-check-label form-text" htmlFor="is-active">
                { t("offcanvas-user-role-is-active-text") }
              </label>
            </div>
          </div>

          <button className="btn btn-outline-primary mt-4" type="button" onClick={ offcanvas_hide }>
            <i className="bi bi-arrow-left"></i> { t("button-cancel") }
          </button>

          <button onClick={ UserRoleOnupdate } className="btn btn-primary mt-4 ms-2" type="submit">
            <i className="bi bi-check2"></i> { t("button-submit") }
          </button>

        </form>
      </div>
    </div>
  );
}

export default UserRoleComponent;
