import axios from "axios";
import config from "../../config";
import { log } from "../../helpers/log_helper";
import { useNavigate } from "react-router-dom";
import {
  PartnerListOffsetOnchangeActionCreator,
  PartnerListLimitOnchangeActionCreator,
  PartnerListOrderOnchangeActionCreator,
  PartnerListOnselectActionCreator,
  PartnerListOnclearActionCreator,
  PartnerFilterPartnerNameOnchangeActionCreator,
  PartnerFilterPartnerTypeOnchangeActionCreator,
  PartnerFilterPartnerRegionOnchangeActionCreator,
  PartnerFilterOnresetActionCreator
} from "../../reducers/partner_list_reducer";
import { PartnerSelectPartnerIdOnchangeActionCreator } from "../../reducers/partner_select_reducer";
import { PartnerDeletePartnerIdsOnshiftActionCreator } from "../../reducers/partner_delete_reducer";
import PartnerListComponent from "../../components/partner/partner_list_component";
import redirect from "../../helpers/redirect_helper";

let is_loading = false;

const PartnerListMiddleware = (props) => {
  const navigate = useNavigate();

  const PartnerListOffsetOnchange = (offset) => {
    const action = PartnerListOffsetOnchangeActionCreator(offset);
    props.store.dispatch(action);
  }

  const PartnerListLimitOnchange = (limit) => {
    let action = PartnerListLimitOnchangeActionCreator(limit);
    props.store.dispatch(action);
  }

  const PartnerListOrderOnchange = (order_by) => {
    const action = PartnerListOrderOnchangeActionCreator(order_by);
    props.store.dispatch(action);
  }

  const PartnerListOnselect = () => {
    if (is_loading) { return }
    is_loading = true;
    const log_prefix = "partner-list";

    const params = {
      offset: props.store.getState().partner_list.offset, 
      limit: props.store.getState().partner_list.limit,
      order_by: props.store.getState().partner_list.order_by, 
      order: props.store.getState().partner_list.order,
    };

    const partner_name = props.store.getState().partner_list.filter.partner_name;
    if (partner_name) {
      params.partner_name__ilike = partner_name;
    }

    const partner_type = props.store.getState().partner_list.filter.partner_type;
    if (partner_type) {
      params.partner_type__ilike = partner_type;
    }

    const partner_region = props.store.getState().partner_list.filter.partner_region;
    if (partner_region) {
      params.partner_region__ilike = partner_region;
    }

    axios({
      method: "get",
      url: config.server_host + "partners", 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      params: params,

    }).then(response => {
      log.debug(log_prefix, response);

      const action = PartnerListOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);
      is_loading = false;

    }).catch(e => {
      log.error(log_prefix, e);

      if (e.status === 422) {
        const action = PartnerListOnselectActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }

      is_loading = false;
    });
  }

  const PartnerListOnclear = () => {
    const action = PartnerListOnclearActionCreator();
    props.store.dispatch(action);
  }

  const PartnerFilterPartnerNameOnchange = (partner_name) => {
    const action = PartnerFilterPartnerNameOnchangeActionCreator(partner_name);
    props.store.dispatch(action);
  }

  const PartnerFilterPartnerTypeOnchange = (partner_type) => {
    const action = PartnerFilterPartnerTypeOnchangeActionCreator(partner_type);
    props.store.dispatch(action);
  }

  const PartnerFilterPartnerRegionOnchange = (partner_region) => {
    const action = PartnerFilterPartnerRegionOnchangeActionCreator(partner_region);
    props.store.dispatch(action);
  }

  const PartnerFilterOnreset = () => {
    const action = PartnerFilterOnresetActionCreator();
    props.store.dispatch(action);
  }

  const PartnerSelectPartnerIdOnchange = (partner_id) => {
    const action = PartnerSelectPartnerIdOnchangeActionCreator(partner_id);
    props.store.dispatch(action);
  }

  const PartnerDeletePartnerIdsOnshift = (partner_id) => {
    let action = PartnerDeletePartnerIdsOnshiftActionCreator(partner_id);
    props.store.dispatch(action);
  }

  return (
    <PartnerListComponent
      dispatch={ props.store.dispatch }
      user_timezone={ props.store.getState().app.user_timezone }
      user_token={ props.store.getState().app.user_token }
      token_payload={ props.store.getState().app.token_payload }

      offset={ props.store.getState().partner_list.offset }
      limit={ props.store.getState().partner_list.limit }
      order_by={ props.store.getState().partner_list.order_by }
      order={ props.store.getState().partner_list.order }
      filter={ props.store.getState().partner_list.filter }
      partner_ids={ props.store.getState().partner_delete.partner_ids }

      response_data={ props.store.getState().partner_list.onselect.response_data }
      response_code={ props.store.getState().partner_list.onselect.response_code }

      PartnerListOffsetOnchange={ PartnerListOffsetOnchange }
      PartnerListLimitOnchange={ PartnerListLimitOnchange }
      PartnerListOrderOnchange={ PartnerListOrderOnchange }
      PartnerListOnselect={ PartnerListOnselect }
      PartnerListOnclear={ PartnerListOnclear }

      PartnerFilterPartnerNameOnchange={ PartnerFilterPartnerNameOnchange }
      PartnerFilterPartnerTypeOnchange={ PartnerFilterPartnerTypeOnchange }
      PartnerFilterPartnerRegionOnchange={ PartnerFilterPartnerRegionOnchange }
      PartnerFilterOnreset={ PartnerFilterOnreset }

      PartnerSelectPartnerIdOnchange={ PartnerSelectPartnerIdOnchange }
      PartnerDeletePartnerIdsOnshift={ PartnerDeletePartnerIdsOnshift }
    />
  );
}
  
export default PartnerListMiddleware;
