import { UserSecretOnclearActionCreator } from "../../reducers/user_secret_reducer";
import UserSecretComponent from "../../components/user/user_secret_component";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import config from "../../config";

const UserSecretMiddleware = (props) => {

  const UserSecretOnclear = () => {
    offcanvas_hide()

    setTimeout(() => {
      const action = UserSecretOnclearActionCreator();
      props.store.dispatch(action);
    }, config.offcanvas_latency);
  }

  return (
    <UserSecretComponent
      user_id={ props.store.getState().user_secret.user_id }
      mfa_secret={ props.store.getState().user_secret.mfa_secret }
      mfa_url={ props.store.getState().user_secret.mfa_url }

      UserSecretOnclear={ UserSecretOnclear }
    />
  );
}
  
export default UserSecretMiddleware;
