import { useTranslation } from "react-i18next";

const UserAdjustmentsComponent = (props) => {
  const { t } = useTranslation();

  let timezones = [];
  Intl.supportedValuesOf("timeZone").forEach(timezone => {
    timezones.push(<option key={ timezone } value={ timezone }>{ timezone }</option>);
  });
  
  const AppTimezoneOnchange = (event) => {
    props.AppTimezoneOnchange(event.target.value);
  }

  const AppLanguageOnchange = (event) => {
    props.AppLanguageOnchange(event.target.value);
  }

  const AppThemeOnchange = () => {
    props.AppThemeOnchange();
  }

  return (
  <div className="offcanvas offcanvas-start w-35" tabIndex="-1" id="offcanvas-user-adjustments">
    <div className="offcanvas-header">
      <h5 className="offcanvas-title">
        { t("offcanvas-user-adjustments-title") }
      </h5>
      <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
    </div>
    <div className="offcanvas-body mb-4">

      <div className="form-text">
        { t("offcanvas-user-adjustments-theme-text") }
      </div>
      <div className="form-group mt-1">
        <div className="d-flex">
          <div className="form-switch">
            <input id="user-adjustments-user-theme" onChange={ AppThemeOnchange } checked={ props.user_theme === "dark" } className="form-check-input" type="checkbox" role="switch" />
            <label className="form-check-label ms-2" htmlFor="user-adjustments-user-theme">{ props.user_theme === "light" ? t("theme-light") : t("theme-dark") }</label>
          </div>
        </div>
      </div>

      <div className="form-text mt-4">
        { t("offcanvas-user-adjustments-language-text") }
      </div>
      <div className="form-floating mt-2">
        <select className="form-select" id="user-language" value={ props.user_language } onChange={ AppLanguageOnchange }>
          <option key="en" value="en">en (english)</option>
          <option key="es" value="es">es (español)</option>
          <option key="ru" value="ru">ru (русский)</option>
        </select>
        <label htmlFor="user-language">
          { t("offcanvas-user-adjustments-language-select") }
        </label>
      </div>

      <div className="form-text mt-4">
        { t("offcanvas-user-adjustments-timezone-text") }
      </div>
      <div className="form-floating mt-2">
        <select className="form-select" id="user-timezone" value={ props.user_timezone } onChange={ AppTimezoneOnchange }>
          { timezones }
        </select>
        <label htmlFor="user-timezone">
          { t("offcanvas-user-adjustments-timezone-select") }
        </label>
      </div>

    </div>
  </div>
    );
}

export default UserAdjustmentsComponent;
