const COMMENT_INSERT_COMMENT_CONTENT_ONCHANGE = "COMMENT_INSERT_COMMENT_CONTENT_ONCHANGE";
const COMMENT_INSERT_ONINSERT = "COMMENT_INSERT_ONINSERT";
const COMMENT_INSERT_ONCLEAR = "COMMENT_INSERT_ONCLEAR";

const initial = {
  comment_content: "",
  oninsert: {
    response_data: {},
    response_code: 0,
  },
};

const CommentInsertReducer = (state = initial, action) => {

  if (action.type === COMMENT_INSERT_COMMENT_CONTENT_ONCHANGE) {
    state.comment_content = action.comment_content;

  } else if (action.type === COMMENT_INSERT_ONINSERT) {
    state.oninsert.response_data = action.response_data;
    state.oninsert.response_code = action.response_code;

  } else if (action.type === COMMENT_INSERT_ONCLEAR) {
    state.comment_content = "";
    state.oninsert.response_data = {};
    state.oninsert.response_code = 0;
  }

  return state;
}

export const CommentInsertCommentContentOnchangeActionCreator = (comment_content) => {
  return {
    type: COMMENT_INSERT_COMMENT_CONTENT_ONCHANGE,
    comment_content: comment_content, 
  }
}

export const CommentInsertOninsertActionCreator = (response_data, response_code) => {
  return {
    type: COMMENT_INSERT_ONINSERT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const CommentInsertOnclearActionCreator = () => {
  return {
    type: COMMENT_INSERT_ONCLEAR,
  }
}

export default CommentInsertReducer;
