const PARTNER_INSERT_PARTNER_NAME_ONCHANGE = "PARTNER_INSERT_PARTNER_NAME_ONCHANGE";
const PARTNER_INSERT_PARTNER_TYPE_ONCHANGE = "PARTNER_INSERT_PARTNER_TYPE_ONCHANGE";
const PARTNER_INSERT_PARTNER_REGION_ONCHANGE = "PARTNER_INSERT_PARTNER_REGION_ONCHANGE";
const PARTNER_INSERT_PARTNER_WEBSITE_ONCHANGE = "PARTNER_INSERT_PARTNER_WEBSITE_ONCHANGE";
const PARTNER_INSERT_PARTNER_CONTACTS_ONCHANGE = "PARTNER_INSERT_PARTNER_CONTACTS_ONCHANGE";
const PARTNER_INSERT_PARTNER_SUMMARY_ONCHANGE = "PARTNER_INSERT_PARTNER_SUMMARY_ONCHANGE";
const PARTNER_INSERT_ONINSERT = "PARTNER_INSERT_ONINSERT";
const PARTNER_INSERT_ONCLEAR = "PARTNER_INSERT_ONCLEAR";

const initial = {
  partner_name: "",
  partner_type: "",
  partner_region: "",
  partner_website: "",
  partner_contacts: "",
  partner_summary: "",
  oninsert: {
    response_data: {},
    response_code: 0,
  }
};

const PartnerInsertReducer = (state = initial, action) => {

  if (action.type === PARTNER_INSERT_PARTNER_NAME_ONCHANGE) {
    state.partner_name = action.partner_name;

  } else if (action.type === PARTNER_INSERT_PARTNER_TYPE_ONCHANGE) {
    state.partner_type = action.partner_type;

  } else if (action.type === PARTNER_INSERT_PARTNER_REGION_ONCHANGE) {
    state.partner_region = action.partner_region;

  } else if (action.type === PARTNER_INSERT_PARTNER_WEBSITE_ONCHANGE) {
    state.partner_website = action.partner_website;

  } else if (action.type === PARTNER_INSERT_PARTNER_CONTACTS_ONCHANGE) {
    state.partner_contacts = action.partner_contacts;

  } else if (action.type === PARTNER_INSERT_PARTNER_SUMMARY_ONCHANGE) {
    state.partner_summary = action.partner_summary;

  } else if (action.type === PARTNER_INSERT_ONINSERT) {
    state.oninsert.response_data = action.response_data;
    state.oninsert.response_code = action.response_code;

  } else if (action.type === PARTNER_INSERT_ONCLEAR) {
    state.partner_name = "";
    state.partner_type = "";
    state.partner_region = "";
    state.partner_website = "";
    state.partner_contacts = "";
    state.partner_summary = "";
    state.oninsert = {
      response_data: {},
      response_code: 0,
    }
  }

  return state;
}

export const PartnerInsertPartnerNameOnchangeActionCreator = (partner_name) => {
  return {
    type: PARTNER_INSERT_PARTNER_NAME_ONCHANGE, 
    partner_name: partner_name, 
  }
}

export const PartnerInsertPartnerTypeOnchangeActionCreator = (partner_type) => {
  return {
    type: PARTNER_INSERT_PARTNER_TYPE_ONCHANGE, 
    partner_type: partner_type, 
  }
}

export const PartnerInsertPartnerRegionOnchangeActionCreator = (partner_region) => {
  return {
    type: PARTNER_INSERT_PARTNER_REGION_ONCHANGE, 
    partner_region: partner_region, 
  }
}

export const PartnerInsertPartnerWebsiteOnchangeActionCreator = (partner_website) => {
  return {
    type: PARTNER_INSERT_PARTNER_WEBSITE_ONCHANGE, 
    partner_website: partner_website, 
  }
}

export const PartnerInsertPartnerContactsOnchangeActionCreator = (partner_contacts) => {
  return {
    type: PARTNER_INSERT_PARTNER_CONTACTS_ONCHANGE, 
    partner_contacts: partner_contacts, 
  }
}

export const PartnerInsertPartnerSummaryOnchangeActionCreator = (partner_summary) => {
  return {
    type: PARTNER_INSERT_PARTNER_SUMMARY_ONCHANGE, 
    partner_summary: partner_summary, 
  }
}

export const PartnerInsertOninsertActionCreator = (response_data, response_code) => {
  return {
    type: PARTNER_INSERT_ONINSERT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const PartnerInsertOnclearActionCreator = () => {
  return {
    type: PARTNER_INSERT_ONCLEAR,
  }
}

export default PartnerInsertReducer;
