import config from "../config";
import { cookies_get, cookies_set } from "../helpers/cookies_helper";

const PARTNER_LIST_OFFSET_ONCHANGE = "PARTNER_LIST_OFFSET_ONCHANGE";
const PARTNER_LIST_LIMIT_ONCHANGE = "PARTNER_LIST_LIMIT_ONCHANGE";
const PARTNER_LIST_ORDER_ONCHANGE = "PARTNER_LIST_ORDER_ONCHANGE";
const PARTNER_LIST_ONSELECT = "PARTNER_LIST_ONSELECT";
const PARTNER_LIST_ONCLEAR = "PARTNER_LIST_ONCLEAR";

const PARTNER_FILTER_PARTNER_NAME_ONCHANGE = "PARTNER_FILTER_PARTNER_NAME_ONCHANGE";
const PARTNER_FILTER_PARTNER_TYPE_ONCHANGE = "PARTNER_FILTER_PARTNER_TYPE_ONCHANGE";
const PARTNER_FILTER_PARTNER_REGION_ONCHANGE = "PARTNER_FILTER_PARTNER_REGION_ONCHANGE";
const PARTNER_FILTER_ONRESET = "PARTNER_FILTER_ONRESET";

const initial = {
  order_by: config.default_partners_order_by,
  order: config.default_partners_order,
  offset: 0,
  limit: config.default_partners_limit,
  onselect: {
    response_data: {},
    response_code: 0,
  },
  filter: {
    partner_name: "",
    partner_type: "",
    partner_region: "",
  }
};

const order_by = cookies_get("partners_order_by");
if (config.allowed_partners_order_by.includes(order_by)) {
  initial.order_by = order_by;
}
cookies_set("partners_order_by", initial.order_by);

const order = cookies_get("partners_order");
if (config.allowed_partners_order.includes(order)) {
  initial.order = order;
}
cookies_set("partners_order", initial.order);

const limit = cookies_get("partners_limit");
if (config.allowed_partners_limit.includes(limit)) {
  initial.limit = limit;
}
cookies_set("partners_limit", initial.limit);

initial.offset = parseInt(cookies_get("partners_offset")) || 0;
cookies_set("partners_offset", initial.offset);

const PartnerListReducer = (state = initial, action) => {

  if (action.type === PARTNER_LIST_LIMIT_ONCHANGE) {
    const limit = parseInt(action.limit) || config.partners_limit;
    state.limit = config.allowed_partners_limit.includes(limit) ? limit : config.default_partners_limit;
    cookies_set("partners_limit", state.limit);

  } else if (action.type === PARTNER_LIST_OFFSET_ONCHANGE) {
    state.offset = parseInt(action.offset) || 0;
    cookies_set("partners_offset", state.offset);

  } else if (action.type === PARTNER_LIST_ORDER_ONCHANGE) {
    const order_by = config.allowed_partners_order_by.includes(action.order_by) ? action.order_by : config.default_partners_order_by;

    if (state.order_by === order_by) {
      state.order = state.order === "asc" ? "desc" : "asc";
      cookies_set("partners_order", state.order);

    } else {
      state.order_by = action.order_by;
      cookies_set("partners_order_by", state.order_by);
    }

  } else if (action.type === PARTNER_LIST_ONSELECT) {
    state.onselect.response_data = action.response_data;
    state.onselect.response_code = action.response_code;

  } else if (action.type === PARTNER_LIST_ONCLEAR) {
    state.onselect.response_data = {};
    state.onselect.response_code = 0;
  
  } else if (action.type === PARTNER_FILTER_PARTNER_NAME_ONCHANGE) {
    state.filter.partner_name = action.partner_name;

  } else if (action.type === PARTNER_FILTER_PARTNER_TYPE_ONCHANGE) {
    state.filter.partner_type = action.partner_type;

  } else if (action.type === PARTNER_FILTER_PARTNER_REGION_ONCHANGE) {
    state.filter.partner_region = action.partner_region;

  } else if (action.type === PARTNER_FILTER_ONRESET) {
    state.filter.partner_name = "";
    state.filter.partner_type = "";
    state.filter.partner_region = "";
  }

  return state;
}

export const PartnerListOffsetOnchangeActionCreator = (offset) => {
  return {
    type: PARTNER_LIST_OFFSET_ONCHANGE,
    offset: offset, 
  }
}

export const PartnerListLimitOnchangeActionCreator = (limit) => {
  return {
    type: PARTNER_LIST_LIMIT_ONCHANGE, 
    limit: limit, 
  }
}

export const PartnerListOrderOnchangeActionCreator = (order_by) => {
  return {
    type: PARTNER_LIST_ORDER_ONCHANGE, 
    order_by: order_by, 
  }
}

export const PartnerListOnselectActionCreator = (response_data, response_code) => {
  return {
      type: PARTNER_LIST_ONSELECT,
      response_data: response_data,
      response_code: response_code,
    }
}

export const PartnerListOnclearActionCreator = () => {
  return {
    type: PARTNER_LIST_ONCLEAR,
  }
}

export const PartnerFilterPartnerNameOnchangeActionCreator = (partner_name) => {
  return {
    type: PARTNER_FILTER_PARTNER_NAME_ONCHANGE,
    partner_name: partner_name, 
  }
}

export const PartnerFilterPartnerTypeOnchangeActionCreator = (partner_type) => {
  return {
    type: PARTNER_FILTER_PARTNER_TYPE_ONCHANGE,
    partner_type: partner_type, 
  }
}

export const PartnerFilterPartnerRegionOnchangeActionCreator = (partner_region) => {
  return {
    type: PARTNER_FILTER_PARTNER_REGION_ONCHANGE,
    partner_region: partner_region,
  }
}

export const PartnerFilterOnresetActionCreator = () => {
  return {
    type: PARTNER_FILTER_ONRESET,
  }
}

export default PartnerListReducer;
