import {
  PartnerInsertPartnerNameOnchangeActionCreator, PartnerInsertPartnerTypeOnchangeActionCreator,
  PartnerInsertPartnerRegionOnchangeActionCreator, PartnerInsertPartnerContactsOnchangeActionCreator,
  PartnerInsertPartnerWebsiteOnchangeActionCreator, PartnerInsertPartnerSummaryOnchangeActionCreator,
  PartnerInsertOninsertActionCreator, PartnerInsertOnclearActionCreator
} from "../../reducers/partner_insert_reducer";
import PartnerInsertComponent from "../../components/partner/partner_insert_component";
import { PartnerListOnclearActionCreator } from "../../reducers/partner_list_reducer";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import { log } from "../../helpers/log_helper";
import redirect from "../../helpers/redirect_helper";

const PartnerInsertMiddleware = (props) => {
  const navigate = useNavigate();

  const PartnerInsertPartnerNameOnchange = (partner_name) => {
    const action = PartnerInsertPartnerNameOnchangeActionCreator(partner_name);
    props.store.dispatch(action);
  }

  const PartnerInsertPartnerTypeOnchange = (partner_type) => {
    const action = PartnerInsertPartnerTypeOnchangeActionCreator(partner_type);
    props.store.dispatch(action);
  }

  const PartnerInsertPartnerRegionOnchange = (partner_region) => {
    const action = PartnerInsertPartnerRegionOnchangeActionCreator(partner_region);
    props.store.dispatch(action);
  }

  const PartnerInsertPartnerWebsiteOnchange = (partner_website) => {
    const action = PartnerInsertPartnerWebsiteOnchangeActionCreator(partner_website);
    props.store.dispatch(action);
  }

  const PartnerInsertPartnerContactsOnchange = (partner_contacts) => {
    const action = PartnerInsertPartnerContactsOnchangeActionCreator(partner_contacts);
    props.store.dispatch(action);
  }

  const PartnerInsertPartnerSummaryOnchange = (partner_summary) => {
    const action = PartnerInsertPartnerSummaryOnchangeActionCreator(partner_summary);
    props.store.dispatch(action);
  }

  const PartnerInsertOninsert = () => {
    const offcanvas_id = "offcanvas-partner-insert";
    const log_prefix = "partner-insert";
    buttons_disable(offcanvas_id);

    axios({
      method: "post",
      url: config.server_host + "partner", 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      data: {
        partner_name: props.store.getState().partner_insert.partner_name,
        partner_type: props.store.getState().partner_insert.partner_type,
        partner_region: props.store.getState().partner_insert.partner_region,
        partner_website: props.store.getState().partner_insert.partner_website,
        partner_contacts: props.store.getState().partner_insert.partner_contacts,
        partner_summary: props.store.getState().partner_insert.partner_summary,
      },

    }).then(response => {
      log.debug(log_prefix, response);
      buttons_enable(offcanvas_id);
      offcanvas_hide();
      
      let action = PartnerInsertOninsertActionCreator(response.data, response.status);
      props.store.dispatch(action);

      action = PartnerListOnclearActionCreator();
      props.store.dispatch(action);

    }).catch(e => {
      log.error(log_prefix, e);
      buttons_enable(offcanvas_id);

      if (e.status === 422) {
        const action = PartnerInsertOninsertActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }
    });
  }

  const PartnerInsertOnclear = () => {
    const action = PartnerInsertOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <PartnerInsertComponent
      partner_name={ props.store.getState().partner_insert.partner_name }
      partner_type={ props.store.getState().partner_insert.partner_type }
      partner_region={ props.store.getState().partner_insert.partner_region }
      partner_website={ props.store.getState().partner_insert.partner_website }
      partner_contacts={ props.store.getState().partner_insert.partner_contacts }
      partner_summary={ props.store.getState().partner_insert.partner_summary }

      response_data={ props.store.getState().partner_insert.oninsert.response_data }
      response_code={ props.store.getState().partner_insert.oninsert.response_code }

      PartnerInsertPartnerNameOnchange={ PartnerInsertPartnerNameOnchange }
      PartnerInsertPartnerTypeOnchange={ PartnerInsertPartnerTypeOnchange }
      PartnerInsertPartnerRegionOnchange={ PartnerInsertPartnerRegionOnchange }
      PartnerInsertPartnerWebsiteOnchange={ PartnerInsertPartnerWebsiteOnchange }
      PartnerInsertPartnerContactsOnchange={ PartnerInsertPartnerContactsOnchange }
      PartnerInsertPartnerSummaryOnchange={ PartnerInsertPartnerSummaryOnchange }

      PartnerInsertOninsert={ PartnerInsertOninsert }
      PartnerInsertOnclear={ PartnerInsertOnclear }
    />
  );
}
  
export default PartnerInsertMiddleware;
