import NavbarComponent from '../components/navbar_component';
import {
  DocumentListSearchOnchangeActionCreator,
  DocumentFilterDocumentFilenameOnchangeActionCreator,
  DocumentListOffsetOnchangeActionCreator,
  DocumentListOnclearActionCreator } from '../reducers/document_list_reducer';
import { UserSelectUserIdOnchangeActionCreator } from '../reducers/user_select_reducer';
import { useNavigate } from "react-router-dom";

const NavbarMiddleware = (props) => {
  const navigate = useNavigate();

  const SearchOnchange = (search) => {
    const action = DocumentListSearchOnchangeActionCreator(search);
    props.store.dispatch(action);
  }

  const SearchOnsubmit = () => {
    const search = props.store.getState().document_list.search;

    let action = DocumentFilterDocumentFilenameOnchangeActionCreator(search);
    props.store.dispatch(action);

    action = DocumentListOffsetOnchangeActionCreator(0);
    props.store.dispatch(action);

    action = DocumentListOnclearActionCreator();
    props.store.dispatch(action);

    SearchOnchange("");
    navigate("/documents");
  }

  const UserSelectUserIdOnchange = (user_id) => {
    const action = UserSelectUserIdOnchangeActionCreator(user_id);
    props.store.dispatch(action);
  }

  return (
    <NavbarComponent
      search={ props.store.getState().document_list.search }
      is_locked={ props.store.getState().app.is_locked }
      token_payload={ props.store.getState().app.token_payload }
      user_theme={ props.store.getState().app.user_theme }
      user_tips={ props.store.getState().app.user_tips }
      AppTokenOndelete={ props.AppTokenOndelete }
      SearchOnchange={ SearchOnchange }
      SearchOnsubmit={ SearchOnsubmit }
      UserSelectUserIdOnchange={ UserSelectUserIdOnchange }
    />
  );
}

export default NavbarMiddleware;
