import { useTranslation } from "react-i18next";
import { useEffect } from "react";
import config from "../../config";
import empty from "../../helpers/empty_helper";
import datetime from "../../helpers/datetime_helper";
import { can_read, can_write, can_edit, can_admin } from "../../helpers/role_helper"
import { offcanvas_hide, offcanvas_show } from "../../helpers/offcanvas_helper";

const CollectionSelectComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-collection-select";

  useEffect(() => {
    document.getElementById(offcanvas_id).addEventListener("show.bs.offcanvas", () => {
      props.CollectionSelectOnselect();
    });

    document.getElementById(offcanvas_id).addEventListener("hide.bs.offcanvas", () => {
      setTimeout(
        () => { props.CollectionSelectOnclear() },
        config.offcanvas_latency);
    });
  }, []);

  const CollectionUpdateCollectionIdOnchange = (event) => {
    event.preventDefault();
    props.CollectionUpdateCollectionIdOnchange(props.collection_id);

    offcanvas_hide();
    offcanvas_show("offcanvas-collection-update");
  }

  const CollectionDeleteCollectionIdOnchange = (event) => {
    event.preventDefault();
    props.CollectionDeleteCollectionIdOnchange(props.collection_id);

    offcanvas_hide();
    offcanvas_show("offcanvas-collection-delete");
  }

  const CollectionLockCollectionIdOnchange = (event) => {
    event.preventDefault();
    props.CollectionLockCollectionIdOnchange(props.collection_id);

    offcanvas_hide();
    offcanvas_show("offcanvas-collection-lock");
  }

  const UserSelectUserIdOnchange = (event) => {
    const user_id = event.target.dataset.user_id;
    props.UserSelectUserIdOnchange(user_id);

    offcanvas_hide();
    offcanvas_show("offcanvas-user-select");
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title d-flex">
          { t("offcanvas-collection-select-title") }

          <div className="dropdown ms-2">
            <a href="#" className="link link-primary dropdown-toggle no-after" type="button" data-bs-toggle="dropdown">
              <i className="bi bi-list"></i>
            </a>
            <ul className="dropdown-menu">
              <li><a className="dropdown-item" href="#" onClick={ offcanvas_hide }>{ t("button-cancel") }</a></li>
              <li><a className={ "dropdown-item" + (can_edit(props.user_role) ? "" : " d-none") } href="#" onClick={ CollectionUpdateCollectionIdOnchange }>{ t("button-edit") }</a></li>
              <li><a className={ "dropdown-item" + (can_edit(props.user_role) ? "" : " d-none") } href="#" onClick={ CollectionLockCollectionIdOnchange }>{ t("button-lock") }</a></li>
              <li><a className={ "dropdown-item" + (can_admin(props.user_role) ? "" : " d-none") } href="#" onClick={ CollectionDeleteCollectionIdOnchange }>{ t("button-delete") }</a></li>
            </ul>
          </div>

        </h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

          <div className="form-text">
            { t("id") }
          </div>
          <div>
            { props.response_code === 200 ? props.response_data.id : <span className="placeholder placeholder-lg col-2"></span> }
          </div>

          <div className="form-text mt-4">
            { t("collection-name") }
          </div>
          <div>
            { props.response_code === 200 ? props.response_data.collection_name : <span className="placeholder placeholder-lg col-8"></span> }
          </div>

          { props.response_code === 200 && props.response_data.collection_summary && <>
            <div className="form-text mt-4">
              { t("collection-summary") }
            </div>
            <div>
              { props.response_code === 200 ? props.response_data.collection_summary : <span className="placeholder placeholder-lg col-12"></span> }
            </div>
          </> }

          <div className="form-text mt-4">
            { t("collection-locked") }
          </div>
          <div>
            <i className={ "bi me-1 " + (props.response_code === 200 && props.response_data.is_locked ? "bi-lock" : "bi-unlock") }></i>
            { props.response_code === 200 ? (props.response_data.is_locked ? t("collection-locked-true") : t("collection-locked-false")) : <span className="placeholder placeholder-lg col-2"></span> }
          </div>

          <div className="form-text mt-4">
            { t("collection-documents-count") }
          </div>
          <div>
            { props.response_code === 200 ? props.response_data.documents_count : <span className="placeholder placeholder-lg col-2"></span> }
          </div>

          <div className="form-text mt-4">
            { t("collection-user") }
          </div>
          <div>
            { props.response_code === 200 ? <span role="button" className="link-primary" data-user_id={ props.response_data.user_id } onClick={ UserSelectUserIdOnchange }>{ props.response_data.user_name }</span> : <span className="placeholder placeholder-lg col-8"></span> }
          </div>

          <div className="form-text mt-4">
            { t("created-date") }
          </div>
          <div>
            { props.response_code === 200 ? datetime(props.response_data.created_date, props.user_timezone, t) : <span className="placeholder placeholder-lg col-8"></span> }
          </div>

          <div className="form-text mt-4">
            { t("updated-date") }
          </div>
          <div>
            { props.response_code === 200 ? datetime(props.response_data.updated_date, props.user_timezone, t) : <span className="placeholder placeholder-lg col-8"></span> }
          </div>

        </form>
      </div>
    </div>
  );
}

export default CollectionSelectComponent;
