import { useTranslation } from "react-i18next";
import config from "../../config";
import empty from "../../helpers/empty_helper";
import datetime from "../../helpers/datetime_helper";
import { can_read, can_write, can_edit, can_admin } from "../../helpers/role_helper"
import PaginationComponent from "../pagination_component";
import DatatableComponent from "../datatable_component";
import DatalistMiddleware from "../../middleware/datalist_middleware";
import DropdownComponent from "../dropdown_component";
import { CollectionFilterUserDatalistOnloadActionCreator } from "../../reducers/collection_list_reducer";
import { offcanvas_show } from "../../helpers/offcanvas_helper";
import { useNavigate } from "react-router-dom";

let timer;

const CollectionListComponent = (props) => {
  const { t } = useTranslation();
  const navigate = useNavigate();

  const CollectionListOnselect = () => {
    props.CollectionListOnselect();
  }

  if (empty(props.response_data) && !empty(props.user_token)) {
    CollectionListOnselect();
  }

  const CollectionListOffsetOnchange = (offset) => {
    props.CollectionListOffsetOnchange(offset);
  }

  const CollectionListLimitOnchange = (limit) => {
    props.CollectionListLimitOnchange(limit);
  }

  const CollectionListOrderOnchange = (event) => {
    const order_by = event.target.dataset.order_by;
    props.CollectionListOrderOnchange(order_by);
    props.CollectionListOnclear();
  }

  const CollectionListOnclear = () => {
    props.CollectionListOnclear();
  }

  const RedirectDocuments = (event) => {
    props.DocumentListOffsetOnchange(0);
    props.DocumentListOnclear();
    props.DocumentFilterOnreset();

    const collection_id = event.target.dataset.collection_id;
    const collection_name = event.target.dataset.collection_name;
    props.DocumentFilterCollectionDatalistCollectionIdOnchange(collection_id, collection_name);

    navigate("/documents");
  }

  const TimerStart = () => {
    clearTimeout(timer);
    timer = setTimeout(() => {
      CollectionListOffsetOnchange(0);
      props.CollectionListOnclear();
    }, config.input_latency);
  }

  const CollectionFilterCollectionNameOnchange = (event) => {
    const collection_name = event.target.value;
    props.CollectionFilterCollectionNameOnchange(collection_name);
    TimerStart();
  }

  const CollectionFilterIsLockedOnchange = (event) => {
    const is_locked = event.target.value;
    props.CollectionFilterIsLockedOnchange(is_locked);
  }

  const CollectionSelectCollectionIdOnchange = (event) => {
    const collection_id = event.target.dataset.collection_id;
    props.CollectionSelectCollectionIdOnchange(collection_id);
    offcanvas_show("offcanvas-collection-select");
  }

  const UserSelectUserIdOnchange = (event) => {
    const user_id = event.target.dataset.user_id;
    props.UserSelectUserIdOnchange(user_id);
    offcanvas_show("offcanvas-user-select");
  }

  const filters_count = ((props.filter.user_datalist.user_id > 0) + (props.filter.is_locked !== "") + (props.filter.collection_name !== "")) || null;

  const columns = [
    { name: t("id"), order_by: "id" },
    { name: t("created-date"), order_by: "created_date" },
    { name: t("collection-user") },
    { name: "" },
    { name: t("collection-name"), order_by: "collection_name" },
    { name: t("collection-documents-count"), order_by: "documents_count" },
  ];

  const rows = props.response_data?.collections?.map(collection => { 
      return [
        collection.id,
        datetime(collection.created_date, props.user_timezone, t),
        <span role="button" className="link-primary" data-user_id={ collection.user_id } onClick={ UserSelectUserIdOnchange }>{ collection.user_name }</span>,
        collection.is_locked ? <i className="bi bi-lock"></i> : "",
        <span role="button" className="link-primary" data-collection_id={ collection.id } onClick={ CollectionSelectCollectionIdOnchange }>{ collection.collection_name }</span>,
        <span role="button" className="link-primary" data-collection_id={ collection.id } data-collection_name={ collection.collection_name } onClick={ RedirectDocuments }>{ collection.documents_count }</span>
      ];
    });

  const ResetFilters = () => {
    props.CollectionListOffsetOnchange(0);
    props.CollectionFilterOnreset();
    props.CollectionListOnclear();
  }

  return (<>
    <h1 className="mb-4">{ t("page-collections-title") }</h1>

    <div className="d-flex d-inline align-items-center mb-4">
      <div className="btn-group btn-group-outline">
        <button type="button" className="btn btn-outline-primary" data-bs-toggle="collapse" href="#collections-filters">
          <i className="bi bi-sliders2"></i> { t("button-filters") } <span className="badge text-bg-primary">{ filters_count }</span>
        </button>

        <button type="button" className="btn btn-outline-primary" onClick={ ResetFilters }>
          <i className="bi bi-x-lg"></i> { t("button-reset") }
        </button>
      </div>

      <a href="#offcanvas-collection-insert" data-bs-toggle="offcanvas" type="button" className={ "btn btn-outline-primary ms-3" + (["writer", "editor", "admin"].includes(props.token_payload.user_role) ? "" : " d-none") }>
        <i className="bi bi-plus-lg"></i> { t("page-collections-add") }
      </a>
      
      <a href="#" className="link-primary text-decoration-none ms-3" onClick={ CollectionListOnclear }>
        <i className="bi bi-arrow-clockwise"></i> { t("button-refresh") }
      </a>

      <div className={ "ms-5" + (props.collection_ids.length > 0 ? "" : " d-none") }>
        Selected collections <span className="badge text-bg-primary">{ props.collection_ids.length }</span>
      </div>

      <a type="button" className={ "btn btn-outline-danger ms-3" + ( props.collection_ids.length > 0 && can_admin(props.token_payload.user_role) ? "" : " d-none" ) } data-bs-toggle="offcanvas" href="#offcanvas-collection-delete">
        <i className="bi bi-trash3"></i> Delete
      </a>

      <a type="button" className={ "btn btn-outline-primary ms-3" + ( props.collection_ids.length > 0 && can_edit(props.token_payload.user_role) ? "" : " d-none" ) } data-bs-toggle="offcanvas" href="#offcanvas-collection-lock">
        <i className="bi bi-lock"></i> Lock
      </a>

    </div>

    <div className="row collapse" id="collections-filters">
      <div className="col-6 mb-4">
        <div className="form-floating">
          <input onChange={ CollectionFilterCollectionNameOnchange } type="search" className={ "form-control" + (props.collection_name ? " border-primary" : "") } id="floatingInput" placeholder={ t("filter-collection-name-name") } value={ props.collection_name } />
          <label htmlFor="floatingInput">{ t("filter-collection-name") }</label>
        </div>
      </div>

      <div className="col-3 mb-4">
        <DropdownComponent
          options={[
            { value: "", text: "" },
            { value: 1, text: t("collection-locked-true") },
            { value: 0, text: t("collection-locked-false") },
          ]}
          dispatch={ props.dispatch }
          dropdown_placeholder={ t("filter-collection-lock") }
          value={ props.is_locked }
          onchange={ CollectionFilterIsLockedOnchange }
          onupdate={ () => { CollectionListOffsetOnchange(0); CollectionListOnclear(); } }
        />
      </div>

      <div className="col-3 mb-4">
        <DatalistMiddleware
          dispatch={ props.dispatch }
          user_token={ props.user_token }
          // datalist data
          datalist_name="collection-list-user-datalist"
          datalist_placeholder={ t("filter-user-name") }
          datalist_value={ props.filter.user_datalist.user_name }
          datalist_id={ props.filter.user_datalist.user_id }
          response_data={ props.filter.user_datalist.response_data }
          response_code={ props.filter.user_datalist.response_code }
          datalist_options={ !empty(props.filter.user_datalist.response_data) ? props.filter.user_datalist.response_data.users.map(el => { return { id: el.id, value: el.first_name + " " + el.last_name } }) : [] }
          // // request
          request_url={ config.server_host + "users" }
          request_param="full_name__ilike"
          request_order_by="full_name"
          request_order="asc"
          // // datalist actions
          datalist_onchange={ props.CollectionFilterUserDatalistUserNameOnchange }
          datalist_onload_action_creator={ CollectionFilterUserDatalistOnloadActionCreator }
          onupdate={ () => { CollectionListOffsetOnchange(0); CollectionListOnclear(); } }
        />
      </div>
    </div>

    <DatatableComponent
      limit={ props.limit }
      order_by={ props.order_by }
      order={ props.order }
      order_onchange={ CollectionListOrderOnchange }
      columns={ columns }
      rows={ rows }
      onselect={ (id) => { props.CollectionDeleteCollectionIdsOnshift(id); props.CollectionLockCollectionIdsOnshift(id); } }
      selected_rows={ props.collection_ids }
      can_select={ can_edit(props.token_payload.user_role) }
    />

    <PaginationComponent
      offset={ props.offset } 
      limit={ props.limit }
      limit_values={ config.allowed_collections_limit }
      count={ props.response_data.collections_count }
      offset_onchange={ CollectionListOffsetOnchange } 
      limit_onchange={ CollectionListLimitOnchange }
      onclear={ CollectionListOnclear }
    />

  </>);
}

export default CollectionListComponent;