import { useTranslation } from 'react-i18next';

const PaginationComponent = (props) => {
  const { t } = useTranslation();

  // Initial values
  const offset = parseInt(props.offset);
  const limit = parseInt(props.limit);
  const count = parseInt(props.count);

  const limit_values = props.limit_values.map(value => { 
    return <option key={ value } value={ value }>{ value }</option>;
  });

  // Change offset.
  const offset_onclick = (offset) => {
    props.offset_onchange(offset);
    props.onclear();
  }

  // Change limit.
  const limit_onclick = (limit) => {
    props.limit_onchange(limit);
    props.offset_onchange(0);
    props.onclear();
  }

  // last offset
  let lastOffset = Math.floor(count / limit) * limit;
  if (count > 0 && count % limit === 0) {
    lastOffset -= limit;
  }

  // middle cells
  let middleStart = offset - (2 * limit);
  if (middleStart < 0) {middleStart = 0}
  
  let middleEnd = offset + (2 * limit);
  if (middleEnd > lastOffset) { middleEnd = lastOffset }

  // left cells
  let leftStart = 0;
  let leftEnd = limit;
  if (leftEnd >= lastOffset) { leftEnd = lastOffset }
  
  // right cells
  let rightEnd = lastOffset; 
  let rightStart = lastOffset - limit;
  if (rightStart < offset) { rightStart = rightEnd }

  // elements
  let elements = [];

  // left arrow
  if (offset > 0) {
    elements.push(
      <li key="minus_one" onClick={ () => offset_onclick(offset - limit) } className="page-item">
        <span role="button" className="page-link">
          <i className="bi bi-arrow-left"></i>
        </span>
      </li>
    );
  }

  // left elements
  if (leftStart < middleStart) {
    elements.push(
      <li key="zero" onClick={ () => offset_onclick(0) } className="page-item">
        <span role="button" className="page-link">
          1
        </span>
      </li>
    );
  }

  if (leftEnd < middleStart) {
    elements.push(
      <li key={ leftEnd } onClick={ () => offset_onclick(leftEnd) } className="page-item">
        <span role="button" className="page-link">
          { (leftEnd / limit) + 1 }
        </span>
      </li>
    );
  }

  // left points
  if (leftEnd < middleStart - limit) {
    elements.push(
      <li key="left-dots" className="page-item">
        <span className="page-link text-secondary">
          <i className="bi bi-dash-lg"></i>
        </span>
      </li>
    );
  }

  // middle elements
  for (let i = middleStart; i <= middleEnd; i += limit) {
    elements.push(
      <li key={ i } className="page-item">
        <span role="button" onClick={ () => offset_onclick(i) } className={"page-link" + (offset === i ? " active" : "")}>
          { (i / limit) + 1 }
        </span>
      </li>
    );
  }

  // right points
  if (rightStart > middleEnd + limit) {
    elements.push(
      <li key="right-dots" className="page-item">
        <span className="page-link text-secondary">
          <i className="bi bi-dash-lg"></i>
        </span>
      </li>
    );
  }

  // right elements
  if (rightStart > middleEnd) {
    elements.push(
      <li key={ rightStart } onClick={ () => offset_onclick(rightStart) } className="page-item">
        <span role="button" className="page-link">
          { (rightStart / limit) + 1 }
        </span>
      </li>
    );
  }

  if (rightEnd > middleEnd) {
    elements.push(
      <li key={ rightEnd } onClick={ () => offset_onclick(rightEnd) } className="page-item">
        <span role="button" className="page-link">
          { (rightEnd / limit) + 1 }
        </span>
      </li>
    );
  }

  // right arrow
  if (offset < rightEnd) {
    elements.push(
      <li key="plus_one" onClick={ () => offset_onclick(offset + limit) } className="page-item">
        <span role="button" className="page-link">
          <i className="bi bi-arrow-right"></i>
        </span>
      </li>
    );
  }

  return (<>
    <div className="row">

      <div className="col-sm-auto">
        <small className="text-secondary">{ t("pagination-count") }: { count }</small>
        <nav className="mt-2">
          <ul className="pagination">
            { elements }
          </ul>
        </nav>
      </div>

      <div className="col-sm-auto">
        <small className="text-secondary">{ t("pagination-limit") }:</small>
        <select value={ limit } className="form-select mt-2" onChange={ (event) => limit_onclick(event.target.value) }>
          { limit_values }
        </select>
      </div>

    </div>
  </>);
}

export default PaginationComponent;
