import {
  CollectionDeleteCollectionIdsOnshiftActionCreator,
  CollectionDeleteOnclearActionCreator } from "../../reducers/collection_delete_reducer";
import { CollectionListOffsetOnchangeActionCreator, CollectionListOnclearActionCreator } from "../../reducers/collection_list_reducer";
import { CollectionLockCollectionIdsOnshiftActionCreator } from "../../reducers/collection_lock_reducer";
import CollectionDeleteComponent from "../../components/collection/collection_delete_component";
import config from "../../config";
import axios from "axios";
import empty from "../../helpers/empty_helper";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import { log } from "../../helpers/log_helper";
import { useNavigate } from "react-router-dom";
import redirect from "../../helpers/redirect_helper";

const CollectionDeleteMiddleware = (props) => {
  const navigate = useNavigate();

  const CollectionDeleteCollectionIdsOnshift = (collection_id) => {
    const action = CollectionDeleteCollectionIdsOnshiftActionCreator(collection_id);
    props.store.dispatch(action);
  }

  const CollectionLockCollectionIdsOnshift = (collection_id) => {
    const action = CollectionLockCollectionIdsOnshiftActionCreator(collection_id);
    props.store.dispatch(action);
  }

  const CollectionDeleteOndelete = () => {
    const offcanvas_id = "offcanvas-collection-delete";
    const log_prefix = "collection-delete";
    buttons_disable(offcanvas_id);

    const collection_id = props.store.getState().collection_delete.collection_id;
    const collection_ids = props.store.getState().collection_delete.collection_ids;

    let ids_to_delete = collection_id ? [collection_id] : Array.from(collection_ids);
    let ids_in_progress = Array.from(ids_to_delete);

    ids_to_delete.forEach(id => {
      axios({
        method: "delete",
        url: config.server_host + "collection/" + id, 
        headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
        params: {},

      }).then(response => {
        log.debug(log_prefix, response);

        ids_in_progress.splice(ids_in_progress.indexOf(id), 1);
        if (collection_ids.includes(id)) {
          CollectionDeleteCollectionIdsOnshift(id);
          CollectionLockCollectionIdsOnshift(id);
        }

        if (empty(ids_in_progress)) {
          CollectionListOnclear();
          buttons_enable(offcanvas_id);
          offcanvas_hide();
        }
        
      }).catch(e => {
        log.error(log_prefix, e);

        if (e.status === 404) {
            ids_in_progress.splice(ids_in_progress.indexOf(id), 1);
            if (collection_ids.includes(id)) {
              CollectionDeleteCollectionIdsOnshift(id);
              CollectionLockCollectionIdsOnshift(id);
            }
  
          if (empty(ids_in_progress)) {
            CollectionListOnclear();
            buttons_enable(offcanvas_id);
            offcanvas_hide();
          }
  
        } else {
          redirect(e, navigate);
        }
      });
    });
  }

  const CollectionDeleteOnclear = () => {
    const action = CollectionDeleteOnclearActionCreator();
    props.store.dispatch(action);
  }

  const CollectionListOnclear = () => {
    let action = CollectionListOffsetOnchangeActionCreator(0);
    props.store.dispatch(action);

    action = CollectionListOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <CollectionDeleteComponent
      collection_id={ props.store.getState().collection_delete.collection_id }
      collection_ids={ props.store.getState().collection_delete.collection_ids }

      CollectionDeleteOndelete={ CollectionDeleteOndelete }
      CollectionDeleteOnclear={ CollectionDeleteOnclear }
    />
  );
}
  
export default CollectionDeleteMiddleware;
