import { useTranslation } from "react-i18next";
import { useEffect } from 'react';
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import errors from "../../helpers/errors_helper";
import config from "../../config";

const UserTotpComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-user-totp";

  useEffect(() => {
    const offcanvas = document.getElementById(offcanvas_id);

    offcanvas.addEventListener("shown.bs.offcanvas", () => {
      offcanvas.querySelector(".focused").focus();
    });

    offcanvas.addEventListener("hide.bs.offcanvas", () => {
      setTimeout(() => { props.UserTotpOnclear() },
      config.offcanvas_refresh_delay);
    });
  }, []);

  const UserTotpUserTotpOnchange = (event) => {
    props.UserTotpUserTotpOnchange(event.target.value);
  }

  const UserTotpTokenUnexpiredOnclick = () => {
    props.UserTotpTokenUnexpiredOnclick();
  }

  const is_valid = (key) => {
    if (key === "user_totp") {
      return  props.user_totp.length === 6 && props.user_totp.match(/^\d+$/) !== null;
    }
  }

  const submit_enabled = is_valid("user_totp");
  const response_errors = errors(props.response_data);

  const UserTotpOnsubmit = (event) => {
    event.preventDefault();
    if (submit_enabled) {
      props.UserTotpOnsubmit();
    }
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title">
          { t("offcanvas-user-totp-title") }
        </h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

          <div className="form-text">
            { t("user-login") }
          </div>
          <div>
            { props.user_login }
          </div>

          <div className="form-text mt-4">
            { t("offcanvas-user-totp-user-totp-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ UserTotpUserTotpOnchange } value={ props.user_totp } type="text" className={ "form-control focused" + ("user_totp" in response_errors ? " border-danger glow-danger" : is_valid("user_totp") ? " border-primary" : "") } placeholder={ t("user-totp") } maxLength="6" />
            <label>{ t("user-totp") }</label>
          </div>
          <div className="form-text text-danger">
            { "user_totp" in response_errors && t("error_" + response_errors["user_totp"]) }
          </div>

          <div className="form-floating mt-4">
            <div className="form-check">
              <input onChange={ UserTotpTokenUnexpiredOnclick } checked={ props.token_unexpired } className="form-check-input" type="checkbox" value="" id="remember-me" />
              <label className="form-check-label form-text" htmlFor="remember-me">
                { t("offcanvas-user-totp-token-unexpired-text") }
              </label>
            </div>
          </div>

          <button onClick={ offcanvas_hide } className="btn btn-outline-primary mt-4" type="button">
            <i className="bi bi-arrow-left"></i> { t("button-cancel") }
          </button>

          <button onClick={ UserTotpOnsubmit } className={"btn btn-primary mt-4 ms-2 " + (!submit_enabled ? "disabled" : "")} type="submit">
            <i className="bi bi-check2"></i> { t("button-submit") }
          </button>

        </form>
      </div>
    </div>
  );
}

export default UserTotpComponent;
