function can_read(user_role) {
  return ["reader", "writer", "editor", "admin"].includes(user_role);
}

function can_write(user_role) {
  return ["writer", "editor", "admin"].includes(user_role);
}

function can_edit(user_role) {
  return ["editor", "admin"].includes(user_role);
}

function can_admin(user_role) {
  return user_role === "admin";
}

export { can_read, can_write, can_edit, can_admin }
