import React from "react"
import empty from "../../helpers/empty_helper";

const FormTextComponent = (props) => {
  return (
    <>
      <div className={ "form-text mt-" + props.mt + ((props.response_code === 200 && !empty(props.value) ? "" : " d-none")) }>
        { props.text }
      </div>
      <div>
        { props.response_code === 200 && !empty(props.value) ? props.value : (props.response_code !== 200 ? <span className="placeholder placeholder-lg col-8"></span> : "") }
      </div>
    </>
  )
}

export default FormTextComponent;
