import { useTranslation } from "react-i18next";
import { useEffect } from "react";
import config from "../../config";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import errors from "../../helpers/errors_helper";

const UserLoginComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-user-login";

  useEffect(() => {
    const offcanvas = document.getElementById(offcanvas_id);

    offcanvas.addEventListener("hide.bs.offcanvas", () => {
      setTimeout(() => { props.UserLoginOnclear() }, config.offcanvas_latency);
    });

    offcanvas.addEventListener("shown.bs.offcanvas", function () {
      offcanvas.querySelector(".focused").focus();
    });
  }, []);

  const UserLoginUserLoginOnchange = (event) => {
    props.UserLoginUserLoginOnchange(event.target.value);
  }

  const UserLoginUserPasswordOnchange = (event) => {
    props.UserLoginUserPasswordOnchange(event.target.value);
  }

  const is_valid = (key) => {
    if (key === "user_login") {
      return props.user_login.length >= 2 && props.user_login.length <= 40;

    } else if (key === "user_password") {
      return props.user_password.length >= 6;
    }
  }

  const submit_enabled = is_valid("user_login") && is_valid("user_password");
  const response_errors = errors(props.response_data);

  const UserLoginOnsubmit = (event) => {
    event.preventDefault();
    if (submit_enabled) {
      props.UserLoginOnsubmit();
    }
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title">
          { t("offcanvas-user-login-title") }
        </h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

          <div className="form-text">
            { t("offcanvas-user-login-user-login-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ UserLoginUserLoginOnchange } value={ props.user_login } type="text" className={ "form-control focused" + ("user_login" in response_errors ? " border-danger glow-danger" : is_valid("user_login") ? " border-primary" : "") } placeholder={ t("user-login") } maxLength="40" />
            <label>{ t("user-login") }</label>
          </div>
          <div className="form-text text-danger">
            { "user_login" in response_errors && t("error_" + response_errors["user_login"]) }
          </div>

          <div className="form-text mt-4">
            { t("offcanvas-user-login-user-password-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ UserLoginUserPasswordOnchange } value={ props.user_password } type="password" className={ "form-control" + ("user_password" in response_errors ? " border-danger glow-danger" : is_valid("user_password") ? " border-primary" : "") } placeholder={ t("user-login-user-password-input") }  autoComplete="user-password" />
            <label>{ t("user-password") }</label>
          </div>
          <div className="form-text text-danger">
            { "user_password" in response_errors && t("error_" + response_errors["user_password"]) }
          </div>

          <button onClick={ offcanvas_hide } className="btn btn-outline-primary mt-4" type="button">
            <i className="bi bi-arrow-left"></i> { t("button-cancel") }
          </button>

          <button onClick={ UserLoginOnsubmit } className={"btn btn-primary mt-4 ms-2 " + (!submit_enabled ? "disabled" : "")} type="submit">
            <i className="bi bi-check2"></i> { t("button-submit") }
          </button>

        </form>
      </div>
    </div>
  );
}

export default UserLoginComponent;
