import { useTranslation } from 'react-i18next';
import empty from '../helpers/empty_helper';
import React from 'react';
import config from '../config';

const DropdownComponent = (props) => {
  const { t } = useTranslation();

  const onchange = (event) => {
      props.onchange(event);
      props.onupdate();
  }

  const options = props.options.map((option, key) => {
    return <option key={ key } value={ option.value }>{ option.text }</option>;
  });

  return (
    <div className="form-floating">
      <select className={ "form-select" + (props.value !== "" ? " border-primary" : "") } id="floatingSelect" onChange={ onchange } value={ props.value }>
        { options }
      </select>
      <label htmlFor="floatingSelect">{ props.dropdown_placeholder }</label>
    </div>
  );
}

export default DropdownComponent;
