import config from "../config";
import Cookies from "universal-cookie";

const cookies = new Cookies();

function cookies_get(key) {
  return cookies.get(key);
}

function cookies_set(key, value) {
  cookies.set(key, value, {path: "/", maxAge: config.user_cookie_expires});
}

function cookies_remove(key) {
  cookies.remove(key);
}

export { cookies_get, cookies_set, cookies_remove }
