const frequency_units = 7; // Hz, kHz, MHz, GHz, THz, PHz, EHz

const frequency = (hertz, t) => {
    const thresh = 1000;  // Conversion threshold (1000)
    const dp = 2;  // Decimal places for rounding

    // If the frequency is 0 or undefined, return '0 Hz'
    if (hertz === 0 || hertz === undefined) {
        return '0 ' + t('frequency.0');  // "Hz"
    }

    // If the frequency is less than 1000 Hz, return it in Hz
    else if (Math.abs(hertz) < thresh) {
        return hertz + ' ' + t('frequency.0');  // "Hz"
    }

    let u = 0;  // Unit index (starts from Hz)
    const r = 10 ** dp;  // Rounding factor for decimal places

    // Convert the frequency into the appropriate unit
    do {
        hertz /= thresh;
        ++u;
    } while (Math.round(Math.abs(hertz) * r) / r >= thresh && u < frequency_units);

    return hertz.toFixed(dp) + ' ' + t('frequency.' + u);  // Return formatted frequency with the correct unit
}

export default frequency;
