const DOCUMENT_MOVE_DOCUMENT_ID_ONCHANGE = "DOCUMENT_MOVE_DOCUMENT_ID_ONCHANGE";
const DOCUMENT_MOVE_DOCUMENT_IDS_ONSHIFT = "DOCUMENT_MOVE_DOCUMENT_IDS_ONSHIFT";
const DOCUMENT_MOVE_COLLECTION_DATALIST_COLLECTION_NAME_ONCHANGE = "DOCUMENT_MOVE_COLLECTION_DATALIST_COLLECTION_NAME_ONCHANGE";
const DOCUMENT_MOVE_COLLECTION_DATALIST_COLLECTION_ID_ONCHANGE = "DOCUMENT_MOVE_COLLECTION_DATALIST_COLLECTION_ID_ONCHANGE";
const DOCUMENT_MOVE_COLLECTION_DATALIST_ONSELECT = "DOCUMENT_MOVE_COLLECTION_DATALIST_ONSELECT";
const DOCUMENT_MOVE_ONCLEAR = "DOCUMENT_MOVE_ONCLEAR";

const initial = {
  document_id: 0,
  document_ids: [],
  collection_datalist: {
    collection_name: "",
    collection_id: 0,
    response_data: {},
    response_code: 0,
  },
  onupdate: {
    response_data: {},
    response_code: 0,
  },
};

const DocumentMoveReducer = (state = initial, action) => {

  if (action.type === DOCUMENT_MOVE_DOCUMENT_ID_ONCHANGE) {
    state.document_id = parseInt(action.document_id);

  } else if (action.type === DOCUMENT_MOVE_DOCUMENT_IDS_ONSHIFT) {
    const document_id = parseInt(action.document_id);

    if (state.document_ids.includes(document_id)) {
      state.document_ids = state.document_ids.filter(id => id !== document_id);

    } else {
      state.document_ids.push(document_id);
    }

  } else if (action.type === DOCUMENT_MOVE_COLLECTION_DATALIST_COLLECTION_NAME_ONCHANGE) {
    state.collection_datalist.collection_name = action.collection_name;

  } else if (action.type === DOCUMENT_MOVE_COLLECTION_DATALIST_COLLECTION_ID_ONCHANGE) {
    state.collection_datalist.collection_id = action.collection_id;
    state.collection_datalist.collection_name = action.collection_name;

  } else if (action.type === DOCUMENT_MOVE_COLLECTION_DATALIST_ONSELECT) {
    state.collection_datalist.response_data = action.response_data;
    state.collection_datalist.response_code = action.response_code;

    const collection = Array.prototype.find.call(action.response_data.collections, el => {
      return el.collection_name.toLocaleLowerCase() === state.collection_datalist.collection_name.toLocaleLowerCase();
    });
    state.collection_datalist.collection_id = collection ? collection.id : 0;

  } else if (action.type === DOCUMENT_MOVE_ONCLEAR) {
    state.document_id = 0

    state.collection_datalist.collection_name = "";
    state.collection_datalist.collection_id = 0;
    state.collection_datalist.response_data = {};
    state.collection_datalist.response_code = 0;
  }

  return state;
}

export const DocumentMoveDocumentIdOnchangeActionCreator = (document_id) => {
  return {
    type: DOCUMENT_MOVE_DOCUMENT_ID_ONCHANGE,
    document_id: document_id, 
  }
}

export const DocumentMoveDocumentIdsOnshiftActionCreator = (document_id) => {
  return {
    type: DOCUMENT_MOVE_DOCUMENT_IDS_ONSHIFT,
    document_id: document_id, 
  }
}

export const DocumentMoveCollectionDatalistCollectionNameOnchangeActionCreator = (collection_name) => {
  return {
    type: DOCUMENT_MOVE_COLLECTION_DATALIST_COLLECTION_NAME_ONCHANGE, 
    collection_name: collection_name, 
  }
}

export const DocumentMoveCollectionDatalistCollectionIdOnchangeActionCreator = (collection_id, collection_name) => {
  return {
    type: DOCUMENT_MOVE_COLLECTION_DATALIST_COLLECTION_ID_ONCHANGE, 
    collection_id: collection_id, 
    collection_name: collection_name,
  }
}

export const DocumentMoveCollectionDatalistOnselectActionCreator = (response_data, response_code) => {
  return {
      type: DOCUMENT_MOVE_COLLECTION_DATALIST_ONSELECT,
      response_data: response_data,
      response_code: response_code,
    }
}

export const DocumentMoveOnclearActionCreator = () => {
  return {
    type: DOCUMENT_MOVE_ONCLEAR,
  }
}

export default DocumentMoveReducer;
