import empty from "../helpers/empty_helper";
import config from "../config";
import filesize from "../helpers/filesize_helper";
import { useTranslation } from "react-i18next";

const DatacardsComponent = (props) => {
  const { t } = useTranslation();

  const cards = (props.cards) ? props.cards.map((card, rowIndex) => {
    return (
      <div key={ rowIndex } className="col-2 mb-4">
        <div className="card">
          { card.thumbnail_url ?
            <a href="#" onClick={ props.onclick }>
              <img data-document_id={ card.id }  src={ card.thumbnail_url } className="card-img-top" style={{ height: config.card_img_height, width: "100%", objectFit: "cover" }} alt={ card.document_filename } />
            </a>
          :
            <svg className="bd-placeholder-img card-img-top" width="100%" height={ config.card_img_height } xmlns="http://www.w3.org/2000/svg" role="img" preserveAspectRatio="xMidYMid slice" focusable="false">
              <title>{ card.document_filename }</title>
              <rect width="100%" height="100%" fill="#868e96"></rect>
            </svg>
          }
          
          <input
            className="form-check-input"
            type="checkbox"
            checked={props.selected_elements.includes(card.id)}
            onChange={event => { props.onselect(card.id) }}
            style={{
              position: "absolute",
              top: "4px",
              left: "8px",
              zIndex: 10
            }}
          />

          <div className="card-body">
            <a href="#" role="button" className="link-primary text-decoration-none" data-document_id={ card.id } onClick={ props.onclick }>
              { card.document_filename }
            </a>
            <p className="card-text">
              <small className="text-secondary">{ filesize(card.document_size, t) }</small>
            </p>
          </div>
        </div>
      </div>
    )

  }) : Array.from({ length: props.limit }, (_, rowIndex) => (
    <div key={ rowIndex } className="col-2 mb-4">
      <div className="card">
        <svg className="bd-placeholder-img card-img-top" width="100%" height={ config.card_img_height } xmlns="http://www.w3.org/2000/svg" role="img" preserveAspectRatio="xMidYMid slice" focusable="false"><title>Placeholder</title><rect width="100%" height="100%" fill="#868e96"></rect></svg>
        <div className="card-body">
          <h5 className="card-title"><span className="placeholder placeholder-lg col-8"></span></h5>
          <p className="card-text">
            <span className="placeholder placeholder-lg col-3 me-1"></span>
          </p>
        </div>
      </div>
    </div>
  ));

  return (<>
    <div className="container overflow-hidden p-0 m-0" style={{ maxWidth: "100%" }}>
      <div className="row">
        { cards }
      </div>
    </div>
  </>);
}

export default DatacardsComponent;
