const USER_ROLE_USER_ID_ONCHANGE = "USER_ROLE_USER_ID_ONCHANGE";
const USER_ROLE_USER_ROLE_ONCHANGE = "USER_ROLE_USER_ROLE_ONCHANGE";
const USER_ROLE_IS_ACTIVE_ONCHANGE = "USER_ROLE_IS_ACTIVE_ONCHANGE";
const USER_ROLE_ONSELECT = "USER_ROLE_ONSELECT";
const USER_ROLE_ONUPDATE = "USER_ROLE_ONUPDATE";
const USER_ROLE_ONCLEAR = "USER_ROLE_ONCLEAR";

const initial = {
  user_id: 0,
  user_login: "",
  user_role: "",
  is_active: false,
  onupdate: {
    response_data: {},
    response_code: 0,
  },
};

const UserRoleReducer = (state = initial, action) => {

   if (action.type === USER_ROLE_USER_ID_ONCHANGE) {
    state.user_id = action.user_id;

  } else if (action.type === USER_ROLE_USER_ROLE_ONCHANGE) {
    state.user_role = action.user_role;
  
  } else if (action.type === USER_ROLE_IS_ACTIVE_ONCHANGE) {
    state.is_active = action.is_active;

  } else if (action.type === USER_ROLE_ONSELECT) {
    state.user_login = action.response_data.user_login;
    state.user_role = action.response_data.user_role;
    state.is_active = action.response_data.is_active;

  } else if (action.type === USER_ROLE_ONUPDATE) {
    state.onupdate.response_data = action.response_data;
    state.onupdate.response_code = action.response_code;
  
  } else if (action.type === USER_ROLE_ONCLEAR) {
    state.user_id = 0;
    state.user_login = "";
    state.user_role = "";
    state.is_active = "";
    state.onupdate.response_data = {};
    state.onupdate.response_code = 0;
  }

  return state;
}

export const UserRoleUserIdOnchangeActionCreator = (user_id) => {
  return {
    type: USER_ROLE_USER_ID_ONCHANGE, 
    user_id: user_id, 
  }
}

export const UserRoleUserRoleOnchangeActionCreator = (user_role) => {
  return {
    type: USER_ROLE_USER_ROLE_ONCHANGE, 
    user_role: user_role, 
  }
}

export const UserRoleIsActiveOnchangeActionCreator = (is_active) => {
  return {
    type: USER_ROLE_IS_ACTIVE_ONCHANGE, 
    is_active: is_active, 
  }
}

export const UserRoleOnselectActionCreator = (response_data, response_code) => {
  return {
    type: USER_ROLE_ONSELECT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const UserRoleOnupdateActionCreator = (response_data, response_code) => {
  return {
    type: USER_ROLE_ONUPDATE,
    response_data: response_data,
    response_code: response_code,
  }
}

export const UserRoleOnclearActionCreator = () => {
  return {
    type: USER_ROLE_ONCLEAR,
  }
}

export default UserRoleReducer;
