import { cookies_get, cookies_set } from "../helpers/cookies_helper";
import config from "../config";

const USER_LIST_OFFSET_ONCHANGE = "USER_LIST_OFFSET_ONCHANGE";
const USER_LIST_LIMIT_ONCHANGE = "USER_LIST_LIMIT_ONCHANGE";
const USER_LIST_ORDER_ONCHANGE = "USER_LIST_ORDER_ONCHANGE";
const USER_LIST_ONSELECT = "USER_LIST_ONSELECT";
const USER_LIST_ONCLEAR = "USER_LIST_ONCLEAR";

const USER_FILTER_FULL_NAME_ONCHANGE = "USER_FILTER_FULL_NAME_ONCHANGE";
const USER_FILTER_USER_ROLE_ONCHANGE = "USER_FILTER_USER_ROLE_ONCHANGE";
const USER_FILTER_IS_ACTIVE_ONCHANGE = "USER_FILTER_IS_ACTIVE_ONCHANGE";
const USER_FILTER_ONRESET = "USER_LIST_ONRESET";

const initial = {
  order_by: config.default_users_order_by,
  order: config.default_users_order,
  offset: 0,
  limit: config.default_users_limit,
  onselect: {
    response_data: {},
    response_code: 0,
  },
  filter: {
    full_name: "",
    user_role: "",
    is_active: "",
  }
};

const order_by = cookies_get("users_order_by");
if (config.allowed_users_order_by.includes(order_by)) {
  initial.order_by = order_by;
}
cookies_set("users_order_by", initial.order_by);

const order = cookies_get("users_order");
if (config.allowed_users_order.includes(order)) {
  initial.order = order;
}
cookies_set("users_order", initial.order);

const limit = cookies_get("users_limit");
if (config.allowed_users_limit.includes(limit)) {
  initial.limit = limit;
}
cookies_set("users_limit", initial.limit);

initial.offset = parseInt(cookies_get("users_offset")) || 0;
cookies_set("users_offset", initial.offset);

const UserReducer = (state = initial, action) => {

  if (action.type === USER_LIST_LIMIT_ONCHANGE) {
    const limit = parseInt(action.limit) || config.default_users_limit;
    state.limit = config.allowed_users_limit.includes(limit) ? limit : config.default_users_limit;
    cookies_set("users_limit", state.limit);

  } else if (action.type === USER_LIST_OFFSET_ONCHANGE) {
    state.offset = parseInt(action.offset) || 0;
    cookies_set("users_offset", state.offset);

  } else if (action.type === USER_LIST_ORDER_ONCHANGE) {
    const order_by = config.allowed_users_order_by.includes(action.order_by) ? action.order_by : config.default_users_order_by;

    if (state.order_by === order_by) {
      state.order = state.order === "asc" ? "desc" : "asc";
      cookies_set("users_order", state.order);

    } else {
      state.order_by = action.order_by;
      cookies_set("users_order_by", state.order_by);
    }

  } else if (action.type === USER_LIST_ONSELECT) {
    state.onselect.response_data = action.response_data;
    state.onselect.response_code = action.response_code;

  } else if (action.type === USER_LIST_ONCLEAR) {
    state.onselect.response_data = {};
    state.onselect.response_code = 0;
  
  } else if (action.type === USER_FILTER_FULL_NAME_ONCHANGE) {
    state.filter.full_name = action.full_name;

  } else if (action.type === USER_FILTER_USER_ROLE_ONCHANGE) {
    state.filter.user_role = action.user_role;

  } else if (action.type === USER_FILTER_IS_ACTIVE_ONCHANGE) {
    state.filter.is_active = action.is_active;

  } else if (action.type === USER_FILTER_ONRESET) {
    state.filter.full_name = "";
    state.filter.user_role = "";
    state.filter.is_active = "";
  }

  return state;
}

export const UserListOffsetOnchangeActionCreator = (offset) => {
  return {
    type: USER_LIST_OFFSET_ONCHANGE,
    offset: offset, 
  }
}

export const UserListLimitOnchangeActionCreator = (limit) => {
  return {
    type: USER_LIST_LIMIT_ONCHANGE, 
    limit: limit, 
  }
}

export const UserListOrderOnchangeActionCreator = (order_by) => {
  return {
    type: USER_LIST_ORDER_ONCHANGE, 
    order_by: order_by, 
  }
}

export const UserListOnselectActionCreator = (response_data, response_code) => {
  return {
      type: USER_LIST_ONSELECT,
      response_data: response_data,
      response_code: response_code,
    }
}

export const UserListOnclearActionCreator = () => {
  return {
    type: USER_LIST_ONCLEAR,
  }
}

export const UserFilterFullNameOnchangeActionCreator = (full_name) => {
  return {
    type: USER_FILTER_FULL_NAME_ONCHANGE,
    full_name: full_name, 
  }
}

export const UserFilterUserRoleOnchangeActionCreator = (user_role) => {
  return {
    type: USER_FILTER_USER_ROLE_ONCHANGE,
    user_role: user_role, 
  }
}

export const UserFilterIsActiveOnchangeActionCreator = (is_active) => {
  return {
    type: USER_FILTER_IS_ACTIVE_ONCHANGE,
    is_active: is_active, 
  }
}

export const UserFilterOnresetActionCreator = () => {
  return {
    type: USER_FILTER_ONRESET,
  }
}

export default UserReducer;
