import axios from "axios";
import config from "../../config";
import { log } from "../../helpers/log_helper";
import { useNavigate } from "react-router-dom";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { UserSelectUserIdOnchangeActionCreator } from "../../reducers/user_select_reducer";
import {
  UserListOffsetOnchangeActionCreator,
  UserListLimitOnchangeActionCreator,
  UserListOrderOnchangeActionCreator,
  UserListOnselectActionCreator,
  UserListOnclearActionCreator,
  UserFilterFullNameOnchangeActionCreator,
  UserFilterUserRoleOnchangeActionCreator,
  UserFilterIsActiveOnchangeActionCreator,
  UserFilterOnresetActionCreator} from "../../reducers/user_list_reducer";
import UserListComponent from "../../components/user/user_list_component";
import redirect from "../../helpers/redirect_helper";

let users_loading = false;

const UserListMiddleware = (props) => {
  const navigate = useNavigate();

  const UserListOffsetOnchange = (offset) => {
    const action = UserListOffsetOnchangeActionCreator(offset);
    props.store.dispatch(action);
  }

  const UserListLimitOnchange = (limit) => {
    let action = UserListLimitOnchangeActionCreator(limit);
    props.store.dispatch(action);
  }

  const UserListOrderOnchange = (order_by) => {
    const action = UserListOrderOnchangeActionCreator(order_by);
    props.store.dispatch(action);
  }

  const UserListOnselect = () => {
    if (users_loading) { return }
    users_loading = true;
    const log_prefix = "user-list-onselect";

    const params = {
      offset: props.store.getState().user_list.offset, 
      limit: props.store.getState().user_list.limit,
      order_by: props.store.getState().user_list.order_by, 
      order: props.store.getState().user_list.order,
    };

    const full_name = props.store.getState().user_list.filter.full_name;
    if (full_name) {
      params.full_name__ilike = full_name;
    }

    const user_role = props.store.getState().user_list.filter.user_role;
    if (user_role) {
      params.user_role__eq = user_role;
    }

    const is_active = props.store.getState().user_list.filter.is_active;
    if (is_active) {
      params.is_active__eq = is_active;
    }

    axios({
      method: "get",
      url: config.server_host + "users", 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      params: params,

    }).then(response => {
      log.debug(log_prefix, response);

      const action = UserListOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);
      users_loading = false;

    }).catch(e => {
      log.error(log_prefix, e);

      if (e.status === 422) {
        const action = UserListOnselectActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }

      users_loading = false;
    });
  }
  
  const UserListOnclear = () => {
    const action = UserListOnclearActionCreator();
    props.store.dispatch(action);
  }

  const UserFilterFullNameOnchange = (full_name) => {
    const action = UserFilterFullNameOnchangeActionCreator(full_name);
    props.store.dispatch(action);
  }

  const UserFilterUserRoleOnchange = (user_role) => {
    const action = UserFilterUserRoleOnchangeActionCreator(user_role);
    props.store.dispatch(action);
  }

  const UserFilterIsActiveOnchange = (is_active) => {
    const action = UserFilterIsActiveOnchangeActionCreator(is_active);
    props.store.dispatch(action);
  }

  const UserFilterOnreset = () => {
    const action = UserFilterOnresetActionCreator();
    props.store.dispatch(action);
  }

  const UserSelectUserIdOnchange = (user_id) => {
    const action = UserSelectUserIdOnchangeActionCreator(user_id);
    props.store.dispatch(action);
  }

  return (
    <UserListComponent
      dispatch={ props.store.dispatch }
      user_timezone={ props.store.getState().app.user_timezone }
      user_token={ props.store.getState().app.user_token }
      token_payload={ props.store.getState().app.token_payload }

      offset={ props.store.getState().user_list.offset }
      limit={ props.store.getState().user_list.limit }
      order_by={ props.store.getState().user_list.order_by }
      order={ props.store.getState().user_list.order }
      filter={ props.store.getState().user_list.filter }

      response_data={ props.store.getState().user_list.onselect.response_data }
      response_code={ props.store.getState().user_list.onselect.response_code }

      UserListOffsetOnchange={ UserListOffsetOnchange }
      UserListLimitOnchange={ UserListLimitOnchange }
      UserListOrderOnchange={ UserListOrderOnchange }
      UserListOnselect={ UserListOnselect }
      UserListOnclear={ UserListOnclear }

      UserFilterFullNameOnchange={ UserFilterFullNameOnchange }
      UserFilterUserRoleOnchange={ UserFilterUserRoleOnchange }
      UserFilterIsActiveOnchange={ UserFilterIsActiveOnchange }
      UserFilterOnreset={ UserFilterOnreset }
      UserSelectUserIdOnchange={ UserSelectUserIdOnchange }
    />
  );
}
  
export default UserListMiddleware;
