const COLLECTION_UPDATE_COLLECTION_ID_ONCHANGE = "COLLECTION_UPDATE_COLLECTION_ID_ONCHANGE";
const COLLECTION_UPDATE_COLLECTION_NAME_ONCHANGE = "COLLECTION_UPDATE_COLLECTION_NAME_ONCHANGE";
const COLLECTION_UPDATE_COLLECTION_SUMMARY_ONCHANGE = "COLLECTION_UPDATE_COLLECTION_SUMMARY_ONCHANGE";
const COLLECTION_UPDATE_IS_LOCKED_ONCHANGE = "COLLECTION_UPDATE_IS_LOCKED_ONCHANGE";
const COLLECTION_UPDATE_ONSELECT = "COLLECTION_UPDATE_ONSELECT";
const COLLECTION_UPDATE_ONUPDATE = "COLLECTION_UPDATE_ONUPDATE";
const COLLECTION_UPDATE_ONCLEAR = "COLLECTION_UPDATE_ONCLEAR";

const initial = {
  collection_id: 0,
  collection_name: "",
  collection_summary: "",
  is_locked: false,
  onupdate: {
    response_data: {},
    response_code: 0,
  },
};

const CollectionUpdateReducer = (state = initial, action) => {

  if (action.type === COLLECTION_UPDATE_COLLECTION_ID_ONCHANGE) {
    state.collection_id = parseInt(action.collection_id);

  } else if (action.type === COLLECTION_UPDATE_COLLECTION_NAME_ONCHANGE) {
    state.collection_name = action.collection_name;

  } else if (action.type === COLLECTION_UPDATE_COLLECTION_SUMMARY_ONCHANGE) {
    state.collection_summary = action.collection_summary;

  } else if (action.type === COLLECTION_UPDATE_IS_LOCKED_ONCHANGE) {
    state.is_locked = !state.is_locked;

  } else if (action.type === COLLECTION_UPDATE_ONSELECT) {
    state.collection_name = action.response_data.collection_name;
    state.collection_summary = action.response_data.collection_summary ? action.response_data.collection_summary : "";
    state.is_locked = action.response_data.is_locked;

  } else if (action.type === COLLECTION_UPDATE_ONUPDATE) {
    state.onupdate.response_data = action.response_data;
    state.onupdate.response_code = action.response_code;

  } else if (action.type === COLLECTION_UPDATE_ONCLEAR) {
    state.collection_id = 0;
    state.collection_name = "";
    state.collection_summary = "";
    state.is_locked = false;
    state.onupdate.response_data = {};
    state.onupdate.response_code = 0;
  }

  return state;
}

export const CollectionUpdateCollectionIdOnchangeActionCreator = (collection_id) => {
  return {
    type: COLLECTION_UPDATE_COLLECTION_ID_ONCHANGE, 
    collection_id: collection_id, 
  }
}

export const CollectionUpdateCollectionNameOnchangeActionCreator = (collection_name) => {
  return {
    type: COLLECTION_UPDATE_COLLECTION_NAME_ONCHANGE, 
    collection_name: collection_name, 
  }
}

export const CollectionUpdateCollectionSummaryOnchangeActionCreator = (collection_summary) => {
  return {
    type: COLLECTION_UPDATE_COLLECTION_SUMMARY_ONCHANGE,
    collection_summary: collection_summary, 
  }
}

export const CollectionUpdateIsLockedOnchangeActionCreator = () => {
  return {
    type: COLLECTION_UPDATE_IS_LOCKED_ONCHANGE,
  }
}

export const CollectionUpdateOnselectActionCreator = (response_data, response_code) => {
  return {
    type: COLLECTION_UPDATE_ONSELECT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const CollectionUpdateOnupdateActionCreator = (response_data, response_code) => {
  return {
    type: COLLECTION_UPDATE_ONUPDATE,
    response_data: response_data,
    response_code: response_code,
  }
}

export const CollectionUpdateOnclearActionCreator = () => {
  return {
    type: COLLECTION_UPDATE_ONCLEAR,
  }
}

export default CollectionUpdateReducer;
