import {
  DocumentDeleteDocumentIdsOnshiftActionCreator,
  DocumentDeleteOnclearActionCreator } from "../../reducers/document_delete_reducer";
import {
  DocumentListOffsetOnchangeActionCreator,
  DocumentListOnclearActionCreator } from "../../reducers/document_list_reducer";
import DocumentDeleteComponent from "../../components/document/document_delete_component";
import config from "../../config";
import axios from "axios";
import empty from "../../helpers/empty_helper";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import { log } from "../../helpers/log_helper";
import { useNavigate } from "react-router-dom";
import redirect from "../../helpers/redirect_helper";

const DocumentDeleteMiddleware = (props) => {
  const navigate = useNavigate();

  const DocumentDeleteDocumentIdsOnshift = (document_id) => {
    const action = DocumentDeleteDocumentIdsOnshiftActionCreator(document_id);
    props.store.dispatch(action);
  }

  const DocumentDeleteOndelete = () => {
    const offcanvas_id = "offcanvas-document-delete";
    const log_prefix = "document-delete";
    buttons_disable(offcanvas_id);

    const document_id = props.store.getState().document_delete.document_id;
    const document_ids = props.store.getState().document_delete.document_ids;

    let ids_to_delete = document_id ? [document_id] : Array.from(document_ids);
    let ids_in_progress = Array.from(ids_to_delete);

    ids_to_delete.forEach(id => {

      axios({
        method: "delete",
        url: config.server_host + "document/" + id, 
        headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
        params: {},

      }).then(response => {
        log.debug(log_prefix, response);

        ids_in_progress.splice(ids_in_progress.indexOf(id), 1);
        if (document_ids.includes(id)) {
          DocumentDeleteDocumentIdsOnshift(id);
        }

        if (empty(ids_in_progress)) {
          DocumentListOnclear();
          buttons_enable(offcanvas_id);
          offcanvas_hide();
        }
        
      }).catch(e => {
        log.error(log_prefix, e);

        if (e.status === 404) {
            ids_in_progress.splice(ids_in_progress.indexOf(id), 1);
            if (document_ids.includes(id)) {
              DocumentDeleteDocumentIdsOnshift(id);
            }
  
          if (empty(ids_in_progress)) {
            DocumentListOnclear();
            buttons_enable(offcanvas_id);
            offcanvas_hide();
          }
  
        } else {
          redirect(e, navigate);
        }

      });
    });
  }

  const DocumentDeleteOnclear = () => {
    const action = DocumentDeleteOnclearActionCreator();
    props.store.dispatch(action);
  }

  const DocumentListOnclear = () => {
    let action = DocumentListOffsetOnchangeActionCreator(0);
    props.store.dispatch(action);

    action = DocumentListOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <DocumentDeleteComponent
      document_id={ props.store.getState().document_delete.document_id }
      document_ids={ props.store.getState().document_delete.document_ids }

      DocumentDeleteOndelete={ DocumentDeleteOndelete }
      DocumentDeleteOnclear={ DocumentDeleteOnclear }
    />
  );
}
  
export default DocumentDeleteMiddleware;
