const COLLECTION_LOCK_COLLECTION_ID_ONCHANGE = "COLLECTION_LOCK_COLLECTION_ID_ONCHANGE";
const COLLECTION_LOCK_COLLECTION_IDS_ONSHIFT = "COLLECTION_LOCK_COLLECTION_IDS_ONSHIFT";
const COLLECTION_LOCK_IS_LOCKED_ONCHANGE = "COLLECTION_LOCK_IS_LOCKED_ONCHANGE";
const COLLECTION_LOCK_ONCLEAR = "COLLECTION_LOCK_ONCLEAR";

const initial = {
  collection_id: 0,
  collection_ids: [],
  is_locked: false,
};

const CollectionLockReducer = (state = initial, action) => {

  if (action.type === COLLECTION_LOCK_COLLECTION_ID_ONCHANGE) {
    state.collection_id = parseInt(action.collection_id);

  } else if (action.type === COLLECTION_LOCK_COLLECTION_IDS_ONSHIFT) {
    const collection_id = parseInt(action.collection_id);

    if (state.collection_ids.includes(collection_id)) {
      state.collection_ids = state.collection_ids.filter(id => id !== collection_id);

    } else {
      state.collection_ids.push(collection_id);
    }

  } else if (action.type === COLLECTION_LOCK_IS_LOCKED_ONCHANGE) {
    state.is_locked = !state.is_locked;

  } else if (action.type === COLLECTION_LOCK_ONCLEAR) {
    state.collection_id = 0;
  }

  return state;
}

export const CollectionLockCollectionIdOnchangeActionCreator = (collection_id) => {
  return {
    type: COLLECTION_LOCK_COLLECTION_ID_ONCHANGE,
    collection_id: collection_id, 
  }
}

export const CollectionLockCollectionIdsOnshiftActionCreator = (collection_id) => {
  return {
    type: COLLECTION_LOCK_COLLECTION_IDS_ONSHIFT,
    collection_id: collection_id, 
  }
}

export const CollectionLockIsLockedOnchangeActionCreator = () => {
  return {
    type: COLLECTION_LOCK_IS_LOCKED_ONCHANGE, 
  }
}

export const CollectionLockOnclearActionCreator = () => {
  return {
    type: COLLECTION_LOCK_ONCLEAR,
  }
}

export default CollectionLockReducer;
