const offcanvas_hide = () => {
  const elements = document.querySelectorAll(`[id^="offcanvas-"]`);
  elements.forEach(element => element.firstElementChild.childNodes[1].click());
}

const offcanvas_show = (id) => {
  document.getElementById(id).firstElementChild.childNodes[2].click();
}

export { offcanvas_hide, offcanvas_show };
