import empty from "../helpers/empty_helper";

const DatatableComponent = (props) => {
  let all_selected = false;
  let displayed_rows = [];
  if (props.rows) {
    displayed_rows = props.rows.map(row => { return row[0] });
    all_selected = displayed_rows.every(item => props.selected_rows.includes(item)); 
  }

  const select_all = () => {
    if (all_selected) {
      displayed_rows.forEach(id => {
        props.onselect(id);
      })
    } else {
      displayed_rows.forEach(id => {
        if (!props.selected_rows.includes(id)) {
          props.onselect(id);
        }
      });
    }
  }
  
  const columns = props.columns.map((column, index) => {
    return (
      <th key={ index } scope="col">
        { column.order_by ? <span onClick={ props.order_onchange } data-order_by={ column.order_by } className="link-primary me-1" role="button">{ column.name }</span> : <span>{ column.name }</span> }
        { column.order_by === props.order_by && (props.order === "asc" ? <i className="bi bi-arrow-down"></i> : <i className="bi bi-arrow-up"></i>) }
      </th>
    )
  });

  const rows = (props.rows) ? props.rows.map((row, rowIndex) => {
    return (
      <tr key={ rowIndex } className={ props.selected_rows.includes(row[0]) ? "table-active" : "" }>
        <td className={ (!props.can_select ? " d-none" : "") }>
          <input className="form-check-input" type="checkbox" checked={ props.selected_rows.includes(row[0]) } onChange={ event => { props.onselect(row[0]) } } />
        </td>
        { row.map((cell, cellIndex) => {
          return <td key={ cellIndex }>{ cell }</td>
        })}
      </tr>
    )
  }) : Array.from({ length: props.limit }, (_, rowIndex) => (
    <tr key={rowIndex}>
      {Array.from({ length: props.columns.length + (props.can_select ? 1 : 0) }).map((_, cellIndex) => (
        <td key={cellIndex}>
          <span className="placeholder placeholder-lg col-8"></span>
        </td>
      ))}
    </tr>
  ));

  return (<>

    <table className="table table-striped table-borderless mb-4">
      <thead>
        <tr>
          <th scope="col" className={ (!props.can_select ? " d-none" : "") }>
            <input className="form-check-input" type="checkbox" id="checkboxNoLabel" value="" onChange={ select_all } checked={ all_selected } />
          </th>
          { columns }
        </tr>
      </thead>
      <tbody>
        { rows }
      </tbody>
    </table>

  </>);
}

export default DatatableComponent;
