import config from "../config";
import { cookies_get, cookies_set } from "../helpers/cookies_helper";

const USER_UPDATE_FIRST_NAME_ONCHANGE = "USER_UPDATE_FIRST_NAME_ONCHANGE";
const USER_UPDATE_LAST_NAME_ONCHANGE = "USER_UPDATE_LAST_NAME_ONCHANGE";
const USER_UPDATE_USER_CONTACTS_ONCHANGE = "USER_UPDATE_USER_CONTACTS_ONCHANGE";
const USER_UPDATE_USER_CAPTION_ONCHANGE = "USER_UPDATE_USER_CAPTION_ONCHANGE";
const USER_UPDATE_FILES_ONCHANGE = "USER_UPDATE_FILES_ONCHANGE";
const USER_UPDATE_ONSELECT = "USER_UPDATE_ONSELECT";
const USER_UPDATE_ONUPDATE = "USER_UPDATE_ONUPDATE";
const USER_UPDATE_ONCLEAR = "USER_UPDATE_ONCLEAR";

const initial = {
  user_id: 0,
  user_login: "",
  user_role: "",
  first_name: "",
  last_name: "",
  user_contacts: "",
  user_caption: "",
  userpic_url: "",
  files: [],
  onupdate: {
    response_data: {},
    response_code: 0,
  },
};

const UserUpdateReducer = (state = initial, action) => {
  
if (action.type === USER_UPDATE_FIRST_NAME_ONCHANGE) {
  state.first_name = action.first_name;
  
} else if (action.type === USER_UPDATE_LAST_NAME_ONCHANGE) {
  state.last_name = action.last_name;
  
} else if (action.type === USER_UPDATE_USER_CONTACTS_ONCHANGE) {
  state.user_contacts = action.user_contacts;
  
} else if (action.type === USER_UPDATE_USER_CAPTION_ONCHANGE) {
  state.user_caption = action.user_caption;

} else if (action.type === USER_UPDATE_FILES_ONCHANGE) {
  state.files = action.files;

  } else if (action.type === USER_UPDATE_ONSELECT) {
    state.user_id = action.response_data.id;
    state.user_login = action.response_data.user_login;
    state.user_role = action.response_data.user_role;
    state.first_name = action.response_data.first_name;
    state.last_name = action.response_data.last_name;
    state.user_contacts = action.response_data.user_contacts;
    state.user_caption = action.response_data.user_caption;
    state.userpic_url = action.response_data.userpic_url;

  } else if (action.type === USER_UPDATE_ONUPDATE) {
    state.onupdate.response_data = action.response_data;
    state.onupdate.response_code = action.response_code;

  } else if (action.type === USER_UPDATE_ONCLEAR) {
    state.user_id = 0;
    state.user_login = "";
    state.user_role = "";
    state.first_name = "";
    state.last_name = "";
    state.user_contacts = "";
    state.user_caption = "";
    state.userpic_url = "";
   
    state.onupdate.response_data = {};
    state.onupdate.response_code = 0;
  }

  return state;
}

export const UserUpdateFirstNameOnchangeActionCreator = (first_name) => {
  return {
    type: USER_UPDATE_FIRST_NAME_ONCHANGE,
    first_name: first_name,
  }
}

export const UserUpdateLastNameOnchangeActionCreator = (last_name) => {
  return {
    type: USER_UPDATE_LAST_NAME_ONCHANGE,
    last_name: last_name,
  }
}

export const UserUpdateUserContactsOnchangeActionCreator = (user_contacts) => {
  return {
    type: USER_UPDATE_USER_CONTACTS_ONCHANGE,
    user_contacts: user_contacts,
  }
}

export const UserUpdateUserCaptionOnchangeActionCreator = (user_caption) => {
  return {
    type: USER_UPDATE_USER_CAPTION_ONCHANGE,
    user_caption: user_caption,
  }
}

export const UserUpdateFilesOnchangeActionCreator = (files) => {
  return {
    type: USER_UPDATE_FILES_ONCHANGE,
    files: files,
  }
}

export const UserUpdateOnselectActionCreator = (response_data, response_code) => {
  return {
    type: USER_UPDATE_ONSELECT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const UserUpdateOnupdateActionCreator = (response_data, response_code) => {
  return {
    type: USER_UPDATE_ONUPDATE,
    response_data: response_data,
    response_code: response_code,
  }
}

export const UserUpdateOnclearActionCreator = () => {
  return {
    type: USER_UPDATE_ONCLEAR,
  }
}

export default UserUpdateReducer;
