const COMMENT_DELETE_COMMENT_ID_ONCHANGE = "COMMENT_DELETE_COMMENT_ID_ONCHANGE";
const COMMENT_DELETE_ONDELETE = "COMMENT_DELETE_ONDELETE";
const COMMENT_DELETE_ONCLEAR = "COMMENT_DELETE_ONCLEAR";

const initial = {
  comment_id: 0,
  ondelete: {
    response_data: {},
    response_code: 0,
  },
};

const CommentDeleteReducer = (state = initial, action) => {

  if (action.type === COMMENT_DELETE_COMMENT_ID_ONCHANGE) {
    state.comment_id = action.comment_id;

  } else if (action.type === COMMENT_DELETE_ONDELETE) {
    state.ondelete.response_data = action.response_data;
    state.ondelete.response_code = action.response_code;

  } else if (action.type === COMMENT_DELETE_ONCLEAR) {
    state.comment_id = 0;
  }

  return state;
}

export const CommentDeleteCommentIdOnchangeActionCreator = (comment_id) => {
  return {
    type: COMMENT_DELETE_COMMENT_ID_ONCHANGE,
    comment_id: comment_id, 
  }
}

export const CommentDeleteOndeleteActionCreator = (response_data, response_code) => {
  return {
    type: COMMENT_DELETE_ONDELETE,
    response_data: response_data,
    response_code: response_code,
  }
}

export const CommentDeleteOnclearActionCreator = () => {
  return {
    type: COMMENT_DELETE_ONCLEAR,
  }
}

export default CommentDeleteReducer;
