import UserAdjustmentsComponent from '../../components/user/user_adjustments_component';

const UserAdjustmentsMiddleware = (props) => {

  return (
    <UserAdjustmentsComponent
      user_timezone={ props.store.getState().app.user_timezone }
      user_language={ props.store.getState().app.user_language }
      user_theme={ props.store.getState().app.user_theme }

      AppTimezoneOnchange={ props.AppTimezoneOnchange }
      AppLanguageOnchange={ props.AppLanguageOnchange }
      AppThemeOnchange={ props.AppThemeOnchange }
    />
  );
}
  
export default UserAdjustmentsMiddleware;
