const buttons_disable = (offcanvas) => {
  const buttons = document.getElementById(offcanvas).querySelectorAll(".btn");
  buttons.forEach(element => element.setAttribute("disabled", true));
}

const buttons_enable = (offcanvas) => {
  const buttons = document.getElementById(offcanvas).querySelectorAll(".btn");
  buttons.forEach(element => element.removeAttribute("disabled"));
}

export { buttons_enable, buttons_disable };
