import { useTranslation } from "react-i18next";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { useEffect } from "react";
import config from "../../config";
import DatalistMiddleware from "../../middleware/datalist_middleware";
import empty from "../../helpers/empty_helper";
import { DocumentMoveCollectionDatalistOnselectActionCreator } from "../../reducers/document_move_reducer";

const DocumentMoveComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-document-move";

  useEffect(() => {
    const offcanvas = document.getElementById(offcanvas_id);

    offcanvas.addEventListener("hide.bs.offcanvas", () => {
      setTimeout(() => { props.DocumentMoveOnclear() },
      config.offcanvas_refresh_delay);
    });
  }, []);

  const DocumentMoveOnupdate = (event) => {
    event.preventDefault();
    props.DocumentMoveOnupdate();
  }

  return (
    <div id="offcanvas-document-move" className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title">{ t("offcanvas-document-move-title") }</h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href="#offcanvas-document-move"></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

          <div className="form-text">
            { t("document-selected") }: { props.document_id ? 1 : props.document_ids.length }
          </div>

          <div className="form-text mt-4">
            { t("document-move-collection-text") }
          </div>

          <div className="form-text mt-2">
            <DatalistMiddleware
              dispatch={ props.dispatch }
              user_token={ props.user_token }
              // datalist data
              datalist_name="document-move-collection-datalist"
              datalist_placeholder={ t("filter-collection-name") }
              datalist_value={ props.collection_datalist.collection_name }
              datalist_id={ props.collection_datalist.collection_id }
              response_data={ props.collection_datalist.response_data }
              response_code={ props.collection_datalist.response_code }
              datalist_options={ !empty(props.collection_datalist.response_data) ? props.collection_datalist.response_data.collections.map(el => { return { id: el.id, value: el.collection_name } }) : [] }
              // request
              request_url={ config.server_host + "collections" }
              request_param="collection_name__ilike"
              request_order_by="collection_name"
              request_order="asc"
              // datalist actions
              datalist_onchange={ props.DocumentMoveCollectionDatalistCollectionNameOnchange }
              datalist_onload_action_creator={ DocumentMoveCollectionDatalistOnselectActionCreator }
              onupdate={ () => {} }
            />
          </div>

          <button onClick={ offcanvas_hide } className="btn btn-outline-primary mt-4" type="button">
            <i className="bi bi-arrow-left"></i> { t("button-cancel") }
          </button>

          <button onClick={ DocumentMoveOnupdate } className="btn btn-primary mt-4 ms-2" type="button" >
            <i className="bi bi-arrow-left-right"></i> { t("button-move") }
          </button>

        </form>
      </div>
    </div>
  );
}

export default DocumentMoveComponent;
