import { useTranslation } from "react-i18next";
import { useEffect } from "react";
import config from "../../config";
import datetime from "../../helpers/datetime_helper";
import { can_edit, can_admin } from "../../helpers/role_helper"
import { offcanvas_hide, offcanvas_show } from "../../helpers/offcanvas_helper";
import FormTextComponent from "../forms/form_text_component";
import FormLinkComponent from "../forms/form_link_component";

const PartnerSelectComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-partner-select";

  useEffect(() => {
    document.getElementById(offcanvas_id).addEventListener("show.bs.offcanvas", () => {
      props.PartnerSelectOnselect();
    });

    document.getElementById(offcanvas_id).addEventListener("hide.bs.offcanvas", () => {
      setTimeout(
        () => { props.PartnerSelectOnclear() },
        config.offcanvas_latency);
    });
  }, []);

  const PartnerUpdatePartnerIdOnchange = (event) => {
    event.preventDefault();
    props.PartnerUpdatePartnerIdOnchange(props.partner_id);

    offcanvas_hide();
    offcanvas_show("offcanvas-partner-update");
  }

  const PartnerDeletePartnerIdOnchange = (event) => {
    event.preventDefault();
    props.PartnerDeletePartnerIdOnchange(props.partner_id);

    offcanvas_hide();
    offcanvas_show("offcanvas-partner-delete");
  }

  const UserSelectUserIdOnchange = (event) => {
    event.preventDefault();
    const user_id = event.target.dataset.id;
    props.UserSelectUserIdOnchange(user_id);

    offcanvas_hide();
    offcanvas_show("offcanvas-user-select");
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title d-flex">
          { t("offcanvas-partner-select-title") }

          <div className="dropdown ms-2">
            <a href="#" className="link link-primary dropdown-toggle no-after" type="button" data-bs-toggle="dropdown">
              <i className="bi bi-list"></i>
            </a>
            <ul className="dropdown-menu">
              <li><a className="dropdown-item" href="#" onClick={ offcanvas_hide }>{ t("button-cancel") }</a></li>
              <li><a className={ "dropdown-item" + (can_edit(props.user_role) ? "" : " d-none") } href="#" onClick={ PartnerUpdatePartnerIdOnchange }>{ t("button-edit") }</a></li>
              <li><a className={ "dropdown-item" + (can_admin(props.user_role) ? "" : " d-none") } href="#" onClick={ PartnerDeletePartnerIdOnchange }>{ t("button-delete") }</a></li>
            </ul>
          </div>

        </h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

          <FormTextComponent
              mt={ 0 }
              response_code={ props.response_code }
              text={ t("id") }
              value={ props.response_data.id }
            />

            <FormTextComponent
              mt={ 4 }
              response_code={ props.response_code }
              text={ t("partner-name") }
              value={ props.response_data.partner_name }
            />

          { props.response_code === 200 && props.response_data.partnerpic_url && <>
            <div className="form-text d-flex justify-content-center align-items-center mt-4">
              <img src={ props.response_data.partnerpic_url } className="card-img-top" style={{ width: "auto", height: "auto" }} alt={ props.response_data.partner_name } />
            </div>
          </> }

          <FormTextComponent
            mt={ 4 }
            response_code={ props.response_code }
            text={ t("partner-type") }
            value={ props.response_data.partner_type }
          />

          <FormTextComponent
            mt={ 4 }
            response_code={ props.response_code }
            text={ t("partner-region") }
            value={ props.response_data.partner_region }
          />

          <FormTextComponent
            mt={ 4 }
            response_code={ props.response_code }
            text={ t("partner-website") }
            value={ props.response_data.partner_website }
          />

          <FormTextComponent
            mt={ 4 }
            response_code={ props.response_code }
            text={ t("partner-contacts") }
            value={ props.response_data.partner_contacts }
          />

          <FormTextComponent
            mt={ 4 }
            response_code={ props.response_code }
            text={ t("partner-summary") }
            value={ props.response_data.partner_summary }
          />

          <FormLinkComponent
            mt={ 4 }
            response_code={ props.response_code }
            text={ t("partner-user") }
            value={ props.response_data.user_name }
            id={ props.response_data.user_id }
            onclick={ UserSelectUserIdOnchange }
          />

          <FormTextComponent
            mt={ 4 }
            response_code={ props.response_code }
            text={ t("created-date") }
            value={ datetime(props.response_data.created_date, props.user_timezone, t) }
          />

          <FormTextComponent
            mt={ 4 }
            response_code={ props.response_code }
            text={ t("updated-date") }
            value={ datetime(props.response_data.updated_date, props.user_timezone, t) }
          />

        </form>
      </div>
    </div>
  );
}

export default PartnerSelectComponent;
