import React from "react"
import empty from "../../helpers/empty_helper";

const FormLinkComponent = (props) => {
  return (
    <>
      <div className={ "form-text mt-" + props.mt + ((props.response_code === 200 && !empty(props.value) ? "" : " d-none")) }>
        { props.text }
      </div>
      <div>
        { props.response_code === 200 ? <a href="#" className="link-primary text-decoration-none" data-id={ props.id } onClick={ props.onclick }>{ props.value }</a> : <span className="placeholder placeholder-lg col-8"></span> }
      </div>
    </>
  )
}

export default FormLinkComponent;
