import { useTranslation } from 'react-i18next';
import empty from '../helpers/empty_helper';
import React from 'react';
import config from '../config';

let timer;

const DatalistComponent = (props) => {
  const { t } = useTranslation();

  // loading on focus
  const InitialDatalistLoad = () => {
    if (!empty(props.user_token)) {
      props.DatalistOnload();
    }
  }

  // change datalist value
  const DatalistValueOnchange = (event) => {
    const value = event.target.value;
    props.DatalistValueOnchange(value);
    TimerStart();
  }

  // load datalist
  const DatalistOnload = () => {
    props.DatalistOnload(true);
  }

  // init loading on delay
  const TimerStart = () => {
    clearTimeout(timer);
    timer = setTimeout(() => {
      DatalistOnload()
    }, config.input_latency);
  }

  const datalist_options = !empty(props.datalist_options) ? props.datalist_options.map(el => {
    return <option key={ el.id } data-id={ el.id } value={ el.value } />
  }) : [];

  return (
    <div className="form-floating">
      <input value={ props.datalist_value } type="search" onFocus={ InitialDatalistLoad } onChange={ DatalistValueOnchange } className={ "form-control" + (props.datalist_id ? " border-primary" : "") } list={ props.datalist_name } placeholder={ props.datalist_placeholder } autoComplete="off" />
      <label>{ props.datalist_placeholder }</label>
      <datalist id={ props.datalist_name }>
        { datalist_options }
      </datalist>
    </div>
  );
}

export default DatalistComponent;
