const DOCUMENT_INSERT_FILES_ONCHANGE = "DOCUMENT_INSERT_FILES_ONCHANGE";
const DOCUMENT_INSERT_FILES_ELAPSED_ONCHANGE = "DOCUMENT_INSERT_FILES_ELAPSED_ONCHANGE";
const DOCUMENT_INSERT_COLLECTION_DATALIST_COLLECTION_NAME_ONCHANGE = "DOCUMENT_INSERT_COLLECTION_DATALIST_COLLECTION_NAME_ONCHANGE";
const DOCUMENT_INSERT_COLLECTION_DATALIST_COLLECTION_ID_ONCHANGE = "DOCUMENT_INSERT_COLLECTION_DATALIST_COLLECTION_ID_ONCHANGE";
const DOCUMENT_INSERT_COLLECTION_DATALIST_ONLOAD = "DOCUMENT_INSERT_COLLECTION_DATALIST_ONLOAD";
const DOCUMENT_INSERT_ONINSERT = "DOCUMENT_INSERT_ONINSERT";
const DOCUMENT_INSERT_ONCLEAR = "DOCUMENT_INSERT_ONCLEAR";

const initial = {
  files: [],
  files_elapsed: false,
  collection_datalist: {
    collection_name: "",
    collection_id: 0,
    response_data: {},
    response_code: 0,
  },
  oninsert: {
    response_data: {},
    response_code: 0,
  }
};

const DocumentInsertReducer = (state = initial, action) => {

  if (action.type === DOCUMENT_INSERT_FILES_ONCHANGE) {
    state.files = action.files;

  } else if (action.type === DOCUMENT_INSERT_FILES_ELAPSED_ONCHANGE) {
    state.files_elapsed = action.files_elapsed;

  } else if (action.type === DOCUMENT_INSERT_COLLECTION_DATALIST_COLLECTION_NAME_ONCHANGE) {
    state.collection_datalist.collection_name = action.collection_name;

  } else if (action.type === DOCUMENT_INSERT_COLLECTION_DATALIST_COLLECTION_ID_ONCHANGE) {
    state.collection_datalist.collection_id = action.collection_id;
    state.collection_datalist.collection_name = action.collection_name;

  } else if (action.type === DOCUMENT_INSERT_COLLECTION_DATALIST_ONLOAD) {
    state.collection_datalist.response_data = action.response_data;
    state.collection_datalist.response_code = action.response_code;

    const collection = Array.prototype.find.call(action.response_data.collections, el => {
      return el.collection_name.toLocaleLowerCase() === state.collection_datalist.collection_name.toLocaleLowerCase();
    });
    state.collection_datalist.collection_id = collection ? collection.id : 0;


  } else if (action.type === DOCUMENT_INSERT_ONINSERT) {
    state.oninsert.response_data = action.response_data;
    state.oninsert.response_code = action.response_code;

  } else if (action.type === DOCUMENT_INSERT_ONCLEAR) {
    state.files = [];

    state.collection_datalist.collection_name = "";
    state.collection_datalist.collection_id = 0;
    state.collection_datalist.response_data = {};
    state.collection_datalist.response_code = 0;

    state.oninsert.response_data = {};
    state.oninsert.response_code = 0;
  }

  return state;
}

export const DocumentInsertFilesOnchangeActionCreator = (files) => {
  return {
    type: DOCUMENT_INSERT_FILES_ONCHANGE, 
    files: files, 
  }
}

export const DocumentInsertFilesElapsedOnchangeActionCreator = (files_elapsed) => {
  return {
    type: DOCUMENT_INSERT_FILES_ELAPSED_ONCHANGE, 
    files_elapsed: files_elapsed, 
  }
}

export const DocumentInsertCollectionDatalistCollectionNameOnchangeActionCreator = (collection_name) => {
  return {
    type: DOCUMENT_INSERT_COLLECTION_DATALIST_COLLECTION_NAME_ONCHANGE, 
    collection_name: collection_name, 
  }
}

export const DocumentInsertCollectionDatalistCollectionIdOnchangeActionCreator = (collection_id, collection_name) => {
  return {
    type: DOCUMENT_INSERT_COLLECTION_DATALIST_COLLECTION_ID_ONCHANGE, 
    collection_id: collection_id, 
    collection_name: collection_name,
  }
}

export const DocumentInsertCollectionDatalistOnloadActionCreator = (response_data, response_code) => {
  return {
      type: DOCUMENT_INSERT_COLLECTION_DATALIST_ONLOAD,
      response_data: response_data,
      response_code: response_code,
    }
}


export const DocumentInsertOninsertActionCreator = (response_data, response_code) => {
  return {
    type: DOCUMENT_INSERT_ONINSERT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const DocumentInsertOnclearActionCreator = () => {
  return {
    type: DOCUMENT_INSERT_ONCLEAR,
  }
}

export default DocumentInsertReducer;
