import axios from "axios";
import config from "../config";
import { log } from "../helpers/log_helper";
import { 
  TelemetryOnselectActionCreator,
  TelemetryOnclearActionCreator } from "../reducers/telemetry_select_reducer";
import TelemetrySelectComponent from "../components/telemetry_select_component";
import { useNavigate } from "react-router-dom";
import redirect from "../helpers/redirect_helper";

let is_loading = false;

const TelemetryMiddleware = (props) => {
  const navigate = useNavigate();

  const TelemetryOnselect = () => {
    if (is_loading) { return }
    is_loading = true;
    const log_prefix = "telemetry-select-onselect";
    
    axios({
      method: "get",
      url: config.server_host + "telemetry", 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      params: {},

    }).then(response => {
      log.debug(log_prefix, response);

      const action = TelemetryOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);
      is_loading = false;

    }).catch(e => {
      log.error(log_prefix, e);
      is_loading = false;
      redirect(e, navigate);
    });
  }

  const TelemetryOnclear = () => {
    const action = TelemetryOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <TelemetrySelectComponent
      dispatch={ props.store.dispatch }
      user_timezone={ props.store.getState().app.user_timezone }
      user_token={ props.store.getState().app.user_token }
      token_payload={ props.store.getState().app.token_payload }

      response_data={ props.store.getState().telemetry_select.onselect.response_data }
      response_code={ props.store.getState().telemetry_select.onselect.response_code }

      TelemetryOnselect={ TelemetryOnselect }
      TelemetryOnclear={ TelemetryOnclear }
    />
  );
}
  
export default TelemetryMiddleware;