const USER_LOGIN_USER_LOGIN_ONCHANGE = "USER_LOGIN_USER_LOGIN_ONCHANGE";
const USER_LOGIN_USER_PASSWORD_ONCHANGE = "USER_LOGIN_USER_PASSWORD_ONCHANGE";
const USER_LOGIN_ONSUBMIT = "USER_LOGIN_ONSUBMIT";
const USER_LOGIN_ONCLEAR = "USER_LOGIN_ONCLEAR";

const initial = {
  user_login: "",
  user_password: "",
  onlogin: {
    response_data: {},
    response_code: 0,
  },
};

const UserLoginReducer = (state = initial, action) => {

  if (action.type === USER_LOGIN_USER_LOGIN_ONCHANGE) {
    state.user_login = action.user_login;
  
  } else if (action.type === USER_LOGIN_USER_PASSWORD_ONCHANGE) {
    state.user_password = action.user_password;

  } else if (action.type === USER_LOGIN_ONSUBMIT) {
    state.onlogin.response_data = action.response_data;
    state.onloginresponse_code = action.response_code;

  } else if (action.type === USER_LOGIN_ONCLEAR) {
    state.user_login = "";
    state.user_password = "";
    state.onlogin.response_data = {};
    state.onlogin.response_code = 0;
  }

  return state;
}

export const UserLoginUserLoginOnchangeActionCreator = (user_login) => {
  return {
    type: USER_LOGIN_USER_LOGIN_ONCHANGE,
    user_login: user_login,
  }
}

export const UserLoginUserPasswordOnchangeActionCreator = (user_password) => {
  return {
    type: USER_LOGIN_USER_PASSWORD_ONCHANGE,
    user_password: user_password,
  }
}

export const UserLoginOnsubmitActionCreator = (response_data, response_code) => {
  return {
    type: USER_LOGIN_ONSUBMIT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const UserLoginOnclearActionCreator = () => {
  return {
    type: USER_LOGIN_ONCLEAR,
  }
}

export default UserLoginReducer;
