import axios from "axios";
import config from "../../config";
import { log } from "../../helpers/log_helper";
import { useNavigate } from "react-router-dom";
import { DocumentSelectDocumentIdOnchangeActionCreator } from "../../reducers/document_select_reducer";
import { CollectionSelectCollectionIdOnchangeActionCreator } from "../../reducers/collection_select_reducer";
import {
  DocumentListOffsetOnchangeActionCreator,
  DocumentListLimitOnchangeActionCreator,
  DocumentListOrderOnchangeActionCreator,
  DocumentListViewOnchangeActionCreator,
  DocumentListOnselectActionCreator,
  DocumentListOnclearActionCreator,
  DocumentFilterDocumentFilenameOnchangeActionCreator,
  DocumentFilterDocumentMimetypeOnchangeActionCreator,
  DocumentFilterUserDatalistUserNameOnchangeActionCreator,
  DocumentFilterCollectionDatalistCollectionNameOnchangeActionCreator,
  DocumentFilterPartnerDatalistPartnerNameOnchangeActionCreator,
  DocumentFilterOnresetActionCreator } from "../../reducers/document_list_reducer";
import { DocumentDeleteDocumentIdsOnshiftActionCreator } from "../../reducers/document_delete_reducer";
import { DocumentMoveDocumentIdsOnshiftActionCreator } from "../../reducers/document_move_reducer";
import DocumentListComponent from "../../components/document/document_list_component";
import redirect from "../../helpers/redirect_helper";
import empty from "../../helpers/empty_helper";

let documents_loading = false;

const DocumentListMiddleware = (props) => {
  const navigate = useNavigate();

  const DocumentSelectDocumentIdOnchange = (document_id) => {
    const action = DocumentSelectDocumentIdOnchangeActionCreator(document_id);
    props.store.dispatch(action);
  }

  const CollectionSelectCollectionIdOnchange = (collection_id) => {
    const action = CollectionSelectCollectionIdOnchangeActionCreator(collection_id);
    props.store.dispatch(action);
  }

  const DocumentListOffsetOnchange = (offset) => {
    const action = DocumentListOffsetOnchangeActionCreator(offset);
    props.store.dispatch(action);
  }

  const DocumentListLimitOnchange = (limit) => {
    let action = DocumentListLimitOnchangeActionCreator(limit);
    props.store.dispatch(action);
  }

  const DocumentListOrderOnchange = (order_by) => {
    const action = DocumentListOrderOnchangeActionCreator(order_by);
    props.store.dispatch(action);
  }

  const DocumentListViewOnchange = (view) => {
    const action = DocumentListViewOnchangeActionCreator(view);
    props.store.dispatch(action);
  }

  const DocumentListOnselect = () => {
    if (documents_loading) { return }
    documents_loading = true;
    const log_prefix = "document-list-onselect";

    const params = {
      offset: props.store.getState().document_list.offset, 
      limit: props.store.getState().document_list.limit,
      order_by: props.store.getState().document_list.order_by, 
      order: props.store.getState().document_list.order,
    };

    const document_filename = props.store.getState().document_list.filter.document_filename;
    if (!empty(document_filename) && document_filename.startsWith("#")) {
      params.tag_value__eq = document_filename.substring(1);

    } else if (!empty(document_filename)) {
      params.document_filename__ilike = document_filename;
    }

    const document_mimetype = props.store.getState().document_list.filter.document_mimetype;
    if (document_mimetype) {
      params.document_mimetype__ilike = document_mimetype;
    }

    const user_id = props.store.getState().document_list.filter.user_datalist.user_id;
    if (user_id) {
      params.user_id__eq = user_id;
    }

    const collection_id = props.store.getState().document_list.filter.collection_datalist.collection_id;
    if (collection_id) {
      params.collection_id__eq = collection_id;
    }

    const partner_id = props.store.getState().document_list.filter.partner_datalist.partner_id;
    if (partner_id) {
      params.partner_id__eq = partner_id;
    }

    axios({
      method: "get",
      url: config.server_host + "documents", 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token},
      params: params,

    }).then(response => {
      log.debug(log_prefix, response);

      const action = DocumentListOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);
      documents_loading = false;

    }).catch(e => {
      log.error(log_prefix, e);

      if (e.status === 422) {
        const action = DocumentListOnselectActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }

      documents_loading = false;
    });
  }

  const DocumentListOnclear = () => {
    const action = DocumentListOnclearActionCreator();
    props.store.dispatch(action);
  }

  const DocumentFilterDocumentFilenameOnchange = (document_filename) => {
    const action = DocumentFilterDocumentFilenameOnchangeActionCreator(document_filename);
    props.store.dispatch(action);
  }

  const DocumentFilterDocumentMimetypeOnchange = (document_mimetype) => {
    const action = DocumentFilterDocumentMimetypeOnchangeActionCreator(document_mimetype);
    props.store.dispatch(action);
  }

  const DocumentFilterUserDatalistUserNameOnchange = (user_name) => {
    const action = DocumentFilterUserDatalistUserNameOnchangeActionCreator(user_name);
    props.store.dispatch(action);
  }

  const DocumentFilterCollectionDatalistCollectionNameOnchange = (collection_name) => {
    const action = DocumentFilterCollectionDatalistCollectionNameOnchangeActionCreator(collection_name);
    props.store.dispatch(action);
  }

  const DocumentFilterPartnerDatalistPartnerNameOnchange = (partner_name) => {
    const action = DocumentFilterPartnerDatalistPartnerNameOnchangeActionCreator(partner_name);
    props.store.dispatch(action);
  }

  const DocumentFilterOnreset = () => {
    const action = DocumentFilterOnresetActionCreator();
    props.store.dispatch(action);
  }

  const DocumentDeleteDocumentIdsOnshift = (document_id) => {
    let action = DocumentDeleteDocumentIdsOnshiftActionCreator(document_id);
    props.store.dispatch(action);
  }

  const DocumentMoveDocumentIdsOnshift = (document_id) => {
    let action = DocumentMoveDocumentIdsOnshiftActionCreator(document_id);
    props.store.dispatch(action);
  }

  const checked_ids = props.store.getState().document_delete.document_ids.filter(
    id => props.store.getState().document_move.document_ids.includes(id));

  return (
    <DocumentListComponent
      dispatch={ props.store.dispatch }
      user_timezone={ props.store.getState().app.user_timezone }
      user_token={ props.store.getState().app.user_token }
      token_payload={ props.store.getState().app.token_payload }

      offset={ props.store.getState().document_list.offset }
      limit={ props.store.getState().document_list.limit }
      order_by={ props.store.getState().document_list.order_by }
      order={ props.store.getState().document_list.order }
      view={ props.store.getState().document_list.view }
      filter={ props.store.getState().document_list.filter }
      document_ids={ checked_ids }

      response_data={ props.store.getState().document_list.onselect.response_data }
      response_code={ props.store.getState().document_list.onselect.response_code }


      // Document actions
      DocumentListOffsetOnchange={ DocumentListOffsetOnchange }
      DocumentListLimitOnchange={ DocumentListLimitOnchange }
      DocumentListOrderOnchange={ DocumentListOrderOnchange }
      DocumentListViewOnchange={ DocumentListViewOnchange }
      DocumentListOnselect={ DocumentListOnselect }
      DocumentListOnclear={ DocumentListOnclear }

      DocumentFilterDocumentFilenameOnchange={ DocumentFilterDocumentFilenameOnchange }
      DocumentFilterDocumentMimetypeOnchange={ DocumentFilterDocumentMimetypeOnchange }
      DocumentFilterUserDatalistUserNameOnchange={ DocumentFilterUserDatalistUserNameOnchange }
      DocumentFilterCollectionDatalistCollectionNameOnchange={ DocumentFilterCollectionDatalistCollectionNameOnchange }
      DocumentFilterPartnerDatalistPartnerNameOnchange={ DocumentFilterPartnerDatalistPartnerNameOnchange }
      DocumentFilterOnreset={ DocumentFilterOnreset }

      DocumentSelectDocumentIdOnchange={ DocumentSelectDocumentIdOnchange }
      CollectionSelectCollectionIdOnchange={ CollectionSelectCollectionIdOnchange }

      DocumentDeleteDocumentIdsOnshift={ DocumentDeleteDocumentIdsOnshift }
      DocumentMoveDocumentIdsOnshift={ DocumentMoveDocumentIdsOnshift }
    />
  );
}
  
export default DocumentListMiddleware;
