const USER_SECRET_USER_ID_ONCHANGE = "USER_SECRET_USER_ID_ONCHANGE";
const USER_SECRET_MFA_SECRET_ONCHANGE = "USER_SECRET_MFA_SECRET_ONCHANGE";
const USER_SECRET_MFA_URL_ONCHANGE = "USER_SECRET_MFA_URL_ONCHANGE";
const USER_SECRET_ONCLEAR = "USER_SECRET_ONCLEAR";

const initial = {
  user_id: 0,
  mfa_secret: "",
  mfa_url: "",
};

const UserSecretReducer = (state = initial, action) => {

  if (action.type === USER_SECRET_USER_ID_ONCHANGE) {
    state.user_id = action.user_id;

  } else if (action.type === USER_SECRET_MFA_SECRET_ONCHANGE) {
    state.mfa_secret = action.mfa_secret;

  } else if (action.type === USER_SECRET_MFA_URL_ONCHANGE) {
    state.mfa_url = action.mfa_url;

  } else if (action.type === USER_SECRET_ONCLEAR) {
    state.user_id = 0;
    state.mfa_secret = "";
    state.mfa_url = "";
  }

  return state;
}

export const UserSecretUserIdOnchangeActionCreator = (user_id) => {
  return {
    type: USER_SECRET_USER_ID_ONCHANGE,
    user_id: user_id, 
  }
}

export const UserSecretMfaSecretOnchangeActionCreator = (mfa_secret) => {
  return {
    type: USER_SECRET_MFA_SECRET_ONCHANGE,
    mfa_secret: mfa_secret, 
  }
}

export const UserSecretMfaUrlOnchangeActionCreator = (mfa_url) => {
  return {
    type: USER_SECRET_MFA_URL_ONCHANGE,
    mfa_url: mfa_url, 
  }
}

export const UserSecretOnclearActionCreator = () => {
  return {
    type: USER_SECRET_ONCLEAR,
  }
}

export default UserSecretReducer;
