import { useTranslation } from "react-i18next";
import errors from "../../helpers/errors_helper";
import { useEffect } from "react";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import empty from "../../helpers/empty_helper";
import config from "../../config";

const UserUpdateComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-user-update";

  useEffect(() => {
    const offcanvas = document.getElementById(offcanvas_id);

    offcanvas.addEventListener("shown.bs.offcanvas", () => {
      props.UserUpdateOnselect();
      offcanvas.querySelector(".focused").focus();
    });

    offcanvas.addEventListener("hide.bs.offcanvas", () => {
      setTimeout(
        () => { props.UserUpdateOnclear() },
        config.offcanvas_refresh_delay);
    });
  }, []);

  
  const UserUpdateFirstNameOnchange = (event) => {
    props.UserUpdateFirstNameOnchange(event.target.value);
  }
  
  const UserUpdateLastNameOnchange = (event) => {
    props.UserUpdateLastNameOnchange(event.target.value);
  }
  
  const UserUpdateUserContactsOnchange = (event) => {
    props.UserUpdateUserContactsOnchange(event.target.value);
  }
  
  const UserUpdateUserCaptionOnchange = (event) => {
    props.UserUpdateUserCaptionOnchange(event.target.value);
  }
  
  const UserUpdateFilesOnchange = (event) => {
    props.UserUpdateFilesOnchange(event.target.files);
  }

  if(empty(props.files)) {
    const files = document.getElementById("user-update-files");
    if(files) {
      files.value = "";
    }
  }

  const is_valid = (key) => {
    if (key === "first_name") {
      return props.first_name.length >= 1 && props.first_name.length <= 40;

    } else if (key === "last_name") {
      return props.last_name.length >= 1 && props.last_name.length <= 40;

    } else if (key === "user_contacts") {
      return !props.user_contacts || props.user_contacts.length <= 512;

    } else if (key === "user_caption") {
      return !props.user_caption || props.user_caption.length <= 40;
    }
  }

  const submit_enabled = is_valid("first_name") && is_valid("last_name") && is_valid("user_contacts") && is_valid("user_caption");
  const response_errors = errors(props.response_data);

  const UserUpdateOnupdate = (event) => {
    event.preventDefault();
    if (submit_enabled) {
      props.UserUpdateOnupdate();
    }
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title">{ t("offcanvas-user-update-title") }</h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

          <div className="form-text">
            { t("id") }
          </div>
          <div>
            { props.user_id }
          </div>

          <div className="form-text mt-4">
            { t("user-first-name-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ UserUpdateFirstNameOnchange } value={ props.first_name } type="text" className={ "form-control focused" + ("first_name" in response_errors ? " border-danger glow-danger" : is_valid("first_name") ? " border-primary" : "") } placeholder={ t("first-name") } maxLength="40" />
            <label>{ t("first-name") }</label>
          </div>
          <div className="form-text text-danger">
            { "first_name" in response_errors && t("error_" + response_errors["first_name"]) }
          </div>

          <div className="form-text mt-4">
            { t("user-last-name-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ UserUpdateLastNameOnchange } value={ props.last_name } type="text" className={ "form-control focused" + ("last_name" in response_errors ? " border-danger glow-danger" : is_valid("last_name") ? " border-primary" : "") } placeholder={ t("last-name") } maxLength="40" />
            <label>{ t("last-name") }</label>
          </div>
          <div className="form-text text-danger">
            { "last_name" in response_errors && t("error_" + response_errors["last_name"]) }
          </div>

          { props.userpic_url && <>
            <div className="form-text d-flex justify-content-center align-items-center mt-4">
              <img src={ props.userpic_url } className="card-img-top" style={{ width: "auto", height: "auto" }} alt={ props.first_name + " " + props.last_name } />
            </div>
          </> }

          <div className="form-text mt-4">
            { t("user-files-text") }
          </div>
          <div className="mt-2">
            <input id="user-update-files" className={ "form-control" + (props.files.length > 0 ? " border-primary" : "") } type="file" onInput={ UserUpdateFilesOnchange } files={ props.files } />
          </div>

          <div className="form-text mt-4">
            { t("user-login") }
          </div>
          <div>
            { props.user_login }
          </div>

          <div className="form-text mt-4">
            { t("user-role") }
          </div>
          <div>
            { props.user_role }
          </div>

          <div className="form-text mt-4">
            { t("user-contacts-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ UserUpdateUserContactsOnchange } value={ props.user_contacts } type="text" className={ "form-control focused" + ("user_contacts" in response_errors ? " border-danger glow-danger" : is_valid("user_contacts") ? " border-primary" : "") } placeholder={ t("user-contacts") } maxLength="256" />
            <label>{ t("user-contacts") }</label>
          </div>
          <div className="form-text text-danger">
            { "user_contacts" in response_errors && t("error_" + response_errors["user_contacts"]) }
          </div>

          <div className="form-text mt-4">
            { t("user-caption-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ UserUpdateUserCaptionOnchange } value={ props.user_caption } type="text" className={ "form-control focused" + ("user_caption" in response_errors ? " border-danger glow-danger" : is_valid("user_caption") ? " border-primary" : "") } placeholder={ t("user-caption") } maxLength="40" />
            <label>{ t("user-caption") }</label>
          </div>
          <div className="form-text text-danger">
            { "user_caption" in response_errors && t("error_" + response_errors["user_caption"]) }
          </div>

          <button className="btn btn-outline-primary mt-4" type="button" onClick={ offcanvas_hide }>
            <i className="bi bi-arrow-left"></i> { t("button-cancel") }
          </button>

          <button onClick={ UserUpdateOnupdate } className={"btn btn-primary mt-4 ms-2 " + (!submit_enabled ? "disabled" : "")} type="submit">
            <i className="bi bi-check2"></i> { t("button-submit") }
          </button>

        </form>
      </div>
    </div>
  );
}

export default UserUpdateComponent;
