const USER_REGISTER_USER_LOGIN_ONCHANGE = "USER_REGISTER_USER_LOGIN_ONCHANGE";
const USER_REGISTER_USER_PASSWORD_ONCHANGE = "USER_REGISTER_USER_PASSWORD_ONCHANGE";
const USER_REGISTER_FIRST_NAME_ONCHANGE = "USER_REGISTER_FIRST_NAME_ONCHANGE";
const USER_REGISTER_LAST_NAME_ONCHANGE = "USER_REGISTER_LAST_NAME_ONCHANGE";
const USER_REGISTER_AGREEMENT_ONCLICK = "USER_REGISTER_AGREEMENT_ONCLICK";
const USER_REGISTER_ONSUBMIT = "USER_REGISTER_ONSUBMIT";
const USER_REGISTER_ONCLEAR = "USER_REGISTER_ONCLEAR";

const initial = {
  user_login: "",
  user_password: "",
  first_name: "",
  last_name: "",
  agreement_accepted: false,
  onregister: {
    response_data: {},
    response_code: 0,
  },
};

const UserRegisterReducer = (state = initial, action) => {

  if (action.type === USER_REGISTER_USER_LOGIN_ONCHANGE) {
    state.user_login = action.user_login;

  } else if (action.type === USER_REGISTER_USER_PASSWORD_ONCHANGE) {
    state.user_password = action.user_password;

  } else if (action.type === USER_REGISTER_FIRST_NAME_ONCHANGE) {
    state.first_name = action.first_name;

  } else if (action.type === USER_REGISTER_LAST_NAME_ONCHANGE) {
      state.last_name = action.last_name;

    } else if (action.type === USER_REGISTER_AGREEMENT_ONCLICK) {
      state.agreement_accepted = !state.agreement_accepted;

  } else if (action.type === USER_REGISTER_ONSUBMIT) {
    state.onregister.response_data = action.response_data;
    state.onregister.response_code = action.response_code;

  } else if (action.type === USER_REGISTER_ONCLEAR) {
    state.user_login = "";
    state.user_password = "";
    state.first_name = "";
    state.last_name = "";
    state.agreement_accepted = false;
    state.onregister.response_data = {};
    state.onregister.response_code = 0;
  }

  return state;
}

export const UserRegisterUserLoginOnchangeActionCreator = (user_login) => {
  return {
    type: USER_REGISTER_USER_LOGIN_ONCHANGE,
    user_login: user_login,
  }
}

export const UserRegisterUserPasswordOnchangeActionCreator = (user_password) => {
  return {
    type: USER_REGISTER_USER_PASSWORD_ONCHANGE,
    user_password: user_password,
  }
}

export const UserRegisterFirstNameOnchangeActionCreator = (first_name) => {
  return {
    type: USER_REGISTER_FIRST_NAME_ONCHANGE,
    first_name: first_name,
  }
}

export const UserRegisterLastNameOnchangeActionCreator = (last_name) => {
  return {
    type: USER_REGISTER_LAST_NAME_ONCHANGE,
    last_name: last_name,
  }
}

export const UserRegisterAgreementOnclickActionCreator = () => {
  return {
    type: USER_REGISTER_AGREEMENT_ONCLICK,
  }
}

export const UserRegisterOnsubmitActionCreator = (response_data, response_code) => {
  return {
    type: USER_REGISTER_ONSUBMIT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const UserRegisterOnclearActionCreator = () => {
  return {
    type: USER_REGISTER_ONCLEAR,
  }
}

export default UserRegisterReducer;
