import i18n from "i18next";
import { initReactI18next } from "react-i18next";
import { jwtDecode } from "jwt-decode";
import { cookies_get, cookies_set, cookies_remove } from "../helpers/cookies_helper";

import config from "../config";
import en from "../i18n/en";
import es from "../i18n/es";
import ru from "../i18n/ru";
import empty from "../helpers/empty_helper";

const APP_LOCK_ONLOAD = "APP_LOCK_ONLOAD";
const APP_TOKEN_ONLOAD = "APP_TOKEN_ONLOAD";
const APP_TOKEN_ONUPDATE = "APP_TOKEN_ONUPDATE";
const APP_TOKEN_ONDELETE = "APP_TOKEN_ONDELETE";
const APP_TIMEZONE_ONLOAD = "APP_TIMEZONE_ONLOAD";
const APP_TIMEZONE_ONCHANGE = "APP_TIMEZONE_ONCHANGE";
const APP_LANGUAGE_ONLOAD = "APP_LANGUAGE_ONLOAD";
const APP_LANGUAGE_ONCHANGE = "APP_LANGUAGE_ONCHANGE";
const APP_THEME_ONLOAD = "APP_THEME_ONLOAD";
const APP_THEME_ONCHANGE = "APP_THEME_ONCHANGE";

const initial = {
  is_locked: false,
  locked_date: 0,
  user_token: null,
  token_payload: {},
  user_timezone: config.default_user_timezone,
  user_language: config.default_user_language,
  user_theme: config.default_user_theme,
};

i18n.use(initReactI18next).init({
  resources: {
    en: {translation: en},
    es: {translation: es},
    ru: {translation: ru},
  },
  lng: initial.user_language,
  resolvedLanguage: initial.user_language,
  fallbackLng: initial.user_language,
});


const AppReducer = (state = initial, action) => {

  if (action.type === APP_LOCK_ONLOAD) {
    state.is_locked = action.response_data.is_locked;
    state.locked_date = action.response_data.locked_date;

  } else if (action.type === APP_TOKEN_ONLOAD) {
    try {
      state.user_token = cookies_get("user-token");
      state.token_payload = jwtDecode(state.user_token);
      cookies_set("user-token", state.user_token);

    } catch (e) {
      state.user_token = null;
      state.token_payload = {};
      cookies_remove("user-token");
    }
    
  } else if (action.type === APP_TOKEN_ONUPDATE) {
    try {
      state.user_token = action.user_token;
      state.token_payload = jwtDecode(state.user_token);
      cookies_set("user-token", state.user_token);

    } catch (e) {
      state.user_token = null;
      state.token_payload = {};
      cookies_remove("user-token");
    }

  } else if (action.type === APP_TOKEN_ONDELETE) {
    state.user_token = null;
    state.token_payload = {};
    cookies_remove("user-token");

  } else if (action.type === APP_TIMEZONE_ONLOAD) {
    let user_timezone = cookies_get("user-timezone");

    if (!empty(user_timezone)) {
      try {
        Intl.DateTimeFormat(undefined, {timeZone: user_timezone});
      } catch (e) {
        user_timezone = null
      }
    }

    if (empty(user_timezone)) {
      try {
        user_timezone = Intl.DateTimeFormat().resolvedOptions().timeZone;
      } catch (e) {
        user_timezone = null;
      }
    }

    state.user_timezone = empty(user_timezone) ? initial.user_timezone : user_timezone;
    cookies_set("user-timezone", state.user_timezone);

  } else if (action.type === APP_TIMEZONE_ONCHANGE) {
    try {
      Intl.DateTimeFormat(undefined, {timeZone: action.user_timezone});
      state.user_timezone = action.user_timezone
    } catch (e) {
      state.user_timezone = initial.user_timezone
    }
    cookies_set("user-timezone", state.user_timezone);

  } else if (action.type === APP_LANGUAGE_ONLOAD) {
    let user_language = cookies_get("user-language");
    if (!Object.keys(i18n.store.data).includes(user_language)) {
      const navigator_language = navigator.language || navigator.userLanguage;
      user_language = navigator_language.split("-")[0];
    }

    if (!Object.keys(i18n.store.data).includes(user_language)) {
      user_language = initial.user_language;
    }

    state.user_language = user_language;
    i18n.changeLanguage(state.user_language);
    cookies_set("user-language", state.user_language);
  
  } else if (action.type === APP_LANGUAGE_ONCHANGE) {
    state.user_language = Object.keys(i18n.store.data).includes(action.user_language) ? action.user_language : initial.user_language;
    i18n.changeLanguage(state.user_language);
    cookies_set("user-language", state.user_language);

  } else if (action.type === APP_THEME_ONLOAD) {
    const user_theme = cookies_get("user-theme");
    state.user_theme = ["light", "dark"].includes(user_theme) ? user_theme : initial.user_theme;
    document.documentElement.setAttribute("data-bs-theme", state.user_theme);
    cookies_set("user-theme", state.user_theme);    

  } else if (action.type === APP_THEME_ONCHANGE) {
    state.user_theme = state.user_theme === "light" ? "dark" : "light";
    document.documentElement.setAttribute("data-bs-theme", state.user_theme);
    cookies_set("user-theme", state.user_theme);
  }

  return state;
}

export const AppLockOnloadActionCreator = (response_data, response_code) => {
  return {
    type: APP_LOCK_ONLOAD,
    response_data: response_data,
    response_code: response_code,
  }
}

export const AppTokenOnloadActionCreator = () => {
  return {
    type: APP_TOKEN_ONLOAD,
  }
}

export const AppTokenOnupdateActionCreator = (user_token) => {
  return {
    type: APP_TOKEN_ONUPDATE,
    user_token: user_token,
  }
}

export const AppTokenOndeleteActionCreator = () => {
  return {
    type: APP_TOKEN_ONDELETE,
  }
}

export const AppTimezoneOnloadActionCreator = () => {
  return {
    type: APP_TIMEZONE_ONLOAD,
  }
}

export const AppTimezoneOnchangeActionCreator = (user_timezone) => {
  return {
    type: APP_TIMEZONE_ONCHANGE,
    user_timezone: user_timezone,
  }
}

export const AppLanguageOnloadActionCreator = () => {
  return {
    type: APP_LANGUAGE_ONLOAD,
  }
}

export const AppLanguageOnchangeActionCreator = (user_language) => {
  return {
    type: APP_LANGUAGE_ONCHANGE,
    user_language: user_language,
  }
}

export const AppThemeOnloadActionCreator = () => {
  return {
    type: APP_THEME_ONLOAD,
  }
}

export const AppThemeOnchangeActionCreator = () => {
  return {
    type: APP_THEME_ONCHANGE,
  }
}

export default AppReducer;
