import {
  PartnerUpdatePartnerNameOnchangeActionCreator,
  PartnerUpdatePartnerTypeOnchangeActionCreator,
  PartnerUpdatePartnerRegionOnchangeActionCreator,
  PartnerUpdatePartnerContactsOnchangeActionCreator,
  PartnerUpdatePartnerWebsiteOnchangeActionCreator,
  PartnerUpdatePartnerSummaryOnchangeActionCreator,
  PartnerUpdateFilesOnchangeActionCreator,
  PartnerUpdateOnselectActionCreator,
  PartnerUpdateOnupdateActionCreator,
  PartnerUpdateOnclearActionCreator
} from "../../reducers/partner_update_reducer";
import PartnerUpdateComponent from "../../components/partner/partner_update_component";
import { PartnerListOnclearActionCreator } from "../../reducers/partner_list_reducer";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import { log } from "../../helpers/log_helper";
import redirect from "../../helpers/redirect_helper";

const PartnerUpdateMiddleware = (props) => {
  const navigate = useNavigate();

  const PartnerUpdatePartnerNameOnchange = (partner_name) => {
    const action = PartnerUpdatePartnerNameOnchangeActionCreator(partner_name);
    props.store.dispatch(action);
  }

  const PartnerUpdatePartnerTypeOnchange = (partner_type) => {
    const action = PartnerUpdatePartnerTypeOnchangeActionCreator(partner_type);
    props.store.dispatch(action);
  }

  const PartnerUpdatePartnerRegionOnchange = (partner_region) => {
    const action = PartnerUpdatePartnerRegionOnchangeActionCreator(partner_region);
    props.store.dispatch(action);
  }

  const PartnerUpdatePartnerWebsiteOnchange = (partner_website) => {
    const action = PartnerUpdatePartnerWebsiteOnchangeActionCreator(partner_website);
    props.store.dispatch(action);
  }

  const PartnerUpdatePartnerContactsOnchange = (partner_contacts) => {
    const action = PartnerUpdatePartnerContactsOnchangeActionCreator(partner_contacts);
    props.store.dispatch(action);
  }

  const PartnerUpdatePartnerSummaryOnchange = (partner_summary) => {
    const action = PartnerUpdatePartnerSummaryOnchangeActionCreator(partner_summary);
    props.store.dispatch(action);
  }

  const PartnerUpdateFilesOnchange = (files) => {
    const log_prefix = "update-update-onpartnerpic";
    const partner_id = props.store.getState().partner_update.partner_id;

    const formData = new FormData();
    formData.append("file", Array.from(files)[0]);

    axios({
      method: "post",
      url: config.server_host + "partner/" + partner_id + "/partnerpic", 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      data: formData,

    }).then(response => {
      log.debug(log_prefix, response);

      const action = PartnerUpdateFilesOnchangeActionCreator("");
      props.store.dispatch(action);

      PartnerUpdateOnselect();
      
    }).catch(e => {
      log.error(log_prefix, e);
    });
  }

  const PartnerUpdateOnselect = () => {
    const log_prefix = "partner-select";

    axios({
      method: "get",
      url: config.server_host + "partner/" + props.store.getState().partner_update.partner_id, 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },

    }).then((response) => {
      log.debug(log_prefix, response);

      const action = PartnerUpdateOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);
      
    }).catch(e => {
      log.error(log_prefix, e);
      redirect(e, navigate);
    });
  }

  const PartnerUpdateOnupdate = () => {
    const offcanvas_id = "offcanvas-partner-update";
    const log_prefix = "partner-update";
    buttons_disable(offcanvas_id);

    axios({
      method: "put",
      url: config.server_host + "partner/" + props.store.getState().partner_update.partner_id, 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      data: {
        partner_name: props.store.getState().partner_update.partner_name,
        partner_type: props.store.getState().partner_update.partner_type,
        partner_region: props.store.getState().partner_update.partner_region,
        partner_website: props.store.getState().partner_update.partner_website,
        partner_contacts: props.store.getState().partner_update.partner_contacts,
        partner_summary: props.store.getState().partner_update.partner_summary,
      },

    }).then(response => {
      log.debug(log_prefix, response);
      buttons_enable(offcanvas_id);
      offcanvas_hide();
      
      const action = PartnerUpdateOnupdateActionCreator(response.data, response.status);
      props.store.dispatch(action);

      PartnerListOnclear();

    }).catch(e => {
      log.error(log_prefix, e);
      buttons_enable(offcanvas_id);

      if (e.status === 422) {
        const action = PartnerUpdateOnupdateActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }
    });
  }

  const PartnerUpdateOnclear = () => {
    const action = PartnerUpdateOnclearActionCreator();
    props.store.dispatch(action);
  }

  const PartnerListOnclear = () => {
    const action = PartnerListOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <PartnerUpdateComponent
      partner_id={ props.store.getState().partner_update.partner_id }
      partner_name={ props.store.getState().partner_update.partner_name }
      partner_type={ props.store.getState().partner_update.partner_type }
      partner_region={ props.store.getState().partner_update.partner_region }
      partner_website={ props.store.getState().partner_update.partner_website }
      partner_contacts={ props.store.getState().partner_update.partner_contacts }
      partner_summary={ props.store.getState().partner_update.partner_summary }
      partnerpic_url={ props.store.getState().partner_update.partnerpic_url }
      files={ props.store.getState().partner_update.files }

      response_data={ props.store.getState().partner_update.onupdate.response_data }
      response_code={ props.store.getState().partner_update.onupdate.response_code }

      PartnerUpdatePartnerNameOnchange={ PartnerUpdatePartnerNameOnchange }
      PartnerUpdatePartnerTypeOnchange={ PartnerUpdatePartnerTypeOnchange }
      PartnerUpdatePartnerRegionOnchange={ PartnerUpdatePartnerRegionOnchange }
      PartnerUpdatePartnerWebsiteOnchange={ PartnerUpdatePartnerWebsiteOnchange }
      PartnerUpdatePartnerContactsOnchange={ PartnerUpdatePartnerContactsOnchange }
      PartnerUpdatePartnerSummaryOnchange={ PartnerUpdatePartnerSummaryOnchange }
      PartnerUpdateFilesOnchange={ PartnerUpdateFilesOnchange }

      PartnerUpdateOnselect={ PartnerUpdateOnselect }
      PartnerUpdateOnupdate={ PartnerUpdateOnupdate }
      PartnerUpdateOnclear={ PartnerUpdateOnclear }
    />
  );
}
  
export default PartnerUpdateMiddleware;
