import {
  CollectionUpdateCollectionNameOnchangeActionCreator, CollectionUpdateCollectionSummaryOnchangeActionCreator,
  CollectionUpdateIsLockedOnchangeActionCreator, CollectionUpdateOnselectActionCreator,
  CollectionUpdateOnupdateActionCreator, CollectionUpdateOnclearActionCreator } from "../../reducers/collection_update_reducer";
import CollectionUpdateComponent from "../../components/collection/collection_update_component";
import { CollectionListOnclearActionCreator } from "../../reducers/collection_list_reducer";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import { log } from "../../helpers/log_helper";
import redirect from "../../helpers/redirect_helper";

const CollectionUpdateMiddleware = (props) => {
  const navigate = useNavigate();

  const CollectionUpdateCollectionNameOnchange = (collection_name) => {
    const action = CollectionUpdateCollectionNameOnchangeActionCreator(collection_name);
    props.store.dispatch(action);
  }

  const CollectionUpdateCollectionSummaryOnchange = (collection_summary) => {
    const action = CollectionUpdateCollectionSummaryOnchangeActionCreator(collection_summary);
    props.store.dispatch(action);
  }

  const CollectionUpdateIsLockedOnchange = () => {
    const action = CollectionUpdateIsLockedOnchangeActionCreator();
    props.store.dispatch(action);
  }

  const CollectionUpdateOnselect = () => {
    const log_prefix = "collection-select";

    axios({
      method: "get",
      url: config.server_host + "collection/" + props.store.getState().collection_update.collection_id, 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },

    }).then((response) => {
      log.debug(log_prefix, response);

      const action = CollectionUpdateOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);
      
    }).catch(e => {
      log.error(log_prefix, e);
      redirect(e, navigate);
    });
  }

  const CollectionUpdateOnupdate = () => {
    const offcanvas_id = "offcanvas-collection-update";
    const log_prefix = "collection-update";
    buttons_disable(offcanvas_id);

    axios({
      method: "put",
      url: config.server_host + "collection/" + props.store.getState().collection_update.collection_id, 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      data: {
        collection_name: props.store.getState().collection_update.collection_name,
        collection_summary: props.store.getState().collection_update.collection_summary,
        is_locked: props.store.getState().collection_update.is_locked,
      },

    }).then(response => {
      log.debug(log_prefix, response);
      buttons_enable(offcanvas_id);
      offcanvas_hide();
      
      const action = CollectionUpdateOnupdateActionCreator(response.data, response.status);
      props.store.dispatch(action);

      CollectionListOnclear();

    }).catch(e => {
      log.error(log_prefix, e);
      buttons_enable(offcanvas_id);

      if (e.status === 422) {
        const action = CollectionUpdateOnupdateActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }

    });
  }

  const CollectionUpdateOnclear = () => {
    const action = CollectionUpdateOnclearActionCreator();
    props.store.dispatch(action);
  }

  const CollectionListOnclear = () => {
    const action = CollectionListOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <CollectionUpdateComponent
      collection_id={ props.store.getState().collection_update.collection_id }
      collection_name={ props.store.getState().collection_update.collection_name }
      collection_summary={ props.store.getState().collection_update.collection_summary }
      is_locked={ props.store.getState().collection_update.is_locked }

      response_data={ props.store.getState().collection_update.onupdate.response_data }
      response_code={ props.store.getState().collection_update.onupdate.response_code }

      CollectionUpdateCollectionNameOnchange={ CollectionUpdateCollectionNameOnchange }
      CollectionUpdateCollectionSummaryOnchange={ CollectionUpdateCollectionSummaryOnchange }
      CollectionUpdateIsLockedOnchange={ CollectionUpdateIsLockedOnchange }
      CollectionUpdateOnselect={ CollectionUpdateOnselect }
      CollectionUpdateOnupdate={ CollectionUpdateOnupdate }
      CollectionUpdateOnclear={ CollectionUpdateOnclear }
    />
  );
}
  
export default CollectionUpdateMiddleware;
