import config from "../config";
import { cookies_get, cookies_set } from "../helpers/cookies_helper";

const COLLECTION_LIST_OFFSET_ONCHANGE = "COLLECTION_LIST_OFFSET_ONCHANGE";
const COLLECTION_LIST_LIMIT_ONCHANGE = "COLLECTION_LIST_LIMIT_ONCHANGE";
const COLLECTION_LIST_ORDER_ONCHANGE = "COLLECTION_LIST_ORDER_ONCHANGE";
const COLLECTION_LIST_ONSELECT = "COLLECTION_LIST_ONSELECT";
const COLLECTION_LIST_ONCLEAR = "COLLECTION_LIST_ONCLEAR";

const COLLECTION_FILTER_USER_DATALIST_USER_NAME_ONCHANGE = "COLLECTION_FILTER_USER_DATALIST_USER_NAME_ONCHANGE";
const COLLECTION_FILTER_USER_DATALIST_ONLOAD = "COLLECTION_LIST_USER_DATALIST_ONLOAD";
const COLLECTION_FILTER_IS_LOCKED_ONCHANGE = "COLLECTION_FILTER_IS_LOCKED_ONCHANGE";
const COLLECTION_FILTER_COLLECTION_NAME_ONCHANGE = "COLLECTION_FILTER_COLLECTION_NAME_ONCHANGE";
const COLLECTION_FILTER_ONRESET = "COLLECTION_FILTER_ONRESET";

const initial = {
  order_by: config.default_collections_order_by,
  order: config.default_collections_order,
  offset: 0,
  limit: config.default_collections_limit,
  onselect: {
    response_data: {},
    response_code: 0,
  },
  filter: {
    collection_name: "",
    is_locked: "",
    user_datalist: {
      user_name: "",
      user_id: 0,
      response_data: {},
      response_code: 0,
    },
  },
};

const order_by = cookies_get("collections_order_by");
if (config.allowed_collections_order_by.includes(order_by)) {
  initial.order_by = order_by;
}
cookies_set("collections_order_by", initial.order_by);

const order = cookies_get("collections_order");
if (config.allowed_collections_order.includes(order)) {
  initial.order = order;
}
cookies_set("collections_order", initial.order);

const limit = cookies_get("collections_limit");
if (config.allowed_collections_limit.includes(limit)) {
  initial.limit = limit;
}
cookies_set("collections_limit", initial.limit);

initial.offset = parseInt(cookies_get("collections_offset")) || 0;
cookies_set("collections_offset", initial.offset);

const CollectionListReducer = (state = initial, action) => {

  if (action.type === COLLECTION_LIST_LIMIT_ONCHANGE) {
    const limit = parseInt(action.limit) || config.default_collections_limit;
    state.limit = config.allowed_collections_limit.includes(limit) ? limit : config.default_collections_limit;
    cookies_set("collections_limit", state.limit);

  } else if (action.type === COLLECTION_LIST_OFFSET_ONCHANGE) {
    state.offset = parseInt(action.offset) || 0;
    cookies_set("collections_offset", state.offset);

  } else if (action.type === COLLECTION_LIST_ORDER_ONCHANGE) {
    const order_by = config.allowed_collections_order_by.includes(action.order_by) ? action.order_by : config.default_collections_order_by;

    if (state.order_by === order_by) {
      state.order = state.order === "asc" ? "desc" : "asc";
      cookies_set("collections_order", state.order);

    } else {
      state.order_by = action.order_by;
      cookies_set("collections_order_by", state.order_by);
    }

  } else if (action.type === COLLECTION_LIST_ONSELECT) {
    state.onselect.response_data = action.response_data;
    state.onselect.response_code = action.response_code;

  } else if (action.type === COLLECTION_LIST_ONCLEAR) {
    state.onselect.response_data = {};
    state.onselect.response_code = 0;

  } else if (action.type === COLLECTION_FILTER_USER_DATALIST_USER_NAME_ONCHANGE) {
    state.filter.user_datalist.user_name = action.user_name;

  } else if (action.type === COLLECTION_FILTER_USER_DATALIST_ONLOAD) {
    state.filter.user_datalist.response_data = action.response_data;
    state.filter.user_datalist.response_code = action.response_code;

    const user = Array.prototype.find.call(action.response_data.users, el => {
      return el.first_name.toLocaleLowerCase() + " " + el.last_name.toLocaleLowerCase() === state.filter.user_datalist.user_name.toLocaleLowerCase();
    });
    state.filter.user_datalist.user_id = user ? user.id : 0;

  } else if (action.type === COLLECTION_FILTER_IS_LOCKED_ONCHANGE) {
    state.filter.is_locked = action.is_locked;

  } else if (action.type === COLLECTION_FILTER_COLLECTION_NAME_ONCHANGE) {
    state.filter.collection_name = action.collection_name;

  } else if (action.type === COLLECTION_FILTER_ONRESET) {
    state.filter.user_datalist.response_data = {};
    state.filter.user_datalist.response_code = 0;
    state.filter.user_datalist.user_id = 0;
    state.filter.user_datalist.user_name = "";
    state.filter.is_locked = "";
    state.filter.collection_name = "";
  }

  return state;
}

export const CollectionListOffsetOnchangeActionCreator = (offset) => {
  return {
    type: COLLECTION_LIST_OFFSET_ONCHANGE,
    offset: offset, 
  }
}

export const CollectionListLimitOnchangeActionCreator = (limit) => {
  return {
    type: COLLECTION_LIST_LIMIT_ONCHANGE, 
    limit: limit, 
  }
}

export const CollectionListOrderOnchangeActionCreator = (order_by) => {
  return {
    type: COLLECTION_LIST_ORDER_ONCHANGE, 
    order_by: order_by, 
  }
}

export const CollectionListOnselectActionCreator = (response_data, response_code) => {
  return {
      type: COLLECTION_LIST_ONSELECT,
      response_data: response_data,
      response_code: response_code,
    }
}

export const CollectionListOnclearActionCreator = () => {
  return {
    type: COLLECTION_LIST_ONCLEAR,
  }
}

export const CollectionFilterCollectionNameOnchangeActionCreator = (collection_name) => {
  return {
    type: COLLECTION_FILTER_COLLECTION_NAME_ONCHANGE, 
    collection_name: collection_name, 
  }
}

export const CollectionFilterIsLockedOnchangeActionCreator = (is_locked) => {
  return {
    type: COLLECTION_FILTER_IS_LOCKED_ONCHANGE, 
    is_locked: is_locked, 
  }
}

export const CollectionFilterUserDatalistUserNameOnchangeActionCreator = (user_name) => {
  return {
    type: COLLECTION_FILTER_USER_DATALIST_USER_NAME_ONCHANGE, 
    user_name: user_name, 
  }
}

export const CollectionFilterUserDatalistOnloadActionCreator = (response_data, response_code) => {
  return {
      type: COLLECTION_FILTER_USER_DATALIST_ONLOAD,
      response_data: response_data,
      response_code: response_code,
    }
}

export const CollectionFilterOnresetActionCreator = () => {
  return {
    type: COLLECTION_FILTER_ONRESET,
  }
}

export default CollectionListReducer;
