import { useTranslation } from "react-i18next";
import errors from "../../helpers/errors_helper";
import { useEffect } from "react";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import config from "../../config";

const PartnerInsertComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-partner-insert";

  useEffect(() => {
    const offcanvas = document.getElementById(offcanvas_id);

    offcanvas.addEventListener("shown.bs.offcanvas", () => {
      offcanvas.querySelector(".focused").focus();
    });

    offcanvas.addEventListener("hide.bs.offcanvas", () => {
      setTimeout(() => { props.PartnerInsertOnclear() },
      config.offcanvas_refresh_delay);
    });
  }, []);

  const PartnerInsertPartnerNameOnchange = (event) => {
    props.PartnerInsertPartnerNameOnchange(event.target.value);
  }

  const PartnerInsertPartnerTypeOnchange = (event) => {
    props.PartnerInsertPartnerTypeOnchange(event.target.value);
  }

  const PartnerInsertPartnerRegionOnchange = (event) => {
    props.PartnerInsertPartnerRegionOnchange(event.target.value);
  }

  const PartnerInsertPartnerWebsiteOnchange = (event) => {
    props.PartnerInsertPartnerWebsiteOnchange(event.target.value);
  }

  const PartnerInsertPartnerContactsOnchange = (event) => {
    props.PartnerInsertPartnerContactsOnchange(event.target.value);
  }

  const PartnerInsertPartnerSummaryOnchange = (event) => {
    props.PartnerInsertPartnerSummaryOnchange(event.target.value);
  }

   const is_valid = (key, value) => {
    if (key === "partner_name") {
      return props.partner_name.length >= 1 && props.partner_name.length <= 256;

    } else if (key === "partner_type") {
      return !props.partner_type || props.partner_type.length <= 256;
    
    } else if (key === "partner_region") {
      return !props.partner_region || props.partner_region.length <= 256;
    
    } else if (key === "partner_website") {
      return !props.partner_website || props.partner_website.length <= 256;
    
    } else if (key === "partner_contacts") {
      return !props.partner_contacts || props.partner_contacts.length <= 512;

    } else if (key === "partner_summary") {
      return !props.partner_summary || props.partner_summary.length <= 512;
    }
  }

  const submit_enabled = is_valid("partner_name") && is_valid("partner_type") && is_valid("partner_region") && is_valid("partner_website") && is_valid("partner_contacts") && is_valid("partner_summary");
  const response_errors = errors(props.response_data);

  const PartnerInsertOninsert = (event) => {
    event.preventDefault();
    if (submit_enabled) {
      props.PartnerInsertOninsert();
    }
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title d-flex">
          { t("offcanvas-partner-insert-title") }
          <div className="dropdown ms-2">
            <a href="#" className="link link-primary dropdown-toggle no-after" type="button" data-bs-toggle="dropdown">
              <i className="bi bi-list"></i>
            </a>
            <ul className="dropdown-menu">
              <li><a className="dropdown-item" href="#" onClick={ offcanvas_hide }>{ t("button-cancel") }</a></li>
            </ul>
          </div>
        </h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

          <div className="form-text">
            { t("partner-name-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ PartnerInsertPartnerNameOnchange } value={ props.partner_name } type="text" className={ "form-control focused" + ("partner_name" in response_errors ? " border-danger glow-danger" : is_valid("partner_name") ? " border-primary" : "") } placeholder={ t("partner-name") } maxLength="256" />
            <label>{ t("partner-name") }</label>
          </div>
          <div className="form-text text-danger">
            { "partner_name" in response_errors && t("error_" + response_errors["partner_name"]) }
          </div>

          <div className="form-text">
            { t("partner-type-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ PartnerInsertPartnerTypeOnchange } value={ props.partner_type } type="text" className={ "form-control" + ("partner_type" in response_errors ? " border-danger glow-danger" : is_valid("partner_type") ? " border-primary" : "") } placeholder={ t("partner-type") } maxLength="256" />
            <label>{ t("partner-type") }</label>
          </div>
          <div className="form-text text-danger">
            { "partner_type" in response_errors && t("error_" + response_errors["partner_type"]) }
          </div>

          <div className="form-text">
            { t("partner-region-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ PartnerInsertPartnerRegionOnchange } value={ props.partner_region } type="text" className={ "form-control" + ("partner_region" in response_errors ? " border-danger glow-danger" : is_valid("partner_region") ? " border-primary" : "") } placeholder={ t("partner-region") } maxLength="256" />
            <label>{ t("partner-region") }</label>
          </div>
          <div className="form-text text-danger">
            { "partner_region" in response_errors && t("error_" + response_errors["partner_region"]) }
          </div>

          <div className="form-text">
            { t("partner-website-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ PartnerInsertPartnerWebsiteOnchange } value={ props.partner_website } type="text" className={ "form-control" + ("partner_website" in response_errors ? " border-danger glow-danger" : is_valid("partner_website") ? " border-primary" : "") } placeholder={ t("partner-website") } maxLength="256" />
            <label>{ t("partner-website") }</label>
          </div>
          <div className="form-text text-danger">
            { "partner_website" in response_errors && t("error_" + response_errors["partner_website"]) }
          </div>

          <div className="form-text">
            { t("partner-contacts-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ PartnerInsertPartnerContactsOnchange } value={ props.partner_contacts } type="text" className={ "form-control" + ("partner_contacts" in response_errors ? " border-danger glow-danger" : is_valid("partner_contacts") ? " border-primary" : "") } placeholder={ t("partner-contacts") } maxLength="512" />
            <label>{ t("partner-contacts") }</label>
          </div>
          <div className="form-text text-danger">
            { "partner_contacts" in response_errors && t("error_" + response_errors["partner_contacts"]) }
          </div>

          <div className="form-text">
            { t("partner-summary-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ PartnerInsertPartnerSummaryOnchange } value={ props.partner_summary } type="text" className={ "form-control" + ("partner_summary" in response_errors ? " border-danger glow-danger" : is_valid("partner_summary") ? " border-primary" : "") } placeholder={ t("partner-summary") } maxLength="512" />
            <label>{ t("partner-summary") }</label>
          </div>
          <div className="form-text text-danger">
            { "partner_summary" in response_errors && t("error_" + response_errors["partner_summary"]) }
          </div>

          <button className="btn btn-outline-primary mt-4" type="button" onClick={ offcanvas_hide }>
            <i className="bi bi-arrow-left"></i> { t("button-cancel") }
          </button>

          <button onClick={ PartnerInsertOninsert } className={"btn btn-primary mt-4 ms-2 " + (!submit_enabled ? "disabled" : "")} type="submit">
            <i className="bi bi-check2"></i> { t("button-submit") }
          </button>

        </form>
      </div>
    </div>
  );
}

export default PartnerInsertComponent;
