import {
  UserTotpUserTotpOnchangeActionCreator,
  UserTotpTokenUnexpiredOnclickActionCreator,
  UserTotpOnsubmitActionCreator,
  UserTotpOnclearActionCreator } from "../../reducers/user_totp_reducer";
import { AppTokenOnupdateActionCreator } from "../../reducers/app_reducer";
import UserTotpComponent from "../../components/user/user_totp_component";
import { log } from "../../helpers/log_helper";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import redirect from "../../helpers/redirect_helper";

const UserTotpMiddleware = (props) => {
  const navigate = useNavigate();

  const UserTotpUserTotpOnchange = (user_totp) => {
    const action = UserTotpUserTotpOnchangeActionCreator(user_totp);
    props.store.dispatch(action);
  }

  const UserTotpTokenUnexpiredOnclick = () => {
    const action = UserTotpTokenUnexpiredOnclickActionCreator();
    props.store.dispatch(action);
  }

  const UserTotpOnsubmit = () => {
    const offcanvas_id = "offcanvas-user-totp";
    const log_prefix = "user-totp";
    buttons_disable(offcanvas_id);

    let params = {
      user_login: props.store.getState().user_totp.user_login,
      user_totp: props.store.getState().user_totp.user_totp,
    };

    if (!props.store.getState().user_totp.token_unexpired > 0) {
      params.token_exp = Math.floor(Date.now() / 1000) + config.user_token_expires;
    }

    axios({
      method: "get",
      url: config.server_host + "auth/token", 
      headers: {},
      params: params,

    }).then(response => {
      log.debug(log_prefix, response);

      buttons_enable(offcanvas_id);
      offcanvas_hide();
      navigate("/documents");

      let action = AppTokenOnupdateActionCreator(response.data.user_token);
      props.store.dispatch(action);

      action = UserTotpOnclearActionCreator();
      props.store.dispatch(action);

    }).catch(e => {
      log.error(log_prefix, e);
      buttons_enable(offcanvas_id);

      if (e.status === 422 || e.status === 403)  {
        const action = UserTotpOnsubmitActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }

    });
  }

  const UserTotpOnclear = () => {
    const action = UserTotpOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <UserTotpComponent
      user_login={ props.store.getState().user_totp.user_login }
      user_totp={ props.store.getState().user_totp.user_totp }
      token_unexpired={ props.store.getState().user_totp.token_unexpired }

      response_data={ props.store.getState().user_totp.ontotp.response_data }
      response_code={ props.store.getState().user_totp.ontotp.response_code }

      UserTotpUserTotpOnchange={ UserTotpUserTotpOnchange }
      UserTotpTokenUnexpiredOnclick={ UserTotpTokenUnexpiredOnclick }
      UserTotpOnsubmit={ UserTotpOnsubmit }
      UserTotpOnclear={ UserTotpOnclear }
    />
  );
}
  
export default UserTotpMiddleware;
