const sizes_count = 6; // B, KiB, MiB, GiB, PiB, EiB, ZiB

const filesize = (bytes, t) => {

    const thresh=1024;
    const dp=1;

    if(bytes === 0 || bytes === undefined) {
        return '0 ' + t('filesize.0');

    } else if (Math.abs(bytes) < thresh) {
        return bytes + ' ' + t('filesize.0');
    }

    let u = 0;
    const r = 10**dp;

    do {
        bytes /= thresh;
        ++u;
    } while (Math.round(Math.abs(bytes) * r) / r >= thresh && u < sizes_count);

    return bytes.toFixed(dp) + ' ' + t('filesize.' + u);
}

export default filesize;
