import DatalistComponent from "../components/datalist_component";
import axios from "axios";
import { log } from "../helpers/log_helper";

const DatalistMiddleware = (props) => {

  // change datalist value
  const DatalistValueOnchange = (value) => {
    props.datalist_onchange(value);
  }

  // load datalist
  const DatalistOnload = (is_updated=false) => {
    let params = {
      order_by: props.request_order_by,
      order: props.request_order,
      offset: 0,
      limit: 10,
      [props.request_param]: props.datalist_value,
    }

    axios({
      method: "get",
      url: props.request_url, 
      headers: {"Authorization": "Bearer " + props.user_token},
      params: params,

    }).then(response => {
      log.debug("datalist", response);

      const action = props.datalist_onload_action_creator(response.data, response.status);
      props.dispatch(action);

      if (is_updated) {
        props.onupdate();
      }

    }).catch(e => {
      log.error("datalist", e);
    });
  }

  return (
    <DatalistComponent
        user_token={ props.user_token }
        datalist_name={ props.datalist_name }
        datalist_placeholder={ props.datalist_placeholder }
        datalist_value={ props.datalist_value }
        datalist_id={ props.datalist_id }
        datalist_options={ props.datalist_options }
        response_data={ props.response_data }
        response_code={ props.response_code }
        DatalistValueOnchange={ DatalistValueOnchange }
        DatalistOnload={ DatalistOnload }
    />
  )
}
  
export default DatalistMiddleware;