const COLLECTION_SELECT_COLLECTION_ID_ONCHANGE = "COLLECTION_SELECT_COLLECTION_ID_ONCHANGE";
const COLLECTION_SELECT_ONSELECT = "COLLECTION_SELECT_ONSELECT";
const COLLECTION_SELECT_ONCLEAR = "COLLECTION_SELECT_ONCLEAR";

const initial = {
  collection_id: 0,
  onselect: {
    response_data: {},
    response_code: 0,
  },
};

const CollectionSelectReducer = (state = initial, action) => {

  if (action.type === COLLECTION_SELECT_COLLECTION_ID_ONCHANGE) {
    state.collection_id = parseInt(action.collection_id);
  
  } else if (action.type === COLLECTION_SELECT_ONSELECT) {
    state.onselect.response_data = action.response_data;
    state.onselect.response_code = action.response_code;

  } else if (action.type === COLLECTION_SELECT_ONCLEAR) {
    state.collection_id = 0;
    state.onselect.response_data = {};
    state.onselect.response_code = 0;
  }

  return state;
}

export const CollectionSelectCollectionIdOnchangeActionCreator = (collection_id) => {
  return {
    type: COLLECTION_SELECT_COLLECTION_ID_ONCHANGE,
    collection_id: collection_id,
  }
}

export const CollectionSelectOnselectActionCreator = (response_data, response_code) => {
  return {
    type: COLLECTION_SELECT_ONSELECT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const CollectionSelectOnclearActionCreator = () => {
  return {
    type: COLLECTION_SELECT_ONCLEAR,
  }
}

export default CollectionSelectReducer;
