import { Suspense } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import config from "../config";
import { log } from "../helpers/log_helper";

import { AppLockOnloadActionCreator } from "../reducers/app_reducer";
import { AppTokenOnloadActionCreator } from "../reducers/app_reducer";
import { AppTokenOndeleteActionCreator } from "../reducers/app_reducer";
import { AppTimezoneOnloadActionCreator } from "../reducers/app_reducer";
import { AppTimezoneOnchangeActionCreator } from "../reducers/app_reducer";
import { AppLanguageOnloadActionCreator } from "../reducers/app_reducer";
import { AppLanguageOnchangeActionCreator } from "../reducers/app_reducer";
import { AppThemeOnloadActionCreator } from "../reducers/app_reducer";
import { AppThemeOnchangeActionCreator } from "../reducers/app_reducer";

import AppComponent from "../components/app_component";

const AppMiddleware = (props) => {
  const navigate = useNavigate();

  const AppLockOnload = () => {
    axios({
      method: "get",
      url: config.server_host + "locked", 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      params: {},

    }).then(response => {
      const action = AppLockOnloadActionCreator(response.data, response.status);
      props.store.dispatch(action);

    }).catch(e => {});
  }

  const AppTokenOnload = () => {
    const action = AppTokenOnloadActionCreator();
    props.store.dispatch(action);
  }

  const AppTokenOndelete = () => {
    const log_prefix = "logout";

    axios({
      method: "delete",
      url: config.server_host + "auth/token", 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },

    }).then(response => {
      log.debug(log_prefix, response);
      const action = AppTokenOndeleteActionCreator();
      props.store.dispatch(action);
      navigate("/");

    }).catch(e => {
      log.error(log_prefix, e);
      const action = AppTokenOndeleteActionCreator();
      props.store.dispatch(action);
      navigate("/");
    });
  }

  const AppTimezoneOnload = () => {
    const action = AppTimezoneOnloadActionCreator();
    props.store.dispatch(action);
  }

  const AppTimezoneOnchange = (user_timezone) => {
    const action = AppTimezoneOnchangeActionCreator(user_timezone);
    props.store.dispatch(action);
  }

  const AppLanguageOnload = () => {
    const action = AppLanguageOnloadActionCreator();
    props.store.dispatch(action);
  }

  const AppLanguageOnchange = (user_language) => {
    const action = AppLanguageOnchangeActionCreator(user_language);
    props.store.dispatch(action);
  }

  const AppThemeOnload = () => {
    const action = AppThemeOnloadActionCreator();
    props.store.dispatch(action);
  }

  const AppThemeOnchange = () => {
    const action = AppThemeOnchangeActionCreator();
    props.store.dispatch(action);
  }

  return (
    <Suspense fallback="Loading...">
      <AppComponent
        store={ props.store }
        AppLockOnload={ AppLockOnload }
        AppTokenOnload={ AppTokenOnload }
        AppTokenOndelete={ AppTokenOndelete }
        AppTimezoneOnload={ AppTimezoneOnload }
        AppTimezoneOnchange={ AppTimezoneOnchange }
        AppLanguageOnload={ AppLanguageOnload }
        AppLanguageOnchange={ AppLanguageOnchange }
        AppThemeOnload={ AppThemeOnload }
        AppThemeOnchange={ AppThemeOnchange }
      />
    </Suspense>
  );
}
  
export default AppMiddleware;
