const PARTNER_SELECT_PARTNER_ID_ONCHANGE = "PARTNER_SELECT_PARTNER_ID_ONCHANGE";
const PARTNER_SELECT_ONSELECT = "PARTNER_SELECT_ONSELECT";
const PARTNER_SELECT_ONCLEAR = "PARTNER_SELECT_ONCLEAR";

const initial = {
  partner_id: 0,
  onselect: {
    response_data: {},
    response_code: 0,
  },
};

const PartnerSelectReducer = (state = initial, action) => {

  if (action.type === PARTNER_SELECT_PARTNER_ID_ONCHANGE) {
    state.partner_id = parseInt(action.partner_id);
  
  } else if (action.type === PARTNER_SELECT_ONSELECT) {
    state.onselect.response_data = action.response_data;
    state.onselect.response_code = action.response_code;
  
  } else if (action.type === PARTNER_SELECT_ONCLEAR) {
    state.partner_id = 0;
    state.onselect.response_data = {};
    state.onselect.response_code = 0;
  }

  return state;
}

export const PartnerSelectPartnerIdOnchangeActionCreator = (partner_id) => {
  return {
    type: PARTNER_SELECT_PARTNER_ID_ONCHANGE,
    partner_id: partner_id,
  }
}

export const PartnerSelectOnselectActionCreator = (response_data, response_code) => {
  return {
    type: PARTNER_SELECT_ONSELECT,
    response_data: response_data,
    response_code: response_code,
  }
}

export const PartnerSelectOnclearActionCreator = () => {
  return {
    type: PARTNER_SELECT_ONCLEAR,
  }
}

export default PartnerSelectReducer;
