import { useTranslation } from "react-i18next";
import errors from "../../helpers/errors_helper";
import { useEffect } from "react";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import config from "../../config";
import DatalistMiddleware from "../../middleware/datalist_middleware";
import empty from "../../helpers/empty_helper";
import {
  DocumentUpdateCollectionDatalistOnloadActionCreator,
  DocumentUpdatePartnerDatalistOnloadActionCreator } from "../../reducers/document_update_reducer";

const DocumentUpdateComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-document-update";

  useEffect(() => {
    const offcanvas = document.getElementById(offcanvas_id);

    offcanvas.addEventListener("shown.bs.offcanvas", () => {
      props.DocumentUpdateOnselect();
      offcanvas.querySelector(".focused").focus();
    });

    offcanvas.addEventListener("hide.bs.offcanvas", () => {
      setTimeout(
        () => { props.DocumentUpdateOnclear() },
        config.offcanvas_refresh_delay);
    });
  }, []);

  const DocumentUpdateIsFlaggedOnchange = () => {
    props.DocumentUpdateIsFlaggedOnchange();
  }

  const DocumentUpdateDocumentFilenameOnchange = (event) => {
    props.DocumentUpdateDocumentFilenameOnchange(event.target.value);
  }

  const DocumentUpdateDocumentSummaryOnchange = (event) => {
    props.DocumentUpdateDocumentSummaryOnchange(event.target.value);
  }

  const DocumentUpdateDocumentTagsOnchange = (event) => {
    props.DocumentUpdateDocumentTagsOnchange(event.target.value);
  }

  const DocumentUpdateFilesOnchange = (event) => {
    props.DocumentUpdateFilesOnchange(event.target.files);
  }

  const is_valid = (key) => {
    if (key === "document_filename") {
      return props.document_filename.length >= 1 && props.document_filename.length <= 256;

    } else if (key === "document_summary") {
      return !props.document_summary || props.document_summary.length <= 512;

    } else if (key === "document_tags") {
      return !props.document_tags || props.document_tags.length <= 256;
    }
  }

  const submit_enabled = is_valid("document_filename") && is_valid("document_summary") && is_valid("document_tags");
  const response_errors = errors(props.response_data);

  const DocumentUpdateOnupdate = (event) => {
    event.preventDefault();
    if (submit_enabled) {
      props.DocumentUpdateOnupdate();
    }
  }

  if(empty(props.files)) {
    const files = document.getElementById("document-update-files");
    if(files) {
      files.value = "";
    }
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title">{ t("offcanvas-document-update-title") }</h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

        <div className="form-text">
            { t("id") }
          </div>
          <div>
            { props.document_id }
          </div>

          <div className="form-text mt-4">
            { t("document-filename-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ DocumentUpdateDocumentFilenameOnchange } value={ props.document_filename } type="text" className={ "form-control focused" + ("document_filename" in response_errors ? " border-danger glow-danger" : is_valid("document_filename") ? " border-primary" : "") } placeholder={ t("document-filename") } maxLength="256" />
            <label>{ t("document-filename") }</label>
          </div>
          <div className="form-text text-danger">
            { "document_filename" in response_errors && t("error_" + response_errors["document_filename"]) }
          </div>

          <div className="form-text mt-4">
            { t("document-flagged-text") }
          </div>
          <div className="form-floating mt-2">
            <div className="form-switch">
              <input id="document-update-flag" onChange={ DocumentUpdateIsFlaggedOnchange } checked={ props.is_flagged } className="form-check-input" type="checkbox" role="switch" />
              <label className="form-check-label ms-2" htmlFor="document-update-flag">{ t("document-flagged") }</label>
            </div>
          </div>

          { props.thumbnail_url && <>
            <div className="form-text d-flex justify-content-center align-items-center mt-4">
              <img src={ props.thumbnail_url } style={{ width: "auto", height: "auto" }} className="card-img-top" alt={ props.document_filename } />
            </div>
          </> }

          <div className="form-text mt-4">
            { t("document-files-text") }
          </div>
          <div className="mt-2">
            <input id="document-update-files" className={ "form-control" + (props.files.length > 0 ? " border-primary" : "") } type="file" onInput={ DocumentUpdateFilesOnchange } files={ props.files } />
          </div>

          <div className="form-text mt-4">
            { t("document-collection-text") }
          </div>
          <div className="form-text mt-2">
            <DatalistMiddleware
              dispatch={ props.dispatch }
              user_token={ props.user_token }
              // datalist data
              datalist_name="document-update-collection-datalist"
              datalist_placeholder={ t("collection-name") }
              datalist_value={ props.collection_datalist.collection_name }
              datalist_id={ props.collection_datalist.collection_id }
              response_data={ props.collection_datalist.response_data }
              response_code={ props.collection_datalist.response_code }
              datalist_options={ !empty(props.collection_datalist.response_data) ? props.collection_datalist.response_data.collections.map(el => { return { id: el.id, value: el.collection_name } }) : [] }
              // request
              request_url={ config.server_host + "collections" }
              request_param="collection_name__ilike"
              request_order_by="collection_name"
              request_order="asc"
              // datalist actions
              datalist_onchange={ props.DocumentUpdateCollectionDatalistCollectionNameOnchange }
              datalist_onload_action_creator={ DocumentUpdateCollectionDatalistOnloadActionCreator }
              onupdate={ () => {} }
            />
          </div>

          <div className="form-text mt-4">
            { t("document-update-partner-text") }
          </div>
          <div className="form-text mt-2">
            <DatalistMiddleware
              dispatch={ props.dispatch }
              user_token={ props.user_token }
              // datalist data
              datalist_name="document-update-partner-datalist"
              datalist_placeholder={ t("partner-name") }
              datalist_value={ props.partner_datalist.partner_name }
              datalist_id={ props.partner_datalist.partner_id }
              response_data={ props.partner_datalist.response_data }
              response_code={ props.partner_datalist.response_code }
              datalist_options={ !empty(props.partner_datalist.response_data) ? props.partner_datalist.response_data.partners.map(el => { return { id: el.id, value: el.partner_name } }) : [] }
              // request
              request_url={ config.server_host + "partners" }
              request_param="partner_name__ilike"
              request_order_by="partner_name"
              request_order="asc"
              // datalist actions
              datalist_onchange={ props.DocumentUpdatePartnerDatalistPartnerNameOnchange }
              datalist_onload_action_creator={ DocumentUpdatePartnerDatalistOnloadActionCreator }
              onupdate={ () => {} }
            />
          </div>

          <div className="form-text mt-4">
            { t("document-summary-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ DocumentUpdateDocumentSummaryOnchange } value={ props.document_summary || "" } type="text" className={ "form-control focused" + ("document_summary" in response_errors ? " border-danger glow-danger" : is_valid("document_summary") ? " border-primary" : "") } placeholder={ t("document-summary") } maxLength="512" />
            <label>{ t("document-summary") }</label>
          </div>
          <div className="form-text text-danger">
            { "document_summary" in response_errors && t("error_" + response_errors["document_summary"]) }
          </div>

          <div className="form-text mt-4">
            { t("document-tags-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ DocumentUpdateDocumentTagsOnchange } value={ props.document_tags || "" } type="text" className={ "form-control focused" + ("document_tags" in response_errors ? " border-danger glow-danger" : is_valid("document_tags") ? " border-primary" : "") } placeholder={ t("document-tags") } maxLength="256" />
            <label>{ t("document-tags") }</label>
          </div>
          <div className="form-text text-danger">
            { "document_tags" in response_errors && t("error_" + response_errors["document_tags"]) }
          </div>

          <button className="btn btn-outline-primary mt-4" type="button" onClick={ offcanvas_hide }>
            <i className="bi bi-arrow-left"></i> { t("button-cancel") }
          </button>

          <button onClick={ DocumentUpdateOnupdate } className={"btn btn-primary mt-4 ms-2 " + (!submit_enabled ? "disabled" : "")} type="submit">
            <i className="bi bi-check2"></i> { t("button-submit") }
          </button>

        </form>
      </div>
    </div>
  );
}

export default DocumentUpdateComponent;
