const COLLECTION_DELETE_COLLECTION_ID_ONCHANGE = "COLLECTION_DELETE_COLLECTION_ID_ONCHANGE";
const COLLECTION_DELETE_COLLECTION_IDS_ONSHIFT = "COLLECTION_DELETE_COLLECTION_IDS_ONSHIFT";
const COLLECTION_DELETE_ONCLEAR = "COLLECTION_DELETE_ONCLEAR";

const initial = {
  collection_id: 0,
  collection_ids: [],
};

const CollectionDeleteReducer = (state = initial, action) => {

  if (action.type === COLLECTION_DELETE_COLLECTION_ID_ONCHANGE) {
    state.collection_id = parseInt(action.collection_id);

  } else if (action.type === COLLECTION_DELETE_COLLECTION_IDS_ONSHIFT) {
    const collection_id = parseInt(action.collection_id);

    if (state.collection_ids.includes(collection_id)) {
      state.collection_ids = state.collection_ids.filter(id => id !== collection_id);

    } else {
      state.collection_ids.push(collection_id);
    }

  } else if (action.type === COLLECTION_DELETE_ONCLEAR) {
    state.collection_id = 0;
  }

  return state;
}

export const CollectionDeleteCollectionIdOnchangeActionCreator = (collection_id) => {
  return {
    type: COLLECTION_DELETE_COLLECTION_ID_ONCHANGE,
    collection_id: collection_id, 
  }
}

export const CollectionDeleteCollectionIdsOnshiftActionCreator = (collection_id) => {
  return {
    type: COLLECTION_DELETE_COLLECTION_IDS_ONSHIFT,
    collection_id: collection_id, 
  }
}

export const CollectionDeleteOnclearActionCreator = () => {
  return {
    type: COLLECTION_DELETE_ONCLEAR,
  }
}

export default CollectionDeleteReducer;
