import axios from "axios";
import config from "../../config";
import { log } from "../../helpers/log_helper";
import { 
  CollectionListOffsetOnchangeActionCreator, CollectionListLimitOnchangeActionCreator,
  CollectionListOrderOnchangeActionCreator, CollectionListOnselectActionCreator,
  CollectionListOnclearActionCreator, CollectionFilterCollectionNameOnchangeActionCreator,
  CollectionFilterUserDatalistUserNameOnchangeActionCreator, CollectionFilterIsLockedOnchangeActionCreator,
  CollectionFilterOnresetActionCreator } from "../../reducers/collection_list_reducer";
import { CollectionSelectCollectionIdOnchangeActionCreator } from "../../reducers/collection_select_reducer";
import { CollectionDeleteCollectionIdsOnshiftActionCreator } from "../../reducers/collection_delete_reducer";
import { CollectionLockCollectionIdsOnshiftActionCreator } from "../../reducers/collection_lock_reducer";
import CollectionListComponent from "../../components/collection/collection_list_component";
import {
  DocumentFilterCollectionDatalistCollectionIdOnchangeActionCreator,
  DocumentFilterOnresetActionCreator,
  DocumentListOffsetOnchangeActionCreator,
  DocumentListOnclearActionCreator } from "../../reducers/document_list_reducer";
import { UserSelectUserIdOnchangeActionCreator } from "../../reducers/user_select_reducer";
import { useNavigate } from "react-router-dom";
import redirect from "../../helpers/redirect_helper";

let is_loading = false;

const CollectionListMiddleware = (props) => {
  const navigate = useNavigate();

  const CollectionListOffsetOnchange = (offset) => {
    const action = CollectionListOffsetOnchangeActionCreator(offset);
    props.store.dispatch(action);
  }

  const CollectionListLimitOnchange = (limit) => {
    let action = CollectionListLimitOnchangeActionCreator(limit);
    props.store.dispatch(action);
  }

  const CollectionListOrderOnchange = (order_by) => {
    const action = CollectionListOrderOnchangeActionCreator(order_by);
    props.store.dispatch(action);
  }

  const CollectionListOnselect = () => {
    if (is_loading) { return }
    is_loading = true;
    const log_prefix = "collection-list";
    
    const params = {
      offset: props.store.getState().collection_list.offset, 
      limit: props.store.getState().collection_list.limit,
      order_by: props.store.getState().collection_list.order_by, 
      order: props.store.getState().collection_list.order,
    };

    const collection_name = props.store.getState().collection_list.filter.collection_name;
    if (collection_name) {
      params.collection_name__ilike = collection_name;
    }

    const user_id = props.store.getState().collection_list.filter.user_datalist.user_id;
    if (user_id) {
      params.user_id__eq = user_id;
    }

    const is_locked = props.store.getState().collection_list.filter.is_locked;
    if (is_locked !== "") {
      params.is_locked__eq = is_locked;
    }

    axios({
      method: "get",
      url: config.server_host + "collections", 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      params: params,

    }).then(response => {
      log.debug(log_prefix, response);

      const action = CollectionListOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);
      is_loading = false;

    }).catch(e => {
      log.error(log_prefix, e);
      is_loading = false;
      redirect(e, navigate);
    });
  }

  const CollectionListOnclear = () => {
    const action = CollectionListOnclearActionCreator();
    props.store.dispatch(action);
  }

  const CollectionFilterCollectionNameOnchange = (collection_name) => {
    const action = CollectionFilterCollectionNameOnchangeActionCreator(collection_name);
    props.store.dispatch(action);
  }

  const CollectionFilterIsLockedOnchange = (is_locked) => {
    const action = CollectionFilterIsLockedOnchangeActionCreator(is_locked);
    props.store.dispatch(action);
  }

  const CollectionFilterUserDatalistUserNameOnchange = (user_name) => {
    const action = CollectionFilterUserDatalistUserNameOnchangeActionCreator(user_name);
    props.store.dispatch(action);
  }

  const CollectionFilterOnreset = () => {
    const action = CollectionFilterOnresetActionCreator();
    props.store.dispatch(action);
  }

  const CollectionSelectCollectionIdOnchange = (collection_id) => {
    const action = CollectionSelectCollectionIdOnchangeActionCreator(collection_id);
    props.store.dispatch(action);
  }

  const CollectionDeleteCollectionIdsOnshift = (collection_id) => {
    let action = CollectionDeleteCollectionIdsOnshiftActionCreator(collection_id);
    props.store.dispatch(action);
  }

  const CollectionLockCollectionIdsOnshift = (collection_id) => {
    let action = CollectionLockCollectionIdsOnshiftActionCreator(collection_id);
    props.store.dispatch(action);
  }

  const UserSelectUserIdOnchange = (user_id) => {
    const action = UserSelectUserIdOnchangeActionCreator(user_id);
    props.store.dispatch(action);
  }

  const DocumentListOffsetOnchange = (offset) => {
    const action = DocumentListOffsetOnchangeActionCreator(offset);
    props.store.dispatch(action);
  }

  const DocumentListOnclear = () => {
    const action = DocumentListOnclearActionCreator();
    props.store.dispatch(action);
  }

  const DocumentFilterOnreset = () => {
    const action = DocumentFilterOnresetActionCreator();
    props.store.dispatch(action);
  }

  const DocumentFilterCollectionDatalistCollectionIdOnchange = (collection_id, collection_name) => {
    const action = DocumentFilterCollectionDatalistCollectionIdOnchangeActionCreator(collection_id, collection_name);
    props.store.dispatch(action);
  }

  const checked_ids = props.store.getState().collection_delete.collection_ids.filter(
    id => props.store.getState().collection_lock.collection_ids.includes(id));

  return (
    <CollectionListComponent
      dispatch={ props.store.dispatch }
      user_timezone={ props.store.getState().app.user_timezone }
      user_token={ props.store.getState().app.user_token }
      token_payload={ props.store.getState().app.token_payload }

      offset={ props.store.getState().collection_list.offset }
      limit={ props.store.getState().collection_list.limit }
      order_by={ props.store.getState().collection_list.order_by }
      order={ props.store.getState().collection_list.order }
      filter={ props.store.getState().collection_list.filter }
      collection_ids={ checked_ids }

      response_data={ props.store.getState().collection_list.onselect.response_data }
      response_code={ props.store.getState().collection_list.onselect.response_code }

      CollectionListOffsetOnchange={ CollectionListOffsetOnchange }
      CollectionListLimitOnchange={ CollectionListLimitOnchange }
      CollectionListOrderOnchange={ CollectionListOrderOnchange }
      CollectionListOnselect={ CollectionListOnselect }
      CollectionListOnclear={ CollectionListOnclear }

      CollectionFilterCollectionNameOnchange={ CollectionFilterCollectionNameOnchange }
      CollectionFilterUserDatalistUserNameOnchange={ CollectionFilterUserDatalistUserNameOnchange }
      CollectionFilterIsLockedOnchange={ CollectionFilterIsLockedOnchange }
      CollectionFilterOnreset={ CollectionFilterOnreset }

      CollectionSelectCollectionIdOnchange={ CollectionSelectCollectionIdOnchange }
      CollectionDeleteCollectionIdsOnshift={ CollectionDeleteCollectionIdsOnshift }
      CollectionLockCollectionIdsOnshift={ CollectionLockCollectionIdsOnshift }
      UserSelectUserIdOnchange={ UserSelectUserIdOnchange }

      DocumentFilterCollectionDatalistCollectionIdOnchange={ DocumentFilterCollectionDatalistCollectionIdOnchange }
      DocumentFilterOnreset={ DocumentFilterOnreset }
      DocumentListOffsetOnchange={ DocumentListOffsetOnchange }
      DocumentListOnclear={ DocumentListOnclear }
    />
  );
}
  
export default CollectionListMiddleware;