import { 
  CollectionInsertCollectionNameOnchangeActionCreator, CollectionInsertCollectionSummaryOnchangeActionCreator,
  CollectionInsertIsLockedOnchangeActionCreator, CollectionInsertOninsertActionCreator,
  CollectionInsertOnclearActionCreator } from "../../reducers/collection_insert_reducer";
import { CollectionListOnclearActionCreator } from "../../reducers/collection_list_reducer";
import CollectionInsertComponent from "../../components/collection/collection_insert_component";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import { log } from "../../helpers/log_helper";
import redirect from "../../helpers/redirect_helper";

const CollectionInsertMiddleware = (props) => {
  const navigate = useNavigate();

  const CollectionInsertCollectionNameOnchange = (collection_name) => {
    const action = CollectionInsertCollectionNameOnchangeActionCreator(collection_name);
    props.store.dispatch(action);
  }

  const CollectionInsertCollectionSummaryOnchange = (collection_summary) => {
    const action = CollectionInsertCollectionSummaryOnchangeActionCreator(collection_summary);
    props.store.dispatch(action);
  }

  const CollectionInsertIsLockedOnchange = () => {
    const action = CollectionInsertIsLockedOnchangeActionCreator();
    props.store.dispatch(action);
  }

  const CollectionInsertOninsert = () => {
    const offcanvas_id = "offcanvas-collection-insert";
    const log_prefix = "collection-insert";
    buttons_disable(offcanvas_id);

    axios({
      method: "post",
      url: config.server_host + "collection", 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token},
      data: {
        collection_name: props.store.getState().collection_insert.collection_name,
        collection_summary: props.store.getState().collection_insert.collection_summary,
        is_locked: props.store.getState().collection_insert.is_locked,
      },

    }).then(response => {
      log.debug(log_prefix, response);
      buttons_enable(offcanvas_id);
      offcanvas_hide();
      
      let action = CollectionInsertOninsertActionCreator(response.data, response.status);
      props.store.dispatch(action);

      action = CollectionListOnclearActionCreator();
      props.store.dispatch(action);

    }).catch(e => {
      log.error(log_prefix, e);
      buttons_enable(offcanvas_id);

      if (e.status === 422) {
        const action = CollectionInsertOninsertActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }
    });
  }

  const CollectionInsertOnclear = () => {
    const action = CollectionInsertOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <CollectionInsertComponent
      collection_name={ props.store.getState().collection_insert.collection_name }
      collection_summary={ props.store.getState().collection_insert.collection_summary }
      is_locked={ props.store.getState().collection_insert.is_locked }

      response_data={ props.store.getState().collection_insert.oninsert.response_data }
      response_code={ props.store.getState().collection_insert.oninsert.response_code }

      CollectionInsertCollectionNameOnchange={ CollectionInsertCollectionNameOnchange }
      CollectionInsertCollectionSummaryOnchange={ CollectionInsertCollectionSummaryOnchange }
      CollectionInsertIsLockedOnchange={ CollectionInsertIsLockedOnchange }
      CollectionInsertOninsert={ CollectionInsertOninsert }
      CollectionInsertOnclear={ CollectionInsertOnclear }
    />
  );
}
  
export default CollectionInsertMiddleware;
