import {
  DocumentListOnclearActionCreator,
  DocumentListOnselectActionCreator,
  DocumentListOffsetOnchangeActionCreator } from "../../reducers/document_list_reducer";
import DocumentMoveComponent from "../../components/document/document_move_component";
import {
  DocumentMoveDocumentIdsOnshiftActionCreator,
  DocumentMoveCollectionDatalistCollectionNameOnchangeActionCreator,
  DocumentMoveCollectionDatalistOnselectActionCreator,
  DocumentMoveOnclearActionCreator } from "../../reducers/document_move_reducer";
import config from "../../config";
import axios from "axios";
import empty from "../../helpers/empty_helper";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import { log } from "../../helpers/log_helper";
import { useNavigate } from "react-router-dom";
import redirect from "../../helpers/redirect_helper";

const DocumentMoveMiddleware = (props) => {
  const navigate = useNavigate();

  const DocumentMoveDocumentIdsOnshift = (document_id) => {
    const action = DocumentMoveDocumentIdsOnshiftActionCreator(document_id);
    props.store.dispatch(action);
  }

  const DocumentMoveCollectionDatalistCollectionNameOnchange = (collection_name) => {
    const action = DocumentMoveCollectionDatalistCollectionNameOnchangeActionCreator(collection_name);
    props.store.dispatch(action);
  }

  const DocumentMoveOnupdate = () => {
    const offcanvas_id = "offcanvas-document-move";
    const log_prefix = "document-move-onupdate";
    buttons_disable(offcanvas_id);

    const document_id = props.store.getState().document_move.document_id;
    const document_ids = props.store.getState().document_move.document_ids;
    const collection_id = props.store.getState().document_move.collection_datalist.collection_id > 0 ? props.store.getState().document_move.collection_datalist.collection_id : null;

    let ids_to_move = document_id ? [document_id] : Array.from(document_ids);
    let ids_in_progress = Array.from(ids_to_move);
   
    ids_to_move.forEach(id => {
      axios({
        method: "put",
        url: config.server_host + "document/" + id + "/collection/" + collection_id, 
        headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
        params: {},

      }).then(response => {
        log.debug(log_prefix, response);
        ids_in_progress.splice(ids_in_progress.indexOf(id), 1);

        if (empty(ids_in_progress)) {
          DocumentListOnclear();
          buttons_enable(offcanvas_id);
          offcanvas_hide();
        }
        
      }).catch(e => {
        log.error(log_prefix, e);

        if (e.status === 404) {
            ids_in_progress.splice(ids_in_progress.indexOf(id), 1);
  
          if (empty(ids_in_progress)) {
            DocumentListOnclear();
            buttons_enable(offcanvas_id);
            offcanvas_hide();
          }
  
        } else {
          redirect(e, navigate);
        }

      });
    });
  }

  const DocumentMoveOnclear = () => {
    const action = DocumentMoveOnclearActionCreator();
    props.store.dispatch(action);
  }

  const DocumentListOnclear = () => {
    let action = DocumentListOffsetOnchangeActionCreator(0);
    props.store.dispatch(action);

    action = DocumentListOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <DocumentMoveComponent
      dispatch={ props.store.dispatch }
      user_token={ props.store.getState().app.user_token }

      document_id={ props.store.getState().document_move.document_id }
      document_ids={ props.store.getState().document_move.document_ids }
      DocumentMoveOnupdate={ DocumentMoveOnupdate }
      DocumentMoveOnclear={ DocumentMoveOnclear }

      collection_datalist={ props.store.getState().document_move.collection_datalist }
      DocumentMoveCollectionDatalistCollectionNameOnchange={ DocumentMoveCollectionDatalistCollectionNameOnchange }
    />
  );
}
  
export default DocumentMoveMiddleware;
