import {
  UserLoginUserLoginOnchangeActionCreator,
  UserLoginUserPasswordOnchangeActionCreator,
  UserLoginOnsubmitActionCreator,
  UserLoginOnclearActionCreator } from "../../reducers/user_login_reducer";
import { UserTotpUserLoginOnchangeActionCreator } from "../../reducers/user_totp_reducer";
import UserLoginComponent from "../../components/user/user_login_component";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { log } from "../../helpers/log_helper";
import { offcanvas_hide, offcanvas_show } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import redirect from "../../helpers/redirect_helper";

const UserLoginMiddleware = (props) => {
  const navigate = useNavigate();

  const UserLoginUserLoginOnchange = (user_login) => {
    const action = UserLoginUserLoginOnchangeActionCreator(user_login);
    props.store.dispatch(action);
  }

  const UserLoginUserPasswordOnchange = (user_password) => {
    const action = UserLoginUserPasswordOnchangeActionCreator(user_password);
    props.store.dispatch(action);
  }

  const UserLoginOnsubmit = () => {
    const offcanvas_id = "offcanvas-user-login";
    const log_prefix = "user-login";
    buttons_disable(offcanvas_id);

    axios({
      method: "post",
      url: config.server_host + "auth/login", 
      headers: {},
      data: {
        user_login: props.store.getState().user_login.user_login,
        user_password: props.store.getState().user_login.user_password,
      },

    }).then(response => {
      log.debug(log_prefix, response);

      offcanvas_hide();
      offcanvas_show("offcanvas-user-totp");
      buttons_enable(offcanvas_id);

      let action = UserLoginOnsubmitActionCreator(response.data, response.status);
      props.store.dispatch(action);

      action = UserTotpUserLoginOnchangeActionCreator(props.store.getState().user_login.user_login);
      props.store.dispatch(action);

    }).catch(e => {
      log.error(log_prefix, e);
      
      buttons_enable(offcanvas_id);

      if (e.status === 422 || e.status === 403)  {
        const action = UserLoginOnsubmitActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }
    });
  }

  const UserLoginOnclear = () => {
    const action = UserLoginOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <UserLoginComponent
      user_login={ props.store.getState().user_login.user_login }
      user_password={ props.store.getState().user_login.user_password }

      response_data={ props.store.getState().user_login.onlogin.response_data }
      response_code={ props.store.getState().user_login.onlogin.response_code }

      UserLoginUserLoginOnchange={ UserLoginUserLoginOnchange }
      UserLoginUserPasswordOnchange={ UserLoginUserPasswordOnchange }
      UserLoginOnsubmit={ UserLoginOnsubmit }
      UserLoginOnclear={ UserLoginOnclear }
    />
  );
}
  
export default UserLoginMiddleware;
