import { CollectionSelectOnselectActionCreator, CollectionSelectOnclearActionCreator } from "../../reducers/collection_select_reducer";
import { CollectionUpdateCollectionIdOnchangeActionCreator } from "../../reducers/collection_update_reducer";
import { CollectionDeleteCollectionIdOnchangeActionCreator } from "../../reducers/collection_delete_reducer";
import { CollectionLockCollectionIdOnchangeActionCreator } from "../../reducers/collection_lock_reducer";
import CollectionSelectComponent from "../../components/collection/collection_select_component";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { log } from "../../helpers/log_helper";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import redirect from "../../helpers/redirect_helper";
import { UserSelectUserIdOnchangeActionCreator } from "../../reducers/user_select_reducer";

const CollectionSelectMiddleware = (props) => {
  const navigate = useNavigate();

  const CollectionSelectOnselect = () => {
    const log_prefix = "collection-select";

    axios({
      method: "get",
      url: config.server_host + "collection/" + props.store.getState().collection_select.collection_id, 
      headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
      params: {},

    }).then((response) => {
      log.debug(log_prefix, response);

      const action = CollectionSelectOnselectActionCreator(response.data, response.status);
      props.store.dispatch(action);
      
    }).catch(e => {
      log.error(log_prefix, e);
      redirect(e, navigate);
    });

  }

  const CollectionSelectOnclear = () => {
    const action = CollectionSelectOnclearActionCreator();
    props.store.dispatch(action);
  }

  const CollectionUpdateCollectionIdOnchange = (collection_id) => {
    const action = CollectionUpdateCollectionIdOnchangeActionCreator(collection_id);
    props.store.dispatch(action);
  }

  const CollectionDeleteCollectionIdOnchange = (collection_id) => {
    const action = CollectionDeleteCollectionIdOnchangeActionCreator(collection_id);
    props.store.dispatch(action);    
  }

  const CollectionLockCollectionIdOnchange = (collection_id) => {
    const action = CollectionLockCollectionIdOnchangeActionCreator(collection_id);
    props.store.dispatch(action);    
  }

  const UserSelectUserIdOnchange = (user_id) => {
    const action = UserSelectUserIdOnchangeActionCreator(user_id);
    props.store.dispatch(action);
  }

  return (
    <CollectionSelectComponent
      user_timezone={ props.store.getState().app.user_timezone }
      user_role={ props.store.getState().app.token_payload.user_role }

      collection_id={ props.store.getState().collection_select.collection_id }
      response_data={ props.store.getState().collection_select.onselect.response_data }
      response_code={ props.store.getState().collection_select.onselect.response_code }

      CollectionSelectOnselect={ CollectionSelectOnselect }
      CollectionSelectOnclear={ CollectionSelectOnclear }
      CollectionUpdateCollectionIdOnchange={ CollectionUpdateCollectionIdOnchange }
      CollectionDeleteCollectionIdOnchange={ CollectionDeleteCollectionIdOnchange }
      CollectionLockCollectionIdOnchange={ CollectionLockCollectionIdOnchange }
      UserSelectUserIdOnchange={ UserSelectUserIdOnchange }
    />
  );
}
  
export default CollectionSelectMiddleware;
