const PARTNER_DELETE_PARTNER_ID_ONCHANGE = "PARTNER_DELETE_PARTNER_ID_ONCHANGE";
const PARTNER_DELETE_PARTNER_IDS_ONSHIFT = "PARTNER_DELETE_PARTNER_IDS_ONSHIFT";
const PARTNER_DELETE_ONCLEAR = "PARTNER_DELETE_ONCLEAR";

const initial = {
  partner_id: 0,
  partner_ids: [],
};

const PartnerDeleteReducer = (state = initial, action) => {

  if (action.type === PARTNER_DELETE_PARTNER_ID_ONCHANGE) {
    state.partner_id = parseInt(action.partner_id);

  } else if (action.type === PARTNER_DELETE_PARTNER_IDS_ONSHIFT) {
    const partner_id = parseInt(action.partner_id);

    if (state.partner_ids.includes(partner_id)) {
      state.partner_ids = state.partner_ids.filter(id => id !== partner_id);

    } else {
      state.partner_ids.push(partner_id);
    }

  } else if (action.type === PARTNER_DELETE_ONCLEAR) {
    state.partner_id = 0;
  }

  return state;
}

export const PartnerDeletePartnerIdOnchangeActionCreator = (partner_id) => {
  return {
    type: PARTNER_DELETE_PARTNER_ID_ONCHANGE,
    partner_id: partner_id, 
  }
}

export const PartnerDeletePartnerIdsOnshiftActionCreator = (partner_id) => {
  return {
    type: PARTNER_DELETE_PARTNER_IDS_ONSHIFT,
    partner_id: partner_id, 
  }
}

export const PartnerDeleteOnclearActionCreator = () => {
  return {
    type: PARTNER_DELETE_ONCLEAR,
  }
}

export default PartnerDeleteReducer;
