import { 
  CollectionLockIsLockedOnchangeActionCreator,
  CollectionLockOnclearActionCreator,
  CollectionLockCollectionIdOnchangeActionCreator } from "../../reducers/collection_lock_reducer";
import { CollectionListOnclearActionCreator } from "../../reducers/collection_list_reducer";
import CollectionLockComponent from "../../components/collection/collection_lock_component";
import config from "../../config";
import axios from "axios";
import empty from "../../helpers/empty_helper";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import { log } from "../../helpers/log_helper";
import { useNavigate } from "react-router-dom";
import redirect from "../../helpers/redirect_helper";

const CollectionLockMiddleware = (props) => {
  const navigate = useNavigate();

  const CollectionLockCollectionIdOnchange = (collection_id) => {
    const action = CollectionLockCollectionIdOnchangeActionCreator(collection_id);
    props.store.dispatch(action);
  }

  const CollectionLockIsLockedOnchange = () => {
    const action = CollectionLockIsLockedOnchangeActionCreator();
    props.store.dispatch(action);
  }

  const CollectionLockOnlock = () => {
    const offcanvas_id = "offcanvas-collection-lock";
    const log_prefix = "collection-lock";
    buttons_disable(offcanvas_id);

    const collection_id = props.store.getState().collection_lock.collection_id;
    const collection_ids = props.store.getState().collection_lock.collection_ids;

    let ids_to_lock = collection_id > 0 ? [collection_id] : Array.from(collection_ids);
    let ids_in_progress = Array.from(ids_to_lock);

    ids_to_lock.forEach(id => {
      axios({
        method: "put",
        url: config.server_host + "collection/" + id + "/locked", 
        headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
        data: { is_locked: props.store.getState().collection_lock.is_locked },

      }).then(response => {
        log.debug(log_prefix, response);
        ids_in_progress.splice(ids_in_progress.indexOf(id), 1);

        if (empty(ids_in_progress)) {
          CollectionListOnclear();
          buttons_enable(offcanvas_id);
          offcanvas_hide();
        }
        
      }).catch(e => {
        log.error(log_prefix, e);

        if (e.status === 404) {
            ids_in_progress.splice(ids_in_progress.indexOf(id), 1);
  
          if (empty(ids_in_progress)) {
            CollectionListOnclear();
            buttons_enable(offcanvas_id);
            offcanvas_hide();
          }
  
        } else {
          redirect(e, navigate);
        }
      });
    });
  }

  const CollectionLockOnclear = () => {
    const action = CollectionLockOnclearActionCreator();
    props.store.dispatch(action);
  }

  const CollectionListOnclear = () => {
    const action = CollectionListOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <CollectionLockComponent
      collection_id={ props.store.getState().collection_lock.collection_id }
      collection_ids={ props.store.getState().collection_lock.collection_ids }
      is_locked={ props.store.getState().collection_lock.is_locked }

      CollectionLockCollectionIdOnchange={ CollectionLockCollectionIdOnchange }
      CollectionLockIsLockedOnchange={ CollectionLockIsLockedOnchange }
      CollectionLockOnlock={ CollectionLockOnlock }
      CollectionLockOnclear={ CollectionLockOnclear }
    />
  );
}
  
export default CollectionLockMiddleware;
