import { useTranslation } from "react-i18next";
import config from "../config";
import empty from "../helpers/empty_helper";
import datetime from "../helpers/datetime_helper";
import { can_read, can_write, can_edit, can_admin } from "../helpers/role_helper"
import { offcanvas_show } from "../helpers/offcanvas_helper";
import { useNavigate } from "react-router-dom";
import filesize from "../helpers/filesize_helper";
import frequency from "../helpers/frequency_helper";
import { useEffect } from "react";

const TelemetrySelectComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-telemetry-select";

  useEffect(() => {
    document.getElementById(offcanvas_id).addEventListener("show.bs.offcanvas", () => {
      props.TelemetryOnselect();
    });

    document.getElementById(offcanvas_id).addEventListener("hide.bs.offcanvas", () => {
      setTimeout(
        () => { props.TelemetryOnclear() },
        config.offcanvas_latency);
    });
  }, []);

  const TelemetryOnselect = () => {
    props.TelemetryOnselect();
  }

  if (empty(props.response_data) && !empty(props.user_token)) {
    TelemetryOnselect();
  }

  const TelemetryOnclear = () => {
    props.TelemetryOnclear();
  }

  const memory_used = props.response_code === 200 ? (parseInt(props.response_data.memory_used) / ( parseInt(props.response_data.memory_total) / 100 )).toFixed(2) : 0;
  const disk_used = props.response_code === 200 ? (parseInt(props.response_data.disk_used) / ( parseInt(props.response_data.disk_total) / 100 )).toFixed(2) : 0;

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
    <div className="offcanvas-header">
      <h5 className="offcanvas-title">{ t("offcanvas-telemetry-select-title") }</h5>
      <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
      <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id } ></button>
    </div>
    <div className="offcanvas-body mb-4">
      <form>

        <div className="form-text">{ t("telemetry-platform-alias") }</div>
        <div>
          { props.response_code === 200 ? props.response_data.platform_alias : <span className="placeholder placeholder-lg col-8"></span> }
        </div>

        <div className="form-text mt-4">{ t("telemetry-platform-processor") }</div>
        <div>
          { props.response_code === 200 ? props.response_data.platform_processor : <span className="placeholder placeholder-lg col-8"></span> }
        </div>

        <div className="form-text mt-4">
          { t("telemetry-cpu") }
        </div>
        <div className="progress" style={{ height: "4px" }} role="progressbar">
          <div className="progress-bar bg-primary" style={{ width: String(props.response_data.cpu_usage_percent) + "%" }}></div>
        </div>
        <div className="text-center">
          { props.response_code === 200 ?  props.response_data.cpu_usage_percent + "% " + frequency(props.response_data.cpu_frequency, t) : "0% " + frequency(0, t) } 
        </div>

        <div className="form-text mt-4">
          { t("telemetry-memory") }
        </div>
        <div className="progress" style={{ height: "4px" }} role="progressbar">
          <div className="progress-bar bg-primary" style={{ width: String(memory_used) + "%" }}></div>
        </div>
        <div className="text-center">
          { props.response_code === 200 ? (filesize(props.response_data.memory_used, t) + "/" + filesize(props.response_data.memory_total, t) + " (" + memory_used + "%)") : "0/0 (0%)" } 
        </div>

        <div className="form-text mt-4">
          { t("telemetry-disk") }
        </div>
        <div className="progress" style={{ height: "4px" }} role="progressbar">
          <div className="progress-bar bg-primary" style={{ width: String(disk_used) + "%" }}></div>
        </div>
        <div className="text-center">
          { props.response_code === 200 ? (filesize(props.response_data.disk_used, t) + "/" + filesize(props.response_data.disk_total, t) + " (" + disk_used + "%)") : "0/0 (0%)" } 
        </div>

        <h5 className="mt-5">CPU</h5>
        <div>Core count: { props.response_code === 200 ? props.response_data.cpu_core_count : <span className="placeholder placeholder-lg col-2"></span> }</div>
        <div>Frequency: { props.response_code === 200 ? frequency(props.response_data.cpu_frequency, t) : <span className="placeholder placeholder-lg col-2"></span> }</div>
        <div>Usage percent: { props.response_code === 200 ? props.response_data.cpu_usage_percent : <span className="placeholder placeholder-lg col-2"></span> }</div>

        <h5>Disk</h5>
        <div>Total: { props.response_code === 200 ? filesize(props.response_data.disk_total, t) : <span className="placeholder placeholder-lg col-2"></span> }</div>
        <div>Used: { props.response_code === 200 ? filesize(props.response_data.disk_used, t) : <span className="placeholder placeholder-lg col-2"></span> }</div>
        <div>Free: { props.response_code === 200 ? filesize(props.response_data.disk_free, t) : <span className="placeholder placeholder-lg col-2"></span> }</div>

        <h5>Memory</h5>
        <div>Total: { props.response_code === 200 ? filesize(props.response_data.memory_total, t) : <span className="placeholder placeholder-lg col-2"></span> }</div>
        <div>Used: { props.response_code === 200 ? filesize(props.response_data.memory_used, t) : <span className="placeholder placeholder-lg col-2"></span> }</div>
        <div>Free: { props.response_code === 200 ? filesize(props.response_data.memory_free, t) : <span className="placeholder placeholder-lg col-2"></span> }</div>

        <button onClick={ TelemetryOnclear } className="btn btn-outline-primary mt-4" type="button">
          <i className="bi bi-arrow-left"></i> { t("button-refresh") }
        </button>

      </form>
    </div>
  </div>
  );
}

export default TelemetrySelectComponent;