const COMMENT_LIST_OFFSET_ONCHANGE = "COMMENT_LIST_OFFSET_ONCHANGE";
const COMMENT_LIST_ONSELECT = "COMMENT_LIST_ONSELECT";
const COMMENT_LIST_ONCLEAR = "COMMENT_LIST_ONCLEAR";

const initial = {
  offset: 0,
  onselect: {
    response_data: {},
    response_code: 0,
  },
};

const CommentListReducer = (state = initial, action) => {

  if (action.type === COMMENT_LIST_OFFSET_ONCHANGE) {
    state.offset = parseInt(action.offset) || 0;

  } else if (action.type === COMMENT_LIST_ONSELECT) {
    state.onselect.response_data = action.response_data;
    state.onselect.response_code = action.response_code;

  } else if (action.type === COMMENT_LIST_ONCLEAR) {
    state.document_id = 0;
    state.offset = 0;
    state.onselect.response_data = {};
    state.onselect.response_code = 0;
  }

  return state;
}

export const CommentListOffsetOnchangeActionCreator = (offset) => {
  return {
    type: COMMENT_LIST_OFFSET_ONCHANGE,
    offset: offset, 
  }
}

export const CommentListOnselectActionCreator = (response_data, response_code) => {
  return {
      type: COMMENT_LIST_ONSELECT,
      response_data: response_data,
      response_code: response_code,
    }
}

export const CommentListOnclearActionCreator = () => {
  return {
    type: COMMENT_LIST_ONCLEAR,
  }
}

export default CommentListReducer;
