import {
  UserPasswordCurrentPasswordOnchangeActionCreator,
  UserPasswordUpdatedPasswordOnchangeActionCreator,
  UserPasswordOnupdateActionCreator,
  UserPasswordOnclearActionCreator } from "../../reducers/user_password_reducer";
import UserPasswordComponent from "../../components/user/user_password_component";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import { log } from "../../helpers/log_helper";
import redirect from "../../helpers/redirect_helper";

const UserPasswordMiddleware = (props) => {
  const navigate = useNavigate();

  const UserPasswordCurrentPasswordOnchange = (current_password) => {
    const action = UserPasswordCurrentPasswordOnchangeActionCreator(current_password);
    props.store.dispatch(action);
  }

  const UserPasswordUpdatedPasswordOnchange = (updated_password) => {
    const action = UserPasswordUpdatedPasswordOnchangeActionCreator(updated_password);
    props.store.dispatch(action);
  }

  const UserPasswordOnupdate = () => {
    const offcanvas_name = "offcanvas-user-password";
    const log_prefix = "user-password-onupdate";
    buttons_disable(offcanvas_name);

    const user_id = props.store.getState().app.token_payload.user_id;
    const user_token = props.store.getState().app.user_token;

    axios({
      method: "put",
      url: config.server_host + "user/" + user_id + "/password", 
      headers: { Authorization: "Bearer " + user_token},
      data: {
        current_password: props.store.getState().user_password.current_password,
        updated_password: props.store.getState().user_password.updated_password,
      },

    }).then(response => {
      log.debug(log_prefix, response);

      buttons_enable(offcanvas_name);
      offcanvas_hide();
      
      const action = UserPasswordOnupdateActionCreator(response.data, response.status);
      props.store.dispatch(action);

      UserPasswordOnclear();

    }).catch(e => {
      log.error(log_prefix, e);
      buttons_enable(offcanvas_name);

      if (e.status === 422) {
        const action = UserPasswordOnupdateActionCreator(e.response.data, e.response.status);
        props.store.dispatch(action);

      } else {
        redirect(e, navigate);
      }
    });
  }

  const UserPasswordOnclear = () => {
    const action = UserPasswordOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <UserPasswordComponent
      current_password={ props.store.getState().user_password.current_password }
      updated_password={ props.store.getState().user_password.updated_password }

      response_data={ props.store.getState().user_password.onupdate.response_data }
      response_code={ props.store.getState().user_password.onupdate.response_code }

      UserPasswordCurrentPasswordOnchange={ UserPasswordCurrentPasswordOnchange }
      UserPasswordUpdatedPasswordOnchange={ UserPasswordUpdatedPasswordOnchange }
      UserPasswordOnupdate={ UserPasswordOnupdate }
      UserPasswordOnclear={ UserPasswordOnclear }
    />
  );
}
  
export default UserPasswordMiddleware;
