import {
  DocumentInsertFilesOnchangeActionCreator,
  DocumentInsertFilesElapsedOnchangeActionCreator,
  DocumentInsertCollectionDatalistCollectionNameOnchangeActionCreator,
  DocumentInsertOnclearActionCreator } from "../../reducers/document_insert_reducer";
import { DocumentListOnclearActionCreator } from "../../reducers/document_list_reducer";
import DocumentInsertComponent from "../../components/document/document_insert_component";
import { useNavigate } from "react-router-dom";
import config from "../../config";
import axios from "axios";
import { buttons_enable, buttons_disable } from "../../helpers/buttons_helper";
import { log } from "../../helpers/log_helper";

const DocumentInsertMiddleware = (props) => {
  const navigate = useNavigate();

  const DocumentInsertFilesOnchange = (files) => {
    let action = DocumentInsertFilesOnchangeActionCreator(files);
    props.store.dispatch(action);
  }

  const DocumentInsertCollectionDatalistCollectionNameOnchange = (collection_name) => {
    const action = DocumentInsertCollectionDatalistCollectionNameOnchangeActionCreator(collection_name);
    props.store.dispatch(action);
  }

  const DocumentInsertOninsert = () => {
    const offcanvas_id = "offcanvas-document-insert";
    const log_prefix = "document-insert-oninsert";
    buttons_disable(offcanvas_id);

    DocumentInsertFilesElapsedOnchange(true);

    const collection_id = props.store.getState().document_insert.collection_datalist.collection_id;
    const files = props.store.getState().document_insert.files;

    Array.from(files).forEach((file, index, array) => {
      const formData = new FormData();
      formData.append("file", file);

      axios({
        method: "post",
        url: config.server_host + "collection/" + collection_id + "/document", 
        headers: { Authorization: "Bearer " + props.store.getState().app.user_token },
        data: formData,

      }).then(response => {
        log.debug(log_prefix, response);

        if (index === array.length - 1) {
          buttons_enable(offcanvas_id);

          const action = DocumentListOnclearActionCreator();
          props.store.dispatch(action);

          DocumentInsertFilesElapsedOnchange(false);
          DocumentInsertOnclear();
        }
        
      }).catch(e => {
        log.error(log_prefix, e);
      });
    });
  }

  const DocumentInsertFilesElapsedOnchange = (files_elapsed) => {
    const action = DocumentInsertFilesElapsedOnchangeActionCreator(files_elapsed);
    props.store.dispatch(action);
  }

  const DocumentInsertOnclear = () => {
    const action = DocumentInsertOnclearActionCreator();
    props.store.dispatch(action);
  }

  return (
    <DocumentInsertComponent
      dispatch={ props.store.dispatch }
      user_token={ props.store.getState().app.user_token }

      files={ props.store.getState().document_insert.files }
      files_elapsed={ props.store.getState().document_insert.files_elapsed }
      collection_datalist={ props.store.getState().document_insert.collection_datalist }

      DocumentInsertFilesOnchange={ DocumentInsertFilesOnchange }
      DocumentInsertCollectionDatalistCollectionNameOnchange={ DocumentInsertCollectionDatalistCollectionNameOnchange }
      DocumentInsertOninsert={ DocumentInsertOninsert }
      DocumentInsertOnclear={ DocumentInsertOnclear }
    />
  );
}
  
export default DocumentInsertMiddleware;
