import { useTranslation } from "react-i18next";
import config from "../../config";
import empty from "../../helpers/empty_helper";
import datetime from "../../helpers/datetime_helper";
import { can_write, can_admin } from "../../helpers/role_helper"
import PaginationComponent from "../pagination_component";
import DatatableComponent from "../datatable_component";
import { offcanvas_show } from "../../helpers/offcanvas_helper";

let timer;

const PartnerListComponent = (props) => {
  const { t } = useTranslation();

  if (empty(props.response_data) && !empty(props.user_token)) {
    props.PartnerListOnselect();
  }

  const PartnerListOrderOnchange = (event) => {
    const order_by = event.target.dataset.order_by;
    props.PartnerListOrderOnchange(order_by);
    props.PartnerListOnclear();
  }

  const PartnerSelectPartnerIdOnchange = (event) => {
    const partner_id = event.target.dataset.partner_id;
    props.PartnerSelectPartnerIdOnchange(partner_id);
    offcanvas_show("offcanvas-partner-select");
  }

  const filters_count = (!empty(props.filter.partner_name) + !empty(props.filter.partner_type) + !empty(props.filter.partner_region)) || null;
  const filters_reset = () => {
    props.PartnerListOffsetOnchange(0);
    props.PartnerFilterOnreset();
    props.PartnerListOnclear();
  }

  const columns = [
    { name: t("id"), order_by: "id" },
    { name: t("created-date"), order_by: "created_date" },
    { name: t("partner-name"), order_by: "partner_name" },
    { name: t("partner-type"), order_by: "partner_type" },
    { name: t("partner-region"), order_by: "partner_region" },
  ];

  const rows = props.response_data?.partners?.map(partner => { 
    return [
      partner.id,
      datetime(partner.created_date, props.user_timezone, t),
      <span role="button" className="link-primary" data-partner_id={ partner.id } onClick={ PartnerSelectPartnerIdOnchange }>{ partner.partner_name }</span>,
      partner.partner_type,
      partner.partner_region,
    ];
  });

  const TimerStart = () => {
    clearTimeout(timer);
    timer = setTimeout(() => {
      props.PartnerListOffsetOnchange(0);
      props.PartnerListOnclear();
    }, config.input_latency);
  }

  const PartnerFilterPartnerNameOnchange = (event) => {
    const partner_name = event.target.value;
    props.PartnerFilterPartnerNameOnchange(partner_name);
    TimerStart();
  }

  const PartnerFilterPartnerTypeOnchange = (event) => {
    const partner_type = event.target.value;
    props.PartnerFilterPartnerTypeOnchange(partner_type);
    TimerStart();
  }

  const PartnerFilterPartnerRegionOnchange = (event) => {
    const partner_region = event.target.value;
    props.PartnerFilterPartnerRegionOnchange(partner_region);
    TimerStart();
  }

  return (<>
    <h1 className="mb-4">{ t("page-partners-title") }</h1>

    <div className="d-flex d-inline align-items-center mb-4">
      <div className="btn-group btn-group-outline">
        <button type="button" className="btn btn-outline-primary" data-bs-toggle="collapse" href="#partner-filter">
          <i className="bi bi-sliders2"></i> { t("button-filters") } <span className="badge text-bg-primary">{ filters_count }</span>
        </button>

        <button type="button" className="btn btn-outline-primary" onClick={ filters_reset }>
          <i className="bi bi-x-lg"></i> { t("button-reset") }
        </button>
      </div>

      <a href="#offcanvas-partner-insert" data-bs-toggle="offcanvas" type="button" className={ "btn btn-outline-primary ms-3" + (can_write(props.token_payload.user_role) ? "" : " d-none") }>
        <i className="bi bi-plus-lg"></i> { t("page-partners-add") }
      </a>

      <a href="#" className="link-primary text-decoration-none ms-3" onClick={ props.PartnerListOnclear }>
        <i className="bi bi-arrow-clockwise"></i> { t("button-refresh") }
      </a>

      <div className={ "ms-5" + (props.partner_ids.length > 0 ? "" : " d-none") }>
        { t("page-partners-selected") } <span className="badge text-bg-primary">{ props.partner_ids.length }</span>
      </div>

      <a type="button" className={ "btn btn-outline-danger ms-3" + ( props.partner_ids.length > 0 && can_admin(props.token_payload.user_role) ? "" : " d-none" ) } data-bs-toggle="offcanvas" href="#offcanvas-partner-delete">
        <i className="bi bi-trash3"></i> { t("button-delete") }
      </a>

    </div>

    <div className="row collapse" id="partner-filter">
      <div className="col-6 mb-4">
        <div className="form-floating">
          <input onChange={ PartnerFilterPartnerNameOnchange } type="search" className={ "form-control" + (props.filter.partner_name ? " border-primary" : "") } id="partner-filter-partner-name" placeholder={ t("filter-partner-name") } value={ props.filter.partner_name } />
          <label htmlFor="partner-filter-partner-name">{ t("filter-partner-name") }</label>
        </div>
      </div>

      <div className="col-3 mb-4">
        <div className="form-floating">
          <input onChange={ PartnerFilterPartnerTypeOnchange } type="search" className={ "form-control" + (props.filter.partner_type ? " border-primary" : "") } id="partner-filter-partner-type" placeholder={ t("filter-partner-type") } value={ props.filter.partner_type } />
          <label htmlFor="partner-filter-partner-type">{ t("filter-partner-type") }</label>
        </div>
      </div>

      <div className="col-3 mb-4">
        <div className="form-floating">
          <input onChange={ PartnerFilterPartnerRegionOnchange } type="search" className={ "form-control" + (props.filter.partner_region ? " border-primary" : "") } id="partner-filter-partner-region" placeholder={ t("filter-partner-region") } value={ props.filter.partner_region } />
          <label htmlFor="partner-filter-partner-region">{ t("filter-partner-region") }</label>
        </div>
      </div>
    </div>

    { rows && !rows.length ?
      <div className="mb-4">
        { t("page-partners-empty") }
      </div>
    :
      <>
        <DatatableComponent
          limit={ props.limit }
          order_by={ props.order_by }
          order={ props.order }
          order_onchange={ PartnerListOrderOnchange }
          columns={ columns }
          rows={ rows }
          selected_rows={ props.partner_ids }
          can_select={ can_admin(props.token_payload.user_role) }
          onselect={ props.PartnerDeletePartnerIdsOnshift }
        />

        <PaginationComponent
          offset={ props.offset } 
          limit={ props.limit }
          limit_values={ config.allowed_partners_limit }
          count={ props.response_data.partners_count }
          offset_onchange={ props.PartnerListOffsetOnchange } 
          limit_onchange={ props.PartnerListLimitOnchange }
          onclear={ props.PartnerListOnclear }
        />
      </>
    }

  </>);
}

export default PartnerListComponent;
