import { useTranslation } from "react-i18next";
import errors from "../../helpers/errors_helper";
import { useEffect } from "react";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import config from "../../config";

const UserPasswordComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-user-password";

  useEffect(() => {
    const offcanvas = document.getElementById(offcanvas_id);

    offcanvas.addEventListener("shown.bs.offcanvas", () => {
      offcanvas.querySelector(".focused").focus();
    });

    offcanvas.addEventListener("hide.bs.offcanvas", () => {
      setTimeout(
        () => { props.UserPasswordOnclear() },
        config.offcanvas_refresh_delay);
    });
  }, []);

  const UserPasswordCurrentPasswordOnchange = (event) => {
    props.UserPasswordCurrentPasswordOnchange(event.target.value);
  }

  const UserPasswordUpdatedPasswordOnchange = (event) => {
    props.UserPasswordUpdatedPasswordOnchange(event.target.value);
  }

  const is_valid = (key) => {
    if (key === "current_password") {
      return props.current_password.length >= 6;

    } else if (key === "updated_password") {
      return props.updated_password.length >= 6;
    }
  }

  const response_errors = errors(props.response_data);
  const submit_enabled = is_valid("current_password") && is_valid("updated_password");

  const UserPasswordOnupdate = (event) => {
    event.preventDefault();
    if (submit_enabled) {
      props.UserPasswordOnupdate();
    }
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title">{ t("offcanvas-user-password-title") }</h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

          <div className="form-text">
            { t("current-password") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ UserPasswordCurrentPasswordOnchange } value={ props.current_password } type="password" className={ "form-control focused" + ("current_password" in response_errors ? " border-danger glow-danger" : is_valid("current_password") ? " border-primary" : "") } placeholder={ t("current-password") } maxLength="256" autoComplete="current-password" />
            <label>{ t("current-password") }</label>
          </div>
          <div className="form-text text-danger">
            { "current_password" in response_errors && t("error_" + response_errors["current_password"]) }
          </div>

          <div className="form-text mt-4">
            { t("updated-password-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ UserPasswordUpdatedPasswordOnchange } value={ props.updated_password } type="password" className={ "form-control" + ("updated_password" in response_errors ? " border-danger glow-danger" : is_valid("updated_password") ? " border-primary" : "") } placeholder={ t("updated-password") } maxLength="256" autoComplete="updated-password" />
            <label>{ t("updated-password") }</label>
          </div>
          <div className="form-text text-danger">
            { "updated_password" in response_errors && t("error_" + response_errors["updated_password"]) }
          </div>

          <button className="btn btn-outline-primary mt-4" type="button" onClick={ offcanvas_hide }>
            <i className="bi bi-arrow-left"></i> { t("button-cancel") }
          </button>

          <button onClick={ UserPasswordOnupdate } className={"btn btn-primary mt-4 ms-2 " + (!submit_enabled ? "disabled" : "")} type="submit">
            <i className="bi bi-check2"></i> { t("button-submit") }
          </button>

        </form>
      </div>
    </div>
  );
}

export default UserPasswordComponent;
