import { offcanvas_hide, offcanvas_show } from "./offcanvas_helper";

export default function hotkeys(AppTokenOndelete) {
  document.addEventListener("keydown", function(event) {

    if (event.ctrlKey && (event.key === "k" || event.key === "л")) {
      event.preventDefault();
      document.getElementById("navbar-search").focus();

    } else if (event.ctrlKey && (event.key === "l" || event.key === "д")) {
      event.preventDefault();
      AppTokenOndelete();
      console.log("logout");
      // event.preventDefault();
      // document.getElementById("navbar-search").focus();

    } else if (event.ctrlKey && (event.key === "o" || event.key === "щ")) {
      event.preventDefault();
      offcanvas_hide();
      offcanvas_show("offcanvas-collection-insert");
    }

  });
}
