import { useTranslation } from "react-i18next";
import errors from "../../helpers/errors_helper";
import { useEffect } from "react";
import { offcanvas_hide } from "../../helpers/offcanvas_helper";
import config from "../../config";

const CollectionUpdateComponent = (props) => {
  const { t } = useTranslation();
  const offcanvas_id = "offcanvas-collection-update";

  useEffect(() => {
    const offcanvas = document.getElementById(offcanvas_id);

    offcanvas.addEventListener("shown.bs.offcanvas", () => {
      props.CollectionUpdateOnselect();
      offcanvas.querySelector(".focused").focus();
    });

    offcanvas.addEventListener("hide.bs.offcanvas", () => {
      setTimeout(
        () => { props.CollectionUpdateOnclear() },
        config.offcanvas_refresh_delay);
    });
  }, []);

  const CollectionUpdateCollectionNameOnchange = (event) => {
    props.CollectionUpdateCollectionNameOnchange(event.target.value);
  }

  const CollectionUpdateCollectionSummaryOnchange = (event) => {
    props.CollectionUpdateCollectionSummaryOnchange(event.target.value);
  }

  const CollectionUpdateIsLockedOnchange = () => {
    props.CollectionUpdateIsLockedOnchange();
  }

  const is_valid = (key) => {
    if (key === "collection_name") {
      return props.collection_name.length >= 1 && props.collection_name.length <= 256;

    } else if (key === "collection_summary") {
      return !props.collection_summary || props.collection_summary.length <= 512;
    }
  }

  const submit_enabled = is_valid("collection_name") && is_valid("collection_summary");
  const response_errors = errors(props.response_data);

  const CollectionUpdateOnupdate = (event) => {
    event.preventDefault();
    if (submit_enabled) {
      props.CollectionUpdateOnupdate();
    }
  }

  return (
    <div id={ offcanvas_id } className="offcanvas offcanvas-start w-35" tabIndex="-1">
      <div className="offcanvas-header">
        <h5 className="offcanvas-title">{ t("offcanvas-collection-update-title") }</h5>
        <button type="button" className="btn-close" data-bs-dismiss="offcanvas"></button>
        <button type="button" className="d-none" data-bs-toggle="offcanvas" href={ "#" + offcanvas_id }></button>
      </div>
      <div className="offcanvas-body mb-4">
        <form>

        <div className="form-text">
            { t("id") }
          </div>
          <div>
            { props.collection_id }
          </div>

          <div className="form-text mt-4">
            { t("collection-name-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ CollectionUpdateCollectionNameOnchange } value={ props.collection_name } type="text" className={ "form-control focused" + ("collection_name" in response_errors ? " border-danger glow-danger" : is_valid("collection_name") ? " border-primary" : "") } placeholder={ t("collection-name") } maxLength="256" />
            <label>{ t("collection-name") }</label>
          </div>
          <div className="form-text text-danger">
            { "collection_name" in response_errors && t("error_" + response_errors["collection_name"]) }
          </div>

          <div className="form-text mt-4">
            { t("collection-summary-text") }
          </div>
          <div className="form-floating mt-2">
            <input onChange={ CollectionUpdateCollectionSummaryOnchange } value={ props.collection_summary || "" } type="text" className={ "form-control focused" + ("collection_summary" in response_errors ? " border-danger glow-danger" : is_valid("collection_summary") ? " border-primary" : "") } placeholder={ t("collection-summary") } maxLength="512" />
            <label>{ t("collection-summary") }</label>
          </div>
          <div className="form-text text-danger">
            { "collection_summary" in response_errors && t("error_" + response_errors["collection_summary"]) }
          </div>

          <div className="form-text mt-4">
            { t("collection-locked-text") }
          </div>
          <div className="form-floating mt-2">
            <div className="form-switch">
              <input id="collection-update-lock" onChange={ CollectionUpdateIsLockedOnchange } checked={ props.is_locked } className="form-check-input" type="checkbox" role="switch" />
              <label className="form-check-label ms-2" htmlFor="collection-update-lock">{ props.is_locked ? t("locked-true") : t("locked-false") }</label>
            </div>
          </div>

          <button className="btn btn-outline-primary mt-4" type="button" onClick={ offcanvas_hide }>
            <i className="bi bi-arrow-left"></i> { t("button-cancel") }
          </button>

          <button onClick={ CollectionUpdateOnupdate } className={"btn btn-primary mt-4 ms-2 " + (!submit_enabled ? "disabled" : "")} type="submit">
            <i className="bi bi-check2"></i> { t("button-submit") }
          </button>

        </form>
      </div>
    </div>
  );
}

export default CollectionUpdateComponent;
