const DOCUMENT_DELETE_DOCUMENT_ID_ONCHANGE = "DOCUMENT_DELETE_DOCUMENT_ID_ONCHANGE";
const DOCUMENT_DELETE_DOCUMENT_IDS_ONSHIFT = "DOCUMENT_DELETE_DOCUMENT_IDS_ONSHIFT";
const DOCUMENT_DELETE_ONCLEAR = "DOCUMENT_DELETE_ONCLEAR";

const initial = {
  document_id: 0,
  document_ids: [],
};

const DocumentDeleteReducer = (state = initial, action) => {

  if (action.type === DOCUMENT_DELETE_DOCUMENT_ID_ONCHANGE) {
    state.document_id = parseInt(action.document_id);

  } else if (action.type === DOCUMENT_DELETE_DOCUMENT_IDS_ONSHIFT) {
    const document_id = parseInt(action.document_id);

    if (state.document_ids.includes(document_id)) {
      state.document_ids = state.document_ids.filter(id => id !== document_id);

    } else {
      state.document_ids.push(document_id);
    }

  } else if (action.type === DOCUMENT_DELETE_ONCLEAR) {
    state.document_id = 0;
  }

  return state;
}

export const DocumentDeleteDocumentIdOnchangeActionCreator = (document_id) => {
  return {
    type: DOCUMENT_DELETE_DOCUMENT_ID_ONCHANGE,
    document_id: document_id, 
  }
}

export const DocumentDeleteDocumentIdsOnshiftActionCreator = (document_id) => {
  return {
    type: DOCUMENT_DELETE_DOCUMENT_IDS_ONSHIFT,
    document_id: document_id, 
  }
}

export const DocumentDeleteOnclearActionCreator = () => {
  return {
    type: DOCUMENT_DELETE_ONCLEAR,
  }
}

export default DocumentDeleteReducer;
